export const CARDS_COMMON = [
  { id: 1, category: "gaiyou", source: "jac-ch1", furi: "ちょれい", jp: "朝礼", romaji: "chorei", id_text: "Apel pagi", desc: "Pertemuan wajib setiap pagi sebelum kerja. Ada 2 jenis: apel umum dan apel per jenis pekerjaan. Mandor:「朝礼には絶対遅れるな」(jangan pernah telat apel pagi).", _origIndex: 0 },
  { id: 2, category: "gaiyou", source: "jac-ch1", furi: "きけんよちかつどうかつどう", jp: "危険予知活動（KY活動）", romaji: "kiken yochi katsudou (KY katsudou)", id_text: "Kegiatan Prediksi Bahaya (KY)", desc: "Kegiatan identifikasi bahaya sebelum mulai bekerja, dilakukan saat apel per jenis pekerjaan. Mandor:「KY表はちゃんと書けよ」(isi formulir KY dengan benar).", _origIndex: 1 },
  { id: 3, category: "gaiyou", source: "jac-ch1", furi: "らじおたいそう", jp: "ラジオ体操", romaji: "rajio taiso", id_text: "Senam radio", desc: "Senam pemanasan saat apel pagi untuk mencegah cedera. Wajib diikuti semua pekerja sebelum kerja dimulai. Mandor:「体操しっかりやれ、怪我の予防になる」(senam sungguh-sungguh, cegah cedera).", _origIndex: 2 },
  { id: 4, category: "gaiyou", source: "jac-ch1", furi: "ゆびさしこしょう", jp: "指差し呼称", romaji: "yubisashi koshou", id_text: "Tunjuk dan panggil", desc: "Metode konfirmasi keselamatan dengan menunjuk dan menyebut keras. Wajib digunakan setiap cek kondisi kerja. Mandor:「確認は必ず指差し呼称でやれよ」(konfirmasi wajib pakai tunjuk dan ucapkan).", _origIndex: 3 },
  { id: 6, category: "hourei", source: "jac-ch2", furi: "ろうどうきじゅんほう", jp: "労働基準法", romaji: "roudou kijunhou", id_text: "UU Standar Ketenagakerjaan", desc: "UU standar kerja minimum: max 8 jam/hari & 40 jam/minggu. Lembur di atas batas wajib dibayar 割増賃金. Mandor:「8時間超えたら記録してくれ」(catat kalau lebih 8 jam, ada upah tambahan).", _origIndex: 4 },
  { id: 7, category: "hourei", source: "jac-ch2", furi: "ろうどうあんぜんえいせいほう", jp: "労働安全衛生法", romaji: "roudou anzen eisei hou", id_text: "UU Keselamatan dan Kesehatan Kerja", desc: "UU yang menjamin keselamatan dan kesehatan pekerja. Di lapangan: dasar aturan APD dan pendidikan K3. Mandor:「ヘルメットと安全帯は必ず着けてくれよ」(wajib pakai helm dan sabuk pengaman).", _origIndex: 5 },
  { id: 8, category: "hourei", source: "jac-ch2", furi: "さいていちんぎんほう", jp: "最低賃金法", romaji: "saitei chingin hou", id_text: "UU Upah Minimum", desc: "UU batas terendah upah yang boleh diberikan, ditetapkan per prefektur. Besaran berbeda tiap daerah. Mandor:「最低賃金以上は必ず払うよ」(pasti bayar di atas upah minimum daerah).", _origIndex: 6 },
  { id: 9, category: "hourei", source: "jac-ch2", furi: "けんせつぎょうほう", jp: "建設業法", romaji: "kensetsu gyou hou", id_text: "UU Industri Konstruksi", desc: "UU yang mengatur izin usaha, kontrak, dan tanggung jawab konstruksi. Perusahaan wajib punya izin per jenis pekerjaan. Mandor:「うちはちゃんと許可を持ってるから安心して」(punya izin resmi, tenang saja).", _origIndex: 7 },
  { id: 10, category: "hourei", source: "jac-ch2", furi: "けんちくきじゅんほう", jp: "建築基準法", romaji: "kenchiku kijun hou", id_text: "UU Standar Bangunan", desc: "UU standar minimum untuk membangun dan menggunakan bangunan. Semua pekerjaan wajib memenuhi standar ini. Mandor:「図面通りに施工しないと検査に通らないぞ」(tidak sesuai gambar, tidak lolos inspeksi).", _origIndex: 8 },
  { id: 11, category: "hourei", source: "jac-ch2", furi: "しょうぼうほう", jp: "消防法", romaji: "shoubou hou", id_text: "UU Pemadam Kebakaran", desc: "UU yang mengatur alat pemadam, sprinkler, dan alarm kebakaran. Di lapangan: posisi APAR wajib diketahui. Mandor:「消火器の場所は必ず覚えておけよ」(wajib hafal posisi APAR di lapangan).", _origIndex: 9 },
  { id: 12, category: "hourei", source: "jac-ch2", furi: "すいどうほう", jp: "水道法", romaji: "suidou hou", id_text: "UU Air Bersih", desc: "UU yang mengatur usaha dan instalasi pasokan air bersih. Hanya insinyur berlisensi yang boleh mengerjakannya. Mandor:「水道工事は有資格者しかできないぞ」(hanya yang bersertifikat boleh kerja).", _origIndex: 10 },
  { id: 13, category: "hourei", source: "jac-ch2", furi: "でんきじぎょうほう", jp: "電気事業法", romaji: "denki jigyou hou", id_text: "UU Usaha Kelistrikan", desc: "UU standar konstruksi dan pemeliharaan fasilitas ketenagalistrikan. Dasar keamanan semua instalasi listrik. Mandor:「電気設備は専門業者に任せろ、触るな」(instalasi listrik serahkan ke ahlinya).", _origIndex: 11 },
  { id: 14, category: "hourei", source: "jac-ch2", furi: "でんきつうしんじぎょうほう", jp: "電気通信事業法", romaji: "denki tsuushin jigyou hou", id_text: "UU Usaha Telekomunikasi", desc: "UU yang mengatur pemasangan jaringan dan peralatan telekomunikasi. Wajib dikerjakan insinyur berkualifikasi. Mandor:「通信配線は有資格者しか触れないぞ」(hanya yang bersertifikat boleh pegang).", _origIndex: 12 },
  { id: 15, category: "hourei", source: "jac-ch2", furi: "さぶろくきょうてい", jp: "36協定", romaji: "saburoku kyoutei", id_text: "Perjanjian 36 (perjanjian lembur)", desc: "Perjanjian berdasar Pasal 36 UU Ketenagakerjaan yang membolehkan lembur. Tanpa ini, perusahaan tidak boleh minta lembur. Mandor:「36協定の範囲内で残業を頼むよ」(lembur sesuai batas perjanjian 36).", _origIndex: 13 },
  { id: 16, category: "hourei", source: "jac-ch2", furi: "ろうさいほけん", jp: "労災保険", romaji: "rousai hoken", id_text: "Asuransi kecelakaan kerja", desc: "Asuransi negara untuk pekerja yang terluka, sakit, atau meninggal akibat kerja. Premi 100% ditanggung pemberi kerja. Mandor:「怪我したらすぐ報告してくれ」(cedera langsung lapor, ada asuransi kerja).", _origIndex: 14 },
  { id: 17, category: "hourei", source: "jac-ch2", furi: "まにえすと", jp: "マニフェスト", romaji: "manifesuto", id_text: "Manifest (lembar kontrol limbah konstruksi)", desc: "Dokumen wajib yang membuktikan limbah industri dibuang dengan benar. Kontraktor utama wajib membuatnya. Mandor:「産廃はマニフェスト書いてから出してくれよ」(tulis manifest dulu sebelum keluarkan limbah).", _origIndex: 15 },
  { id: 18, category: "hourei", source: "jac-ch2", furi: "けんせつりさいくるほう", jp: "建設リサイクル法", romaji: "kensetsu risaikuru hou", id_text: "UU Daur Ulang Konstruksi", desc: "UU yang mewajibkan pemilahan dan daur ulang limbah konstruksi. Sampah di lokasi wajib disimpan sesuai jenis (分別). Mandor:「ゴミは必ず分別してから置いとけよ」(sampah wajib dipilah sesuai jenis).", _origIndex: 16 },
  { id: 19, category: "hourei", source: "jac-ch2", furi: "こようほけんほう", jp: "雇用保険法", romaji: "koyou hoken hou", id_text: "UU Asuransi Ketenagakerjaan", desc: "UU yang mengatur tunjangan pengangguran bagi yang kehilangan pekerjaan. Premi ditanggung bersama pemberi kerja dan pekerja. Mandor:「雇用保険は失業した時のためだよ」(potongan asuransi itu persiapan kalau PHK).", _origIndex: 17 },
  { id: 20, category: "hourei", source: "jac-ch2", furi: "がすじぎょうほう", jp: "ガス事業法", romaji: "gasu jigyou hou", id_text: "UU Usaha Gas", desc: "UU yang mengatur usaha gas kota (都市ガス), berbeda dari gas LPG. Pekerjaan gas kota hanya oleh kontraktor berlisensi khusus. Mandor:「都市ガス工事は専門業者に任せろ」(serahkan ke kontraktor berlisensi khusus).", _origIndex: 18 },
  { id: 21, category: "hourei", source: "jac-ch2", furi: "げすいどうほう", jp: "下水道法", romaji: "gesuidou hou", id_text: "UU Saluran Air Limbah", desc: "UU yang mengatur sistem saluran pembuangan air limbah kota. Instalasi gedung wajib terhubung ke sistem pembuangan resmi. Mandor:「排水は直接側溝に流すな、下水へ」(air limbah jangan ke parit, ke saluran resmi).", _origIndex: 19 },
  { id: 22, category: "hourei", source: "jac-ch2", furi: "はいきぶものしょりほう", jp: "廃棄物処理法", romaji: "haikibumono shori hou", id_text: "UU Pengelolaan Limbah", desc: "UU yang mengatur pengelolaan dan pembuangan limbah industri. Manifest wajib dibuat kontraktor utama sebelum limbah diangkut. Mandor:「産廃は許可業者しか運べないぞ」(limbah industri hanya oleh yang berizin).", _origIndex: 20 },
  { id: 23, category: "hourei", source: "jac-ch2", furi: "ろうさいかくし", jp: "労災かくし", romaji: "rousai kakushi", id_text: "Penyembunyian kecelakaan kerja — KEJAHATAN", desc: "Menyembunyikan kecelakaan kerja dari kantor inspeksi adalah kejahatan. Setiap kecelakaan wajib segera dilaporkan. Mandor:「労災を隠すのは犯罪だ、必ず報告しろよ」(menyembunyikan kecelakaan adalah kejahatan).", _origIndex: 21 },
  { id: 24, category: "hourei", source: "jac-ch2", furi: "でんきこうじぎょうほう", jp: "電気工事業法", romaji: "denki kouji gyou hou", id_text: "UU Pekerjaan Listrik (≠ UU Kelistrikan)", desc: "UU yang mengatur kontraktor pekerjaan listrik, berbeda dari 電気事業法. Kontraktor listrik wajib terdaftar terpisah. Mandor:「電気工事業の登録なしには工事できないぞ」(tanpa registrasi, tidak boleh kerja).", _origIndex: 22 },
  { id: 25, category: "hourei", source: "jac-ch2", furi: "けんせつぎょうほうのにじゅうきゅうぎょうしゅ", jp: "建設業法の29業種", romaji: "kensetsu gyou hou no nijuukyuu gyoushu", id_text: "29 jenis usaha yang perlu izin konstruksi", desc: "29 jenis usaha konstruksi yang memerlukan izin sesuai 建設業法. Termasuk listrik, pipa, insulasi termal, telekomunikasi, dll. Mandor:「業種ごとに許可を取らないといけないんだ」(izin harus diambil per jenis pekerjaan).", _origIndex: 23 },
  { id: 26, category: "hourei", source: "jac-ch2", furi: "あすべすと", jp: "アスベスト（石綿）", romaji: "asubesuto (ishiwata)", id_text: "Asbes — DILARANG", desc: "Mineral serat berbahaya yang dilarang karena menyebabkan kanker paru. Bangunan lama yang dicurigai asbes wajib disurvei sebelum dibongkar. Mandor:「アスベストが疑われる建物は素手で触るな」(jangan pegang tangan kosong).", _origIndex: 24 },
  { id: 27, category: "hourei", source: "jac-ch2", furi: "たいきおせんぼうしほう", jp: "大気汚染防止法", romaji: "taiki osen boushi hou", id_text: "UU Pencegahan Polusi Udara", desc: "UU pencegahan polusi udara. Bongkar gedung berisi asbes wajib lapor ke gubernur prefektur 14 hari sebelumnya. Mandor:「アスベスト解体は14日前に知事への届出が必要だ」(lapor gubernur 14 hari sebelum mulai).", _origIndex: 25 },
  { id: 29, category: "sekou", source: "jac-ch3", furi: "せつびこうじ", jp: "設備工事", romaji: "setsubi kouji", id_text: "Pekerjaan peralatan", desc: "Meliputi peralatan AC, peralatan kebersihan suplai air & drainase, pekerjaan menjaga suhu, dan peralatan pemadam kebakaran.", _origIndex: 27 },
  { id: 41, category: "sekou", source: "jac-ch6", furi: "じゅちゅういっぴんせいさん", jp: "受注一品生産", romaji: "juchuu ippin seisan", id_text: "Produksi pesanan satu-per-satu", desc: "Karakteristik khas konstruksi: setiap proyek dibuat sesuai permintaan klien dari awal, berbeda dari produksi pabrik.", _origIndex: 39 },
  { id: 50, category: "sekou", source: "jac-jitsugi1", furi: "せこうかんりしょていのひんしつ", jp: "施工管理", romaji: "sekou kanri — shotei no hinshitsu", id_text: "Manajemen konstruksi — kualitas yang ditentukan", desc: "所定の品質。施工管理とは、施工計画に基づいて、施工者が、所定の【品質】の工事目的物を完成させるために必要な管理のことである。Kata kunci: 品質 (kualitas), bukan 環境 (lingkungan).", _origIndex: 48 },
  { id: 111, category: "anzen", source: "jac-ch2", furi: "あんぜんだいいち", jp: "安全第一", romaji: "anzen daiichi", id_text: "Keselamatan Utama (Safety First)", desc: "Prinsip dasar di lokasi konstruksi Jepang: keselamatan di atas segalanya. Papan \"Safety First\" dipasang di setiap lokasi. Mandor:「急いでても安全を後回しにするな」(meski buru-buru, jangan kesampingkan keselamatan).", _origIndex: 107 },
  { id: 112, category: "anzen", source: "jac-ch7", furi: "ふるはあねすがたついらくせいしようきぐう", jp: "フルハーネス型墜落制止用器具", romaji: "furu haanesugata tsuiraku seishi you kiguu", id_text: "Peralatan penahan jatuh jenis full harness", desc: "Wajib digunakan saat bekerja di ketinggian. Full harness lebih aman dari harness dada saja.", _origIndex: 108 },
  { id: 114, category: "anzen", source: "jac-ch2", furi: "ついらくてんらく", jp: "墜落・転落", romaji: "tsuiraku / tenraku", id_text: "Jatuh dari ketinggian / Terjatuh bergulir", desc: "Jatuh dari ketinggian adalah penyebab kematian terbanyak di konstruksi. Tahun 2021: 110 kasus dari 288 kematian total. Mandor:「高所作業では絶対にフルハーネスをつけてくれよ」(di ketinggian wajib pakai full harness).", _origIndex: 109 },
  { id: 116, category: "anzen", source: "jac-ch6", furi: "きゅうしいぢいえすいい", jp: "QCDSE", romaji: "kyuu shii dii esu ii", id_text: "5 Manajemen QCDSE", desc: "Q=Kualitas, C=Biaya (Cost), D=Jadwal/Waktu (Delivery), S=Keselamatan (Safety), E=Lingkungan (Environment).", _origIndex: 110 },
  { id: 118, category: "anzen", source: "jac-ch6", furi: "ごえむ", jp: "5M", romaji: "go emu", id_text: "5M (metode pelaksanaan)", desc: "Men (Manusia), Materials (Material), Methods (Metode), Machinery (Mesin), Money (Uang).", _origIndex: 111 },
  { id: 119, category: "anzen", source: "jac-ch7", furi: "あんかあぽいんと", jp: "アンカーポイント", romaji: "ankaa pointo", id_text: "Titik angkur (anchor point)", desc: "Titik pengait pada struktur untuk mengaitkan peralatan penahan jatuh saat bekerja di ketinggian.", _origIndex: 112 },
  { id: 120, category: "anzen", source: "jac-jitsugi1", furi: "さんそけつぼう", jp: "酸素欠乏（さんそけつぼう）", romaji: "sanso ketsubou", id_text: "Kekurangan oksigen — bahaya di MANHOLE", desc: "Bahaya di ruang tertutup → MANHOLE. Perlu cek kadar oksigen sebelum masuk. Kerja di atas tiang/atap gedung TIDAK termasuk risiko ini.", _origIndex: 113 },
  { id: 121, category: "anzen", source: "jac-jitsugi1", furi: "どどめ", jp: "土留め（どどめ）≥ 1.5m", romaji: "dodome", id_text: "Penahan tanah — WAJIB jika galian ≥ 1.5m", desc: "Mencegah longsor tanah (土砂崩れ) pada pekerjaan galian. WAJIB jika kedalaman ≥1.5m. Berbeda dari 換気 (ventilasi) dan 排水 (drainase).", _origIndex: 114 },
  { id: 122, category: "anzen", source: "jac-jitsugi2", furi: "しんきにゅうじょうしゃきょういくしんにゅうしゃあんぜんえいせいきょういく", jp: "新規入場者教育 vs 新入者安全衛生教育", romaji: "shinki nyuujousha kyouiku vs shinnyuusha anzen eisei kyouiku", id_text: "K3 pekerja baru lokasi vs K3 rekrutan baru", desc: "①新規入場者教育 = untuk PENDATANG BARU ke LOKASI KERJA. ②新入者安全衛生教育 = untuk PEKERJA BARU yang baru DIREKRUT perusahaan. Keduanya wajib.", _origIndex: 115 },
  { id: 123, category: "anzen", source: "jac-jitsugi1", furi: "さんだいさいがい", jp: "三大災害（さんだいさいがい）", romaji: "sandai saigai", id_text: "Tiga bencana besar konstruksi", desc: "①墜落・転落 (TERBANYAK) ②建設機械・クレーン災害 ③崩壊・倒壊. Menyumbang 40–70% kematian.", _origIndex: 116 },
  { id: 124, category: "anzen", source: "jac-ch6", furi: "しぎょうまえてんけん", jp: "始業前点検（しぎょうまえてんけん）", romaji: "shigyou mae tenken", id_text: "Pemeriksaan sebelum mulai kerja", desc: "WAJIB sebelum bekerja: ①Mesin ②Alat/perkakas ③Prosedur kerja. Banyak kecelakaan terjadi saat menangani alat/mesin.", _origIndex: 117 },
  { id: 125, category: "anzen", source: "jac-ch7", furi: "ばっくほうのあんぜん", jp: "バックホウ（油圧ショベル）の安全", romaji: "bakkuhou no anzen", id_text: "Keselamatan backhoe / excavator", desc: "Bahaya: ①激突 — tertabrak bucket ②はさまれ — terjepit bucket. Saat naik/turun ke truk: risiko terbalik. Wajib ada 誘導員 (pemandu).", _origIndex: 118 },
  { id: 126, category: "anzen", source: "jac-ch4", furi: "すぼり", jp: "素掘り（すぼり）", romaji: "subori", id_text: "Penggalian tanpa penahan (open cut)", desc: "Penggalian TANPA 土留め, diperbolehkan HANYA jika tanah benar-benar stabil. Berbeda dari galian ≥1.5m yang WAJIB pakai 土留め.", _origIndex: 119 },
  { id: 127, category: "anzen", source: "jac-ch3", furi: "どらいわあくゑるぽいんとこうほう", jp: "ドライワーク（ウェルポイント工法）", romaji: "dorai waaku (weru pointo kouhou)", id_text: "Pekerjaan kering — metode wellpoint (max 10m)", desc: "Pipa pompa ditancapkan ke tanah, air dipompa keluar dengan pompa vakum. Kedalaman max ≈10m. Lebih dalam → ディープウェル.", _origIndex: 120 },
  { id: 128, category: "anzen", source: "jac-jitsugi2", furi: "ひろうぼうしてきせつなすいみんとしょくじ", jp: "疲労防止", romaji: "hirou boushi — tekisetsu na suimin to shokuji", id_text: "Pencegahan kelelahan — tidur & makan yang cukup", desc: "疲労がたまると事故につながるので、【適切な睡眠と食事をとること】を心がける。Kelelahan menyebabkan kecelakaan → perhatikan tidur & makan yang cukup.", _origIndex: 121 },
  { id: 129, category: "career", source: "jac-ch1", furi: "けんせつきゃりああっぷしすてむ", jp: "建設キャリアアップシステム（CCUS）", romaji: "kensetsu kyaria appu shisutemu", id_text: "Sistem Kenaikan Karier Konstruksi", desc: "Sistem rekam karier pekerja konstruksi, 4 level (putih→biru→perak→emas). Level 2 butuh ≥645 hari kerja tercatat. Mandor:「CCUSカードは毎日タッチするのを忘れるな」(jangan lupa tap kartu CCUS setiap hari).", _origIndex: 122 },
  { id: 130, category: "career", source: "jac-ch1", furi: "もとうり", jp: "元請（ゼネコン）", romaji: "motouri (zenekon)", id_text: "Kontraktor umum (general contractor)", desc: "Perusahaan yang menerima kontrak dari klien dan mengatur seluruh pekerjaan. Bertanggung jawab atas semua sub-kontraktor. Mandor:「ゼネコンからの指示は最優先で動けよ」(instruksi general contractor adalah prioritas).", _origIndex: 123 },
  { id: 131, category: "career", source: "jac-ch2", furi: "したうけせんもんこうじぎょうしゃ", jp: "下請（専門工事業者）", romaji: "shitauke (senmon kouji gyousha)", id_text: "Kontraktor khusus / sub-kontraktor", desc: "Kontraktor spesialis yang menerima subkontrak dari kontraktor utama. Bekerja sesuai instruksi 職長. Mandor:「職長の指示に従って確実に作業してくれよ」(ikuti instruksi mandor dan kerjakan dengan tepat).", _origIndex: 124 },
  { id: 134, category: "career", source: "jac-gakka1", furi: "ごえす", jp: "5S（整理・整頓・清掃・清潔・しつけ）", romaji: "go esu", id_text: "5S: Pilah / Tata / Bersih / Higienis / Disiplin", desc: "Seiri=Pilah, Seiton=Tata, Seisou=Bersih, Seiketsu=Higienis, Shitsuke=DISIPLIN (item ke-5, sering ditanyakan).", _origIndex: 125 },
  { id: 135, category: "career", source: "jac-gakka1", furi: "ぱわあはらすめんと", jp: "パワー・ハラスメント（パワハラ）", romaji: "pawaa harasumento", id_text: "Pelecehan kekuasaan (Power Harassment)", desc: "Memanfaatkan keunggulan posisi untuk memberi tekanan melebihi batas wajar. Berbeda dari セクハラ.", _origIndex: 126 },
  { id: 136, category: "career", source: "jac-gakka2", furi: "しかくのしゅるい", jp: "資格の種類：電気工事士・工事担任者・消防設備士", romaji: "shikaku no shurui", id_text: "Kualifikasi: listrik / telekomunikasi / pemadam", desc: "①電気工事士 = LISTRIK. ②工事担任者 = TELEKOMUNIKASI. ③消防設備士 = PEMADAM KEBAKARAN.", _origIndex: 127 },
  { id: 137, category: "career", source: "jac-ch2", furi: "せくしゃるはらすめんと", jp: "セクシャル・ハラスメント（セクハラ）", romaji: "sekusharu harasumento", id_text: "Pelecehan seksual (Sexual Harassment)", desc: "Tindakan atau ucapan seksual yang tidak diinginkan di tempat kerja. Berbeda dari パワハラ, keduanya dilarang keras. Mandor:「セクハラは厳しく対処する、相談してくれ」(pelecehan ditangani keras, konsultasikan masalah).", _origIndex: 128 },
  { id: 138, category: "sekou", source: "jac-jitsugi1", furi: "すいじゅんき", jp: "水準器（レベル）", romaji: "suijunki (reberu)", id_text: "Waterpas / Level (instrumen survei)", desc: "Alat survei dengan teleskop untuk mengukur ketinggian/elevasi. Dipasang di atas tripod. Sering diuji lewat FOTO.", _origIndex: 129 },
  { id: 139, category: "sekou", source: "jac-ch5", furi: "とらんしっと", jp: "トランシット", romaji: "toranshitto", id_text: "Theodolit / Transit", desc: "Alat ukur sudut vertikal dan horizontal — saat ini umumnya versi digital. Mandor:「トランシットで通りと直角を確認して」(cek kelurusan dan sudut siku dengan transit).", _origIndex: 130 },
  { id: 140, category: "sekou", source: "jac-ch5", furi: "とおたるすてえしょん", jp: "トータルステーション", romaji: "tootaru suteeshon", id_text: "Total station", desc: "Gabungan alat ukur jarak dan sudut elektronik dalam satu perangkat. Mandor:「トータルステーションで座標を確認して」(konfirmasi koordinat dengan total station).", _origIndex: 131 },
  { id: 141, category: "sekou", source: "jac-ch5", furi: "すみだし", jp: "墨出し（すみだし）", romaji: "sumi dashi", id_text: "Penandaan tinta / marking", desc: "Penandaan posisi dan ketinggian struktur di lokasi konstruksi. Pekerjaan terpenting yang butuh akurasi tinggi.", _origIndex: 132 },
  { id: 142, category: "sekou", source: "jac-ch5", furi: "こんべっくす", jp: "コンベックス", romaji: "konbekkusu", id_text: "Meteran pita (convex rule)", desc: "Meteran pita logam tipis — nama resmi 'convex rule', di lapangan dipanggil 'konbe'. Mandor:「コンベックスで寸法を二度確認して」(ukur dimensi dua kali dengan meteran).", _origIndex: 133 },
  { id: 143, category: "sekou", source: "jac-ch5", furi: "ふりこさげふり", jp: "振り子・下げ振り", romaji: "furiko / sage furi", id_text: "Bandul lot (plumb bob)", desc: "Pemberat berujung kerucut untuk memeriksa tegak lurusnya tiang. Prinsip: benang dari atas, cek jarak ke permukaan.", _origIndex: 134 },
  { id: 144, category: "sekou", source: "jac-ch5", furi: "さんだあ", jp: "サンダー", romaji: "sandaa", id_text: "Sander (alat poles)", desc: "Alat listrik untuk ampelas permukaan datar — jenis getar, sabuk, dan putar. Mandor:「サンダーかける前に養生してください」(lakukan pelindungan area sebelum mengampelas).", _origIndex: 135 },
  { id: 145, category: "sekou", source: "jac-jitsugi1", furi: "すみつぼ", jp: "墨つぼ（すみつぼ）", romaji: "sumi tsubo", id_text: "Wadah tinta / chalk line reel", desc: "Membuat garis lurus panjang dengan menarik benang bercelup tinta. Berbeda dari: 墨さし (kuas pendek), チョーク, レーザー墨出し器. Sering diuji lewat FOTO.", _origIndex: 136 },
  { id: 146, category: "sekou", source: "jac-ch4", furi: "ろくずみにげすみじずみ", jp: "墨出し用語：陸墨・逃げ墨・地墨", romaji: "rokuzumi / nigesumi / jizumi", id_text: "Tinta horizontal / tinta geser / tinta lantai", desc: "①陸墨: garis referensi HORIZONTAL (ketinggian). ②逃げ墨: garis yang dipindah dari posisi asli karena terhalang. ③地墨: garis ditandai langsung di LANTAI.", _origIndex: 137 },
  { id: 147, category: "sekou", source: "jac-ch4", furi: "べんちまーく", jp: "ベンチマーク（BM）・GL・FL", romaji: "BM / GL / FL", id_text: "BM = benchmark / GL = ground / FL = floor", desc: "BM: titik referensi ketinggian di lokasi. GL: ketinggian permukaan tanah. FL: ketinggian lantai jadi (1FL, 2FL, ...).", _origIndex: 138 },
  { id: 148, category: "sekou", source: "jac-ch4", furi: "とおりしんかべしんはしらしん", jp: "通り芯（とおりしん）・壁芯・柱芯", romaji: "toori shin / kabe shin / hashira shin", id_text: "Garis sumbu tengah — dinding dan kolom", desc: "通り芯: center line. 壁芯: center line dinding. 柱芯: center line kolom. Acuan penandaan posisi di lokasi.", _origIndex: 139 },
  { id: 149, category: "sekou", source: "jac-jitsugi2", furi: "だいしゃ", jp: "台車（だいしゃ）", romaji: "daisha", id_text: "Kereta dorong datar (platform cart)", desc: "Platform datar berkaki roda untuk mengangkut material dan peralatan berat di lokasi konstruksi. Di proyek: berbeda dari 一輪車 (satu roda), そり (sledge), ころ (roller).", _origIndex: 140 },
  { id: 150, category: "sekou", source: "jac-ch5", furi: "いちりんしゃ", jp: "一輪車（いちりんしゃ）", romaji: "ichirinsha", id_text: "Gerobak sorong satu roda (wheelbarrow)", desc: "Alat angkut dengan satu roda di depan dan dua gagang di belakang. Digunakan untuk mengangkut tanah, pasir, campuran beton di lokasi konstruksi. Berbeda dari 台車 (platform datar 4 roda).", _origIndex: 141 },
  { id: 151, category: "hourei", source: "jac-ch2", furi: "わりましちんぎんりつ", jp: "割増賃金率", romaji: "warimashi chingin ritsu", id_text: "Lembur: biasa +25% / libur +35% / malam +25%", desc: "Tiga tingkat upah tambahan wajib sesuai UU. Batas lembur: 45 jam/bulan, 360 jam/tahun (berlaku April 2024). Mandor:「残業代は法律通りに払うから記録してくれ」(upah lembur dibayar sesuai UU, catat jam).", _origIndex: 142 },
  { id: 152, category: "hourei", source: "jac-ch2", furi: "つうきんさいがいぎょうむさいがい", jp: "通勤災害 vs 業務災害", romaji: "tsuukin saigai vs gyoumu saigai", id_text: "Kecelakaan perjalanan vs kecelakaan tempat kerja", desc: "通勤災害: kecelakaan saat perjalanan rumah↔kerja via rute wajar. 業務災害: akibat pekerjaan itu sendiri. Keduanya ditanggung 労災保険. Mandor:「通勤中の事故もすぐ報告してくれよ」(kecelakaan di perjalanan pun lapor).", _origIndex: 143 },
  { id: 153, category: "career", source: "jac-ch2", furi: "ぎのうけんてい／ぎのうし", jp: "技能検定 / 技能士", romaji: "ginou kentei / ginoushi", id_text: "Uji keterampilan / Teknisi berlisensi negara", desc: "Ujian sertifikasi nasional; lulus → dapat 合格証書 dan boleh menyebut diri 技能士. Ada 32 jenis di konstruksi, 5 tingkat. Mandor:「2級取ったら手当もつくし、CCUSも上がるぞ」(lulus level 2, ada tunjangan dan CCUS naik).", _origIndex: 144 },
  { id: 154, category: "hourei", source: "jac-ch2", furi: "とくていぎのうがいこくじんのこようほけん", jp: "特定技能外国人の雇用保険（失業給付）", romaji: "tokutei ginou gaikokujin no koyou hoken", id_text: "SSW asing bisa dapat tunjangan pengangguran", desc: "SSW yang kehilangan pekerjaan tidak wajib langsung pulang, bisa dapat tunjangan 雇用保険. Boleh tinggal selama aktif mencari kerja. Mandor:「仕事なくなってもすぐ帰国しなくていいぞ」(tidak harus langsung pulang).", _origIndex: 145 },
  { id: 155, category: "hourei", source: "jac-ch2", furi: "こようほけんのしきゅうようけん", jp: "雇用保険の支給要件（12ヶ月以上）", romaji: "koyou hoken no shikyuu youken", id_text: "Syarat tunjangan: ≥12 bln dalam 2 tahun terakhir", desc: "Syarat: menganggur dan mau bekerja, plus ≥12 bulan masa asuransi dalam 2 tahun terakhir. Tunjangan 45–80% upah, 90–360 hari. Mandor:「12ヶ月以上入ってれば給付もらえるよ」(masuk ≥12 bulan, bisa dapat tunjangan).", _origIndex: 146 },
  { id: 156, category: "hourei", source: "jac-ch2", furi: "すとれすへっく", jp: "ストレスチェック（50人以上の事業場）", romaji: "sutoresu chekku", id_text: "Cek stres — WAJIB perusahaan ≥50 orang, 1x/tahun", desc: "Perusahaan ≥50 karyawan wajib lakukan cek beban psikologis tiap tahun oleh dokter/perawat. Diatur 労働安全衛生法. Mandor:「ストレスチェックは必ず受けてくれよ」(wajib ikut stress check dari perusahaan).", _origIndex: 147 },
  { id: 157, category: "hourei", source: "jac-ch2", furi: "どろおんとうろくぎむ", jp: "ドローン登録義務（≥100g）", romaji: "doroon touroku gimu", id_text: "Drone ≥100g WAJIB didaftarkan ke pemerintah", desc: "Drone berat ≥100g wajib didaftarkan sebagai pesawat tak berawak. Sering dipakai untuk survei (測量) di konstruksi. Mandor:「現場でドローン使う前に登録を確認しろよ」(pakai drone di lapangan, pastikan sudah terdaftar).", _origIndex: 148 },
  { id: 158, category: "hourei", source: "jac-ch2", furi: "こうくうしょうがいとう", jp: "航空障害灯（≥60m）", romaji: "koukuu shougai tou", id_text: "Lampu hambatan penerbangan: wajib pada objek ≥60m", desc: "Bangunan, crane, atau struktur setinggi ≥60m wajib dipasangi lampu hambatan penerbangan, termasuk crane sementara. Mandor:「60メートル以上のクレーンには航空障害灯が必要だぞ」(crane ≥60m wajib pasang lampu hambatan).", _origIndex: 149 },
  { id: 159, category: "hourei", source: "jac-ch2", furi: "ちんぎんしはらいのごげんそく", jp: "賃金支払いの5原則", romaji: "chingin shiharai no go gensoku", id_text: "5 prinsip pembayaran upah (Labor Standards Act)", desc: "Lima prinsip pembayaran upah: ①tunai ②langsung ③penuh ④min. 1x/bulan ⑤tanggal tetap. Di lapangan: semua 5 harus terpenuhi. Mandor:「給料は毎月決まった日に全額渡すのが法律だよ」(gaji penuh tiap bulan, tanggal tetap).", _origIndex: 150 },
  { id: 160, category: "hourei", source: "jac-ch2", furi: "きゅうけいじかんのきてい", jp: "休憩時間の規定（6時間・8時間）", romaji: "kyuukei jikan no kitei", id_text: "Aturan istirahat: >6jam→45 mnt; >8jam→1 jam", desc: "Istirahat wajib di tengah jam kerja, diberikan serentak. Kerja >6 jam → 45 menit, >8 jam → 1 jam. Mandor:「8時間超えたら1時間休憩を取らせるぞ」(kerja lebih 8 jam, ambil 1 jam istirahat).", _origIndex: 151 },
  { id: 161, category: "hourei", source: "jac-ch2", furi: "かいこよこくさんじゅうにちまえ", jp: "解雇予告（かいこよこく）", romaji: "kaiko yokoku", id_text: "PHK wajib diumumkan 30 hari sebelumnya", desc: "Pemberi kerja wajib memberitahu 30 hari sebelum memecat; jika tidak, bayar ganti 30 hari upah. Mandor:「辞めてもらう時は30日前に必ず言うよ」(kalau harus berhenti, saya beritahu 30 hari sebelumnya).", _origIndex: 152 },
  { id: 162, category: "hourei", source: "jac-ch2", furi: "そうおんきせいほうていそうおんがたけんせつきかい", jp: "騒音規制法・低騒音型機械", romaji: "souon kisei hou / tei souon gata kensetsu kikai", id_text: "UU Kebisingan: wajib pilih mesin rendah bising", desc: "UU yang mengatur tingkat kebisingan dari konstruksi. Wajib pilih mesin 低騒音型 dan atur jadwal/zona bising. Mandor:「この現場では低騒音型の機械を選ぶように」(di lokasi ini pilih mesin rendah kebisingan).", _origIndex: 153 },
  { id: 163, category: "hourei", source: "jac-ch2", furi: "でんぱほうめんきょうがひつようなとらんしいばあ", jp: "電波法", romaji: "denpa hou", id_text: "UU Gelombang Radio: transceiver butuh izin", desc: "UU yang mengatur penggunaan gelombang radio. Transceiver tanpa izin atau impor tak disetujui Jepang adalah ilegal. Mandor:「そのトランシーバー、免許あるか確認したか？」(transceiver itu sudah ada izinnya, sudah dicek?).", _origIndex: 154 },
  { id: 164, category: "hourei", source: "jac-ch2", furi: "ろうさいほけんのよんきゅうふ", jp: "労災保険の4給付（療養・休業・遺族・介護）", romaji: "rousai hoken no yon kyuufu", id_text: "4 jenis tunjangan asuransi kecelakaan kerja", desc: "4 tunjangan 労災: biaya pengobatan penuh, ganti upah, ahli waris jika meninggal, dan perawatan jika cacat. Semua dijamin negara. Mandor:「怪我したら労災で全部面倒みてもらえるよ」(cedera, semua ditanggung asuransi kerja).", _origIndex: 155 },
  { id: 165, category: "hourei", source: "jac-ch2", furi: "ろうさいほけんとくべつかにゅうせいど", jp: "労災保険の特別加入制度（一人親方・中小企業主）", romaji: "rousai hoken tokubetsu kanyuu seido", id_text: "Jalur khusus asuransi kerja: kontraktor mandiri", desc: "労災保険 biasanya hanya untuk karyawan, tapi kontraktor mandiri (一人親方) boleh masuk lewat 特別加入制度. Mandor:「一人親方でも特別加入で労災に入れるぞ」(kontraktor mandiri pun bisa masuk asuransi kerja).", _origIndex: 156 },
  { id: 166, category: "hourei", source: "jac-ch2", furi: "けんせつろうどうしゃこようかいぜんほう", jp: "建設労働者雇用改善法", romaji: "kensetsu roudousha koyou kaizen hou", id_text: "UU Peningkatan Ketenagakerjaan Konstruksi", desc: "UU yang mendorong perbaikan kondisi kerja konstruksi. Rencana ke-10 (2021–2025) menargetkan CCUS dan batas lembur. Mandor:「CCUSカードは毎日忘れずタッチしてくれよ」(jangan lupa tap kartu CCUS setiap hari).", _origIndex: 157 },
  { id: 167, category: "hourei", source: "jac-ch2", furi: "ちゅうしゃじょうほう", jp: "駐車場法（ちゅうしゃじょうほう）", romaji: "chuushajou hou", id_text: "UU Perparkiran: lapor sebelum bangun/ubah parkir", desc: "UU yang mengatur pembangunan fasilitas parkir di perkotaan. Membangun atau memodifikasi parkir wajib lapor ke pemda sebelum mulai. Mandor:「駐車場工事は着工前に届出が要るぞ」(wajib lapor ke pemda).", _origIndex: 158 },
  { id: 168, category: "hourei", source: "jac-ch2", furi: "すいしつおだくぼうしほう", jp: "水質汚濁防止法", romaji: "suishitsu odaku boushi hou", id_text: "UU Pencemaran Air: air beton wajib dinetralkan", desc: "UU yang mengatur kualitas air buangan. Air yang kontak beton sangat basa, wajib dinetralkan dengan CO₂ sebelum dibuang ke saluran. Mandor:「コンクリートの排水は中和してから流してくれよ」(air beton wajib dinetralkan dulu).", _origIndex: 159 },
  { id: 169, category: "hourei", source: "jac-ch2", furi: "ばいしょうよていのきんし", jp: "賠償予定の禁止（ばいしょうよていのきんし）", romaji: "baishou yotei no kinshi", id_text: "Dilarang tetapkan denda/ganti rugi di muka", desc: "Pemberi kerja dilarang mencantumkan klausul denda pemutusan di muka. Pekerja boleh menolak kontrak yang memuat ini. Mandor:「契約に罰金条項は違法だよ、サインするな」(klausul denda melanggar UU, jangan tanda tangan).", _origIndex: 160 },
  { id: 170, category: "hourei", source: "jac-ch2", furi: "きかいきんとうのげんそくきょうせいろうどうのきんし", jp: "機会均等の原則 / 強制労働の禁止", romaji: "kikai kintou no gensoku / kyousei roudou no kinshi", id_text: "Non-diskriminasi kebangsaan + dilarang kerja paksa", desc: "Dilarang membeda-bedakan upah berdasarkan kebangsaan/kepercayaan/status sosial, dan dilarang kerja paksa. Mandor:「国籍が違っても同じ条件で働いてもらうぞ」(beda kebangsaan pun kondisi kerja sama).", _origIndex: 161 },
  { id: 171, category: "hourei", source: "jac-ch2", furi: "かいこせいげんしょうびょうりょうようちゅうわかいこきんし", jp: "解雇制限", romaji: "kaiko seigen — shoubyou ryouyouchuu wa kaiko kinshi", id_text: "Dilarang pecat saat sakit/cedera kerja + 30 hari", desc: "Pekerja yang sakit/cedera karena kerja tidak boleh dipecat selama pengobatan + 30 hari setelahnya. Berlaku otomatis sesuai UU. Mandor:「仕事中の怪我で休んでる間は解雇できないから安心しろ」(cedera kerja, tidak bisa dipecat).", _origIndex: 162 },
  { id: 172, category: "hourei", source: "jac-ch2", furi: "ろうどうじょうけんのめいじろくこうもん", jp: "労働条件の明示", romaji: "roudou jouken no meiji — roku koumon", id_text: "6 hal wajib diberitahu pemberi kerja saat rekrut", desc: "6 hal wajib diberitahu tertulis: durasi kontrak, lokasi/jenis kerja, jam kerja, upah, libur, ketentuan resign/PHK. Mandor:「契約の時に条件は書面でもらってくれよ」(saat kontrak, minta kondisi kerja secara tertulis).", _origIndex: 163 },
  { id: 173, category: "hourei", source: "jac-ch2", furi: "ちいきべつさいていちんぎん", jp: "地域別最低賃金（ちいきべつさいていちんぎん）", romaji: "chiiki betsu saitei chingin", id_text: "Upah minimum berbeda per prefektur", desc: "Upah minimum ditetapkan per prefektur sesuai biaya hidup daerah. Berlaku untuk semua pekerja tanpa memandang jenis kontrak. Mandor:「最低賃金は毎年変わるから確認してくれよ」(upah minimum berubah tiap tahun, cek selalu).", _origIndex: 164 },
  { id: 174, category: "career", source: "jac-ch2", furi: "にんていくんれん", jp: "認定訓練（にんていくんれん）", romaji: "nintei kunren", id_text: "Pelatihan vokasi yang diakui gubernur prefektur", desc: "Pelatihan vokasi oleh pihak swasta yang diakui resmi gubernur prefektur; berbeda dari pelatihan pemerintah langsung. Mandor:「この研修は知事認定だから証書がもらえるぞ」(pelatihan diakui gubernur, dapat sertifikat).", _origIndex: 165 },
  { id: 175, category: "hourei", source: "jac-ch2", furi: "ほうていきゅうじつまいしゅうすくなくともいっかい", jp: "法定休日", romaji: "houtei kyuujitsu — maishuu sukunakutomo ikkai", id_text: "Hari libur wajib: minimal 1 hari per minggu", desc: "Hari libur yang ditetapkan UU: minimal 1 hari per minggu wajib diberikan. Bekerja di hari ini → upah +35% (休日出勤). Mandor:「週に1日は必ず休んでくれよ、法律で決まってるから」(minimal 1 hari libur per minggu, aturan UU).", _origIndex: 166 },
  { id: 176, category: "hourei", source: "jac-ch2", furi: "ゆうきゅうきゅうかのかいとりきんし", jp: "有給休暇の買い取り禁止", romaji: "yuukyuu kyuuka no kaitori kinshi", id_text: "Dilarang tukarkan cuti berbayar dengan uang", desc: "Pemberi kerja tidak boleh mengkonversi cuti berbayar menjadi uang tambahan. Cuti harus digunakan sebagai waktu istirahat. Mandor:「有給はお金に変えられないから、ちゃんと休んで使ってくれ」(cuti tidak bisa ditukar uang).", _origIndex: 167 },
  { id: 177, category: "hourei", source: "jac-ch2", furi: "けんこうしんだんていきねんいっかいとやといいれじ", jp: "健康診断", romaji: "kenkou shindan — teiki nen ikkai to yatoiire ji", id_text: "Cek kesehatan: 1x/tahun + saat rekrut baru", desc: "Perusahaan wajib selenggarakan pemeriksaan kesehatan 1x/tahun dan saat rekrut baru. Biaya ditanggung perusahaan. Mandor:「年1回の健康診断は会社が出すから必ず受けてくれよ」(medical check-up setahun sekali, wajib ikut).", _origIndex: 168 },
  { id: 192, category: "anzen", source: "jac-ch3", furi: "はっぱ", jp: "発破（はっぱ）", romaji: "happa", id_text: "Peledakan / blasting", desc: "Peledakan batu menggunakan bahan peledak (火薬類) dalam pekerjaan tambang, terowongan, atau galian batu. Untuk mengerjakan peledakan, wajib memiliki lisensi 発破技士.", _origIndex: 183 },
  { id: 199, category: "sekou", source: "jac-ch3", furi: "ようせつぶんるいゆうせつあっせつろうせつ", jp: "溶接の3分類（融接・圧接・ろう接）", romaji: "yousetsu 3 bunrui: yuusetsu assetsu rousetsu", id_text: "3 kategori pengelasan: fusion / pressure / brazing", desc: "融接=material dilelehkan (arc/gas/laser). 圧接=dipanaskan+ditekan tanpa cair, contoh: ガス圧接 tulangan. ろう接=logam penghubung bersuhu leleh rendah sebagai lem. Mandor:「融接箇所の検査します」(inspeksi las lebur).", _origIndex: 190 },
  { id: 202, category: "sekou", source: "jac-ch3", furi: "ばいぶれえたこんくりいとしめかため", jp: "バイブレータ（コンクリート締固め）", romaji: "baibureeta konkuriito shimekatame", id_text: "Vibrator untuk pemadatan beton", desc: "Alat getar dimasukkan ke beton segar untuk hilangkan gelembung (気泡) dan pastikan beton isi sudut bekisting (締固め). Mandor:「バイブレータちゃんと入れて、気泡抜いて」(masukkan vibrator, keluarkan gelembung).", _origIndex: 193 },
  { id: 208, category: "anzen", source: "jac-ch3", furi: "たまがけいじょうわぎのうこうしゅう", jp: "玉掛け（たまがけ）", romaji: "tamagake 1t ijou wa ginou koushuu", id_text: "Rigging (ikat beban crane): ≥1t wajib teknik", desc: "玉掛け=ikat beban ke kait crane. ≥1t wajib 技能講習. <1t cukup 特別教育. Kesalahan rigging bisa menyebabkan beban jatuh fatal. Mandor:「玉掛け資格ある人でやって」(kerjakan oleh pemegang sertifikat).", _origIndex: 199 },
  { id: 209, category: "hourei", source: "jac-ch3", furi: "しかくしゅるいこっかめんきょぎのうこうしゅうとくべつきょういく", jp: "資格の3種類：国家免許・技能講習・特別教育", romaji: "shikaku 3 shurui: kokka menkyo ginou koushuu tokubetsu kyouiku", id_text: "3 tingkat kualifikasi K3 konstruksi Jepang", desc: "①国家免許=lisensi negara (クレーン運転士 dll). ②技能講習修了証=lulus pelatihan terdaftar. ③特別教育=pelatihan khusus sebelum tugas berbahaya. Mandor:「この作業、技能講習持ってる人ですか」(punya sertifikat teknik?).", _origIndex: 200 },
  { id: 210, category: "hourei", source: "jac-ch3", furi: "はっぱぎしめんきょ", jp: "発破技士免許（はっぱぎし）", romaji: "happa gishi menkyo", id_text: "Lisensi juru peledak / blaster license", desc: "Untuk peledakan (発破) di konstruksi/tambang, wajib lisensi negara 発破技士. Tugas: bor, pasang bahan peledak, sambung kawat, nyalakan, tangani gagal ledak. Mandor:「発破技士いますか」(ada juru peledak?).", _origIndex: 201 },
  { id: 211, category: "sekou", source: "jac-ch3", furi: "かいたいこうじあべすとたいさく", jp: "解体工事（かいたい）", romaji: "kaitai kouji asbesuto taisaku", id_text: "Pekerjaan pembongkaran bangunan + penanganan asbes", desc: "アスベスト対策。Sebelum bongkar, survei asbes (石綿) wajib. Jika ada, dibongkar prosedur khusus. Limbah (解体ガラ) dipilah: beton, besi, berbahaya. Mandor:「石綿調査の結果出ましたか」(hasil survei asbes keluar?).", _origIndex: 202 },
  { id: 216, category: "anzen", source: "jac-ch3", furi: "たいるはりこうじらっかりすくたしょくしゅれんけい", jp: "タイル張り工事", romaji: "tairu hari kouji rakka risuku ta-shokushu renkei", id_text: "Pekerjaan ubin: risiko jatuh & koordinasi lintas", desc: "Ubin jatuh dari ketinggian berpotensi fatal. Koordinasi pipa (配管) dan listrik wajib sebelum tempel ubin. Mandor:「配管確認してから貼って」(cek pipa dulu baru tempel ubin).", _origIndex: 207 },
  { id: 224, category: "hourei", source: "jac-ch3", furi: "くれえんいどうしきくれえんしかくしきい", jp: "クレーン・移動式クレーン資格", romaji: "kureen idoushiki kureen shikaku shikii 5t 1t", id_text: "Lisensi crane: batas 5t dan 1t", desc: "クレーン: ≥5t→免許, 1〜5t→技能講習. 移動式: ≥5t→免許. 玉掛け: ≥1t→技能講習, <1t→特別教育. Angka kunci: 5t (免許) dan 1t (玉掛け). Mandor:「何トン吊りですか、資格確認して」(berapa ton angkat, cek lisensi).", _origIndex: 215 },
  { id: 225, category: "hourei", source: "jac-ch3", furi: "こうしょさぎょうしゃしかくきょうかい", jp: "高所作業車の資格境界", romaji: "kousho sagyousha shikaku kyoukai 10m", id_text: "Kendaraan ketinggian: ≥10m teknik, <10m khusus", desc: "作業床 ≥10m → 技能講習修了者. 作業床 <10m → 特別教育修了者. Angka kunci: 10m. Mandor:「高所作業車、10m以上なら技能講習ね」(≥10m butuh teknik).", _origIndex: 216 },
  { id: 226, category: "hourei", source: "jac-ch3", furi: "しゃりょうけいけんせつきかいしかくきょうかい", jp: "車両系建設機械の資格境界", romaji: "sharyoukei kensetsu kikai shikaku kyoukai 3t", id_text: "Alat berat: ≥3t teknik, <3t pendidikan khusus", desc: "Buldoser, backhoe, dll: 機体重量 ≥3t → 技能講習. <3t → 特別教育. Angka kunci: 3t. Berlaku mesin gali, angkut, bongkar. Mandor:「機体重量3t以上は技能講習持ってる人で」(≥3t harus bersertifikat).", _origIndex: 217 },
  { id: 227, category: "hourei", source: "jac-ch3", furi: "がすようせつさぎょうしゅにんしゃめんきょああくようせつさぎょうしゃとくべつきょういく", jp: "ガス溶接・アーク溶接の資格", romaji: "gasu yousetsu sagyou shuninsha menkyo vs aaku yousetsu sagyousha tokubetsu kyouiku", id_text: "Las gas: lisensi / Las arc: pendidikan khusus", desc: "ガス溶接作業主任者=免許(negara). ガス溶接作業者=技能講習. アーク溶接作業者=特別教育. Hierarki: 主任者>作業者. Mandor:「ガス溶接の主任者は免許持ってますよね」(pengawas las gas punya lisensi?).", _origIndex: 218 },
  { id: 231, category: "sekou", source: "jac-ch3", furi: "きかいどこうこうじだいひょうきかいぶるどおざあゆあつしょべるほいいるろおだあ", jp: "機械土工事の代表機械", romaji: "kikai dokou kouji daihyou kikai: burudoozaa yuatsu shoberu hoiiruroodaa", id_text: "Alat berat tanah: buldoser, excavator, loader", desc: "ブルドーザ=dorong tanah. 油圧ショベル=gali+muat ke dump truck. ホイールローダ=muat material. クラムシェル=gali bawah air. Mandor:「ショベルで掘って、すぐローダに積んで」(gali lalu muat).", _origIndex: 222 },
  { id: 233, category: "hourei", source: "jac-ch3", furi: "けんちくきじゅんほうたいしんきじゅんしんどきょうきょう", jp: "建築基準法の耐震基準", romaji: "kenchiku kijunhou taishin kijun: shindo 5kyou / 6kyou-7", id_text: "Standar tahan gempa UU Bangunan: 5kuat & 6kuat-7", desc: "震度5強→機能保持(tetap berfungsi). 震度6強〜7→倒壊しない(tidak runtuh). Angka kunci: 5強 dan 6強〜7. Mandor:「耐震補強の設計確認して」(cek desain penguatan tahan gempa).", _origIndex: 224 },
  { id: 241, category: "hourei", source: "jac-ch3", furi: "でんきこうじしいっしゅにしゅおおがたしせついっしゅ", jp: "電気工事士（一種・二種）", romaji: "denki koujishi isshu vs nishu: oogata shisetsu → isshu", id_text: "Lisensi teknisi listrik: kelas 1 vs kelas 2", desc: "二種=rumah/kecil (600V以下). 一種=gedung besar, pabrik, tegangan tinggi — wajib. Kerja tanpa lisensi = pelanggaran hukum. Mandor:「高圧工事は一種持ちでやって」(tegangan tinggi harus kelas 1).", _origIndex: 232 },
  { id: 242, category: "hourei", source: "jac-ch3", furi: "こうじたんにんしゃでんきつうしんしゅにんぎじゅつしゃ", jp: "工事担任者・電気通信主任技術者", romaji: "kouji tanninsha denki tsuushin shunin gijutsusha", id_text: "Lisensi telekomunikasi: penanggung jawab & teknis", desc: "Kesalahan instalasi telekomunikasi bisa sebabkan gangguan jaringan masif. ①工事担任者 dan ②電気通信主任技術者 adalah lisensi wajib — bukan sekadar 特別教育. Mandor:「工事担任者の資格証確認させて」(lihat sertifikat penanggung jawab).", _origIndex: 233 },
  { id: 243, category: "hourei", source: "jac-ch3", furi: "ごんどらそうさとくべつきょういくこうそうびるがいへきさぎょう", jp: "ゴンドラ操作", romaji: "gondora sousa → tokubetsu kyouiku: kousou biru gaiheki sagyou", id_text: "Gondola gedung tinggi → wajib pendidikan khusus", desc: "特別教育（高層ビルの外壁作業）。ゴンドラ=platform gantung untuk dinding luar gedung tinggi. Wajib 特別教育. Berbeda dari 高所作業車 yang berjalan di darat. Mandor:「ゴンドラ作業、特別教育受けてる人ですか」(sudah pelatihan khusus?).", _origIndex: 234 },
  { id: 244, category: "hourei", source: "jac-ch3", furi: "さんそけつぼうきけんさぎょうしゅにんしゃぎのうこうしゅうまんほおるちかどう", jp: "酸素欠乏危険作業主任者", romaji: "sanso ketsubou kiken sagyou shuninsha: ginou koushuu — manhooru chikadou", id_text: "Pengawas kerja O₂ rendah → wajib pelatihan teknik", desc: "技能講習（マンホール・地下道）。Manhole/tunnel = risiko 酸素欠乏症 dan 硫化水素中毒. Pengawas (作業主任者) wajib 技能講習. Pekerja biasa wajib 特別教育. Mandor:「地下道に入る前、酸欠の確認して」(cek kadar oksigen sebelum masuk).", _origIndex: 235 },
  { id: 245, category: "hourei", source: "jac-ch3", furi: "いしわたあすべすととりあつかいさぎょうしゃとくべつきょういく", jp: "石綿（アスベスト）取り扱い作業者", romaji: "ishiwata asubesuto toriatsukai sagyousha → tokubetsu kyouiku", id_text: "Pekerja asbes saat bongkar bangunan → khusus wajib", desc: "Bangunan lama mengandung 石綿 (asbes) dibongkar sangat hati-hati. Pekerja wajib 特別教育修了者 (石綿則第27条). Berbeda dari 石綿作業主任者 yang perlu 技能講習. Mandor:「石綿は飛散しないよう防護してくれ」(lindungi agar asbes tidak beterbangan).", _origIndex: 236 },
  { id: 246, category: "hourei", source: "jac-ch3", furi: "ゆうきようざいさぎょうしゅにんしゃぎのうこうしゅうしつないたんく", jp: "有機溶剤作業主任者", romaji: "yuuki youzai sagyou shuninsha → ginou koushuu: shitsunai tanku", id_text: "Pengawas pelarut organik → wajib pelatihan teknik", desc: "技能講習（室内タンク等）。Bekerja dengan 有機溶剤 di ruang dalam/tangki bisa sebabkan keracunan. Pengawas wajib 技能講習. Berlaku kadar pelarut >5%. Mandor:「有機溶剤使う前に換気して」(ventilasi dulu).", _origIndex: 237 },
  { id: 250, category: "sekou", source: "jac-ch4", furi: "たてずみしあげずみ", jp: "立て墨（たてずみ）・仕上げ墨（しあげずみ）", romaji: "tate zumi / shiage zumi", id_text: "Garis referensi vertikal / Garis dimensi finishing", desc: "立て墨=garis vertikal di dinding/kolom. 仕上げ墨=referensi dimensi finishing dari sumbu/permukaan struktural. Mandor:「立て墨と仕上げ墨の位置を確認して」.", _origIndex: 241 },
  { id: 251, category: "sekou", source: "jac-ch4", furi: "おやずみ", jp: "親墨（おやずみ）", romaji: "oya zumi", id_text: "Garis induk / garis referensi utama", desc: "Garis referensi utama seperti 通り芯 (sumbu kolom/dinding) dan 陸墨 (horizontal) yang menjadi DASAR untuk pekerjaan墨出し di tahap berikutnya. Disebut 'induk' karena semua garis lain diturunkan dari sini.", _origIndex: 242 },
  { id: 252, category: "sekou", source: "jac-ch4", furi: "かねをふるすみつけ", jp: "矩を振る（かねをふる）・墨付け（すみつけ）", romaji: "kane wo furu / sumitsuke", id_text: "Buat sudut 90° / penandaan kayu untuk dipotong", desc: "矩を振る=membuat garis sudut 90° di tahap 墨出し. 墨付け=memberi tanda pengerjaan pada kayu struktural. Mandor:「矩と墨付けを正確にやれ」.", _origIndex: 243 },
  { id: 253, category: "sekou", source: "jac-ch4", furi: "きじゅんずみ", jp: "基準墨（きじゅんずみ）", romaji: "kijun zumi", id_text: "Garis referensi dasar bangunan", desc: "Garis lurus horizontal/vertikal yang menjadi standar utama saat mendirikan bangunan. Dari garis ini, 通り芯 (sumbu kolom/dinding) diturunkan. Dibuat menggunakan墨つぼ tradisional atau laser墨出し器.", _origIndex: 244 },
  { id: 255, category: "sekou", source: "jac-ch4", furi: "たかさきごう", jp: "FH・SL・CH（高さ記号）", romaji: "FH / SL / CH", id_text: "FH = tinggi tanah / SL = slab / CH = plafon", desc: "FH=Formation Height (tinggi tanah rencana). SL=Slab Level (tinggi permukaan slab). CH=Ceiling Height (jarak FL ke plafon). Melengkapi GL/FL/BM. Mandor:「FHとSLとCHを図面で確認して」.", _origIndex: 246 },
  { id: 259, category: "sekou", source: "jac-ch4", furi: "ようへきやいたこうやいた", jp: "擁壁・矢板・鋼矢板", romaji: "youheki / yaita / kou yaita", id_text: "Dinding penahan tanah / papan turap / turap baja", desc: "擁壁=dinding penahan tanah. 矢板=papan penahan tanah. 鋼矢板=turap baja ujung alur sehingga bisa saling mengunci. Mandor:「鋼矢板の継ぎ目を確認して」.", _origIndex: 250 },
  { id: 261, category: "sekou", source: "jac-ch4", furi: "かまばみずかえまんぼう", jp: "釜場・水替え・万棒", romaji: "kamaba / mizukae / manbou", id_text: "Lubang pompa / pemompaan galian / hitungan masuk", desc: "釜場=lubang di dasar galian tempat pompa dipasang. 水替え=pompa air yang menggenang. 万棒=hitung jumlah truk/orang yang masuk lokasi. Mandor:「釜場のポンプを動かしておけよ」.", _origIndex: 252 },
  { id: 262, category: "sekou", source: "jac-ch4", furi: "じぎょうべたきそふうちんぐくいきそ", jp: "地業・ベタ基礎・フーチング・杭基礎", romaji: "jigyou / beta kiso / fuuchingu / kui kiso", id_text: "Pekerjaan pondasi / 3 jenis pondasi utama", desc: "地業=pekerjaan di bawah slab pondasi. ベタ基礎=cor beton seluruh dasar. フーチング=hanya di titik beban. 杭基礎=pondasi tiang di tanah lunak. Mandor:「転圧後に捨てコンを打てよ」.", _origIndex: 253 },
  { id: 263, category: "sekou", source: "jac-ch4", furi: "すらぶ", jp: "スラブ（構造スラブ・基礎スラブ・フラットスラブ）", romaji: "surabu", id_text: "Slab (pelat lantai/pondasi/tanpa balok)", desc: "スラブ = pelat datar pada bangunan (lantai, pondasi, dll). 構造スラブ = slab yang menopang bangunan. 基礎スラブ = slab di bagian pondasi. フラットスラブ = slab tanpa balok (梁なし).", _origIndex: 254 },
  { id: 265, category: "anzen", source: "jac-ch4", furi: "あしばのしゅるいわくぐみたんかんくさびきんけつしき", jp: "足場の種類：枠組み・単管・くさび", romaji: "ashiba no shurui: wakugumi / tankan / kusabi kinketsu shiki", id_text: "Jenis perancah: rangka / pipa tunggal / pasak", desc: "枠組み=rangka prefabrikasi. 単管=pipa tunggal, fleksibel. くさび緊結式=dikunci pasak, kuat dan cepat. Mandor:「足場の種類は作業内容に合わせて選んでくれ」.", _origIndex: 256 },
  { id: 266, category: "anzen", source: "jac-ch4", furi: "さぎょうゆかかりがこい", jp: "作業床（さぎょうゆか）・仮囲い（かりがこい）", romaji: "sagyouyuka / karigakoi", id_text: "Lantai kerja (perancah) / Pagar sementara lokasi", desc: "作業床=lantai perancah dari papan tempat pekerja berdiri. 仮囲い=pagar sementara lokasi dari jalan/lahan tetangga. Mandor:「作業床の隙間と仮囲いの固定を確認しろよ」.", _origIndex: 257 },
  { id: 269, category: "sekou", source: "jac-ch4", furi: "すてこんくりいとすてこん", jp: "捨てコンクリート（すてコン）", romaji: "sute konkuriito (sute kon)", id_text: "Beton lantai kerja (beton lean/blinding)", desc: "Beton tipis 5–10 cm dicor di atas 地業 sebelum tulangan dan bekisting dipasang. Membuat referensi ketinggian akurat dan permukaan rata. Mandor:「捨てコンの墨出しをしっかりやってくれ」.", _origIndex: 260 },
  { id: 270, category: "sekou", source: "jac-ch4", furi: "けっそくはっかあ", jp: "結束（けっそく）・ハッカー", romaji: "kessoku / hakkaa", id_text: "Pengikatan tulangan / Alat pengikat kawat besi", desc: "結束=mengikat persilangan tulangan dengan kawat 結束線 menggunakan ハッカー. Cara ikat: たすき掛け atau 片だすき. Mandor:「ハッカーの使い方を覚えてくれよ」.", _origIndex: 261 },
  { id: 271, category: "sekou", source: "jac-ch4", furi: "うちかさねうちつぎこおるどじょいんと", jp: "打ち重ね vs 打ち継ぎ", romaji: "uchi kasane vs uchitsugi / koorudo jointo", id_text: "Pengecoran di atas beton belum/sudah keras", desc: "打ち重ね=cor di atas beton BELUM keras; batas 150mnt (<25°C) atau 120mnt (≥25°C). Terlambat→コールドジョイント. 打ち継ぎ=cor di atas SUDAH keras. Mandor:「時間を守って打ち重ねろ」.", _origIndex: 262 },
  { id: 272, category: "anzen", source: "jac-ch4", furi: "ぱんくかたわくほうかい", jp: "パンク（型枠崩壊）", romaji: "panku (kata waku houkai)", id_text: "Pecahnya bekisting akibat tekanan beton", desc: "Bekisting pecah saat pengecoran karena 支保工 tidak kuat sehingga beton mengalir keluar. Berbahaya dan menyebabkan pemborosan besar. Mandor:「パンクしたらすぐ作業を止めて報告しろよ」.", _origIndex: 263 },
  { id: 273, category: "sekou", source: "jac-ch4", furi: "おさまりとりあい", jp: "納まり（おさまり）・取合い（とりあい）", romaji: "osamari / toriai", id_text: "Kerapian pemasangan / pertemuan dua elemen berbeda", desc: "納まり=keserasian tata letak elemen. 取合い=pertemuan dua elemen berbeda. Keduanya sering digunakan bersamaan. Mandor:「取合いの納まりが悪いから直してくれ」.", _origIndex: 264 },
  { id: 274, category: "sekou", source: "jac-ch4", furi: "つらいちふろくめちがい", jp: "面一・不陸・目違い", romaji: "tsura ichi / furoku / mechigai", id_text: "Rata sejajar / tidak rata / tepi tak sejajar", desc: "面一(つらいち)=dua permukaan dalam satu bidang rata. 不陸=permukaan bergelombang. 目違い=sambungan tile/papan yang tidak sejajar. Mandor:「面一になってるか確認してくれよ」.", _origIndex: 265 },
  { id: 275, category: "sekou", source: "jac-ch4", furi: "だめてなおしてもどりだんどり", jp: "駄目・手直し・手戻り・段取り", romaji: "dame / tenaoshi / temodori / dandori", id_text: "Pekerjaan sisa / koreksi / ulang / urutan kerja", desc: "駄目=pekerjaan terlewat saat hampir finishing. 手直し=koreksi sebagian. 手戻り=mengulang pekerjaan (buang waktu). 段取り=rencanakan urutan kerja. Mandor:「段取りして手戻りを減らせよ」.", _origIndex: 266 },
  { id: 276, category: "sekou", source: "jac-ch4", furi: "たっぱうわばしたば", jp: "建端（たっぱ）・上端・下端", romaji: "tappa / uwaba / shitaba", id_text: "Tinggi elemen / ujung atas / ujung bawah elemen", desc: "建端(たっぱ)=tinggi elemen. 上端=tepi atas elemen. 下端=tepi bawah elemen. Digunakan saat memberi instruksi pemasangan di lapangan. Mandor:「上端と下端の位置を確認してから取り付けて」.", _origIndex: 267 },
  { id: 277, category: "sekou", source: "jac-ch4", furi: "いっけんいっしゃくいっすんひとつぼ", jp: "一間・一尺・一寸・一坪", romaji: "ikken / isshaku / issun / hitotsubo", id_text: "1 ken≈1.8m / 1 shaku≈30cm / 1 tsubo≈3.3m²", desc: "Satuan lama yang masih dipakai: 1間≈1.818m, 1尺≈30.3cm, 1寸≈3.03cm. 1坪=1間×1間≈3.3m². Muncul dalam gambar tradisional. Mandor:「この部屋は3坪くらいだ」.", _origIndex: 268 },
  { id: 278, category: "sekou", source: "jac-ch4", furi: "ぴっち", jp: "ピッチ（割り付けの間隔）", romaji: "picchi", id_text: "Jarak pemasangan berulang / pitch antar elemen", desc: "Jarak antara elemen yang dipasang berulang: tulangan, baut, atau tile. Lebih umum dari 間隔. Contoh: ピッチ200mm. Mandor:「ピッチ200ミリで正確に並べてくれ」.", _origIndex: 269 },
  { id: 292, category: "career", source: "jac-ch4", furi: "ほうれんそうほうこくれんらくそうだん", jp: "ほうれんそう（報告・連絡・相談）", romaji: "houren sou (houkoku / renraku / soudan)", id_text: "Laporan / Komunikasi / Konsultasi — 3 pilar kerja", desc: "ほうれんそう=報告 (lapor ke atasan), 連絡 (sampaikan info/jadwal), 相談 (konsultasikan masalah). Sampaikan singkat dan jelas. Mandor:「問題があったらすぐ相談してくれよ」.", _origIndex: 283 },
  { id: 293, category: "career", source: "jac-ch4", furi: "さぎょういんつめしょのるうる", jp: "作業員詰め所（さぎょういんつめしょ）のルール", romaji: "sagyouin tsumesho no ruuru", id_text: "Aturan di ruang pekerja/ganti lokasi konstruksi", desc: "作業員詰め所=ruang ganti/istirahat pekerja. Aturan: merokok di tempat khusus, ポイ捨て禁止, helm di tempat ditentukan, barang di loker, cuci tangan, cek 掲示板. Mandor:「詰め所のルールを守ってくれよ」.", _origIndex: 284 },
  { id: 294, category: "sekou", source: "jac-ch4", furi: "みつけみえがかりみえかくれ", jp: "見付け・見え掛かり・見え隠れ", romaji: "mitsuke / miegakari / miekakure", id_text: "Tampak penuh / tampak sebagian / tampak bila gerak", desc: "見付け=permukaan yang sepenuhnya terlihat dari depan. 見え掛かり=tampak dari celah/sudut miring. 見え隠れ=tampak hanya saat sesuatu digeser. Mandor:「見付け部分は特に丁寧に仕上げてくれ」.", _origIndex: 285 },
  { id: 295, category: "sekou", source: "jac-ch4", furi: "そりむくりろく", jp: "反り vs 起り・陸", romaji: "sori vs mukuri / roku", id_text: "Melengkung cekung / cembung / horizontal sempurna", desc: "反り(そり)=melengkung CEKUNG. 起り(むくり)=melengkung CEMBUNG. 陸(ろく)=horizontal sempurna; 陸屋根=atap datar. Mandor:「この面が反っているから直してくれよ」.", _origIndex: 286 },
  { id: 296, category: "sekou", source: "jac-ch4", furi: "ころびにげ", jp: "転び（ころび）・逃げ（にげ）", romaji: "korobi / nige", id_text: "Elemen miring dari vertikal / toleransi dimensi", desc: "転び=kolom/dinding yang seharusnya tegak namun miring. 拝む=bangunan yang miring. 逃げ=toleransi dimensi yang SENGAJA diambil untuk menyerap kesalahan. Mandor:「柱が転んでいるから修正してくれ」.", _origIndex: 287 },
  { id: 297, category: "sekou", source: "jac-ch4", furi: "みきるみきりざえなじみ", jp: "見切る・見切り材・馴染み", romaji: "mikiru / mikirizable / najimi", id_text: "Selesaikan sambungan / penutup / kerapatan", desc: "見切る=selesaikan sambungan dua pekerjaan finishing. 見切り材=material penutup sambungan. 馴染み=kerapatan sambungan. Mandor:「見切り材の馴染みが悪いから直してくれ」.", _origIndex: 288 },
  { id: 298, category: "sekou", source: "jac-ch4", furi: "べたふかし", jp: "ベタ・ふかし（ふかす）", romaji: "beta / fukashi (fukasu)", id_text: "Menutup seluruh permukaan / penebalan finishing", desc: "ベタ=menutupi seluruh permukaan tanpa celah (contoh: ベタ塗り). ふかし=finishing dibuat lebih tebal/maju dari desain awal. Mandor:「ここはふかして仕上げをそろえてくれ」.", _origIndex: 289 },
  { id: 299, category: "sekou", source: "jac-ch4", furi: "とおりをみる", jp: "通り（とおり）を見る", romaji: "toori wo miru", id_text: "Mengecek kelurusan elemen", desc: "通り=kondisi lurus. 通りが悪い=bengkok. 通りを見る=memeriksa kelurusan dengan alat. Dipakai saat QC besi, dinding, kolom. Mandor:「柱の通りを見てくれよ、少し曲がってるぞ」.", _origIndex: 290 },
  { id: 300, category: "sekou", source: "jac-ch4", furi: "ひろいだし", jp: "拾い出し（ひろいだし）", romaji: "hiroi dashi", id_text: "Perhitungan kebutuhan material dari gambar", desc: "Proses membaca gambar kerja untuk menghitung jumlah material dan tenaga kerja. Mirip quantity take-off. Mandor:「拾い出しをしてから材料を発注してくれよ」.", _origIndex: 291 },
  { id: 301, category: "sekou", source: "jac-ch4", furi: "ばしょううちうつだせつする", jp: "場所打ち（ばしょうち）・打つ／打設する（だせつ）", romaji: "bashouuchi / utsu / dasetsu suru", id_text: "Pengecoran di lokasi / istilah menuang beton", desc: "場所打ち=beton yang dicor langsung di lokasi, bukan precast. 打つ/打設する=terminologi untuk menuang beton ke dalam bekisting. Mandor:「打設前に型枠を確認して」.", _origIndex: 292 },
  { id: 302, category: "sekou", source: "jac-ch4", furi: "のろあんこ", jp: "ノロ・アンコ", romaji: "noro / anko", id_text: "Adukan semen encer / penyumbat sementara bekisting", desc: "ノロ=campuran semen+air sangat encer; juga bocoran beton dari celah bekisting. アンコ=pengisi di bekisting untuk membentuk cekungan. Mandor:「ノロが漏れないよう型枠を締めてくれ」.", _origIndex: 293 },
  { id: 303, category: "sekou", source: "jac-ch4", furi: "てにょうくぎじまい", jp: "転用（てんよう）・釘仕舞", romaji: "tenyou / kugijimai", id_text: "Pemakaian ulang bekisting / pencabutan paku bekas", desc: "転用=memakai kembali bekisting di lokasi berbeda untuk hemat biaya. 釘仕舞=mencabut semua paku dari bekisting bekas agar bisa dipakai ulang. Mandor:「転用するなら釘仕舞をちゃんとやってくれ」.", _origIndex: 294 },
  { id: 304, category: "sekou", source: "jac-ch4", furi: "はいごうねりまぜたんぴんぐ", jp: "配合・練り混ぜ・タンピング", romaji: "haigou / nerimaze / tanpingu", id_text: "Rasio campuran beton / pengadukan / pemadatan slab", desc: "配合=perbandingan semen, pasir, kerikil, air. 練り混ぜ=mencampur hingga merata. タンピング=ketuk permukaan slab agar padat. Mandor:「配合は設計通りにして、タンピングも忘れずに」.", _origIndex: 295 },
  { id: 313, category: "sekou", source: "jac-ch4", furi: "ばりばりとり", jp: "バリ・バリ取り", romaji: "bari / bari tori", id_text: "Gerinda sisa pemotongan / proses membuangnya", desc: "バリ=tonjolan sisa material di tepi produk logam/plastik akibat pemotongan. バリ取り=membersihkan バリ agar permukaan rata dan aman. Mandor:「パイプを切ったらバリ取りをして怪我防止しろ」.", _origIndex: 304 },
  { id: 316, category: "anzen", source: "jac-ch4", furi: "ふくそうのちゅうい", jp: "服装の注意（ふくそうのちゅうい）4項目", romaji: "fukusou no chuui", id_text: "4 pantangan pakaian di lokasi konstruksi", desc: "4 larangan: ①半袖・短パン禁止 ②上着前開け禁止 (tersangkut) ③袖まくり禁止 (lengan ke pergelangan) ④ポケット手禁止 (tak bisa menahan saat jatuh). Mandor:「服装を整えて入場してくれ」.", _origIndex: 307 },
  { id: 317, category: "career", source: "jac-ch4", furi: "あとかたづけしょうかかくにん", jp: "後片付け・消火確認", romaji: "atokataduke / shouka kakunin", id_text: "Beres-beres setelah kerja / konfirmasi api padam", desc: "Setelah kerja selesai WAJIB beres-beres dengan mindset mempersiapkan段取り untuk esok. Jika pakai api, pastikan padam sebelum pulang. Mandor:「帰る前に火の元を必ず確認してくれよ」.", _origIndex: 308 },
  { id: 318, category: "sekou", source: "jac-ch4", furi: "すてざいりょう", jp: "捨て（すて）材料（ざいりょう）", romaji: "sute zairyou", id_text: "Material sacrificial untuk kelancaran konstruksi", desc: "捨て=material non-struktural untuk memudahkan 施工. Contoh: 捨てコン, 捨て板, 捨て石. Mandor:「捨てコンを打ってから墨出しをするんだよ」.", _origIndex: 309 },
  { id: 323, category: "sekou", source: "jac-ch4", furi: "おうすんぽう", jp: "追う（おう）・寸法（すんぽう）", romaji: "ou / sunpou", id_text: "Mengukur berurutan dari referensi / ukuran/dimensi", desc: "追う=mengukur posisi berurutan dari titik referensi. 寸法=ukuran atau dimensi panjang. Keduanya istilah dasar pengukuran di lapangan. Mandor:「基準から追って寸法を確認してくれよ」.", _origIndex: 314 },
  { id: 326, category: "sekou", source: "jac-ch4", furi: "つらかねおがむ", jp: "面（つら）・矩（かね）・拝む（おがむ）", romaji: "tsura / kane / ogamu", id_text: "Permukaan elemen / sudut siku / elemen yang miring", desc: "面(つら)=permukaan elemen bangunan. 矩(かね)=sudut siku-siku 90°. 拝む=elemen yang seharusnya tegak namun miring. Mandor:「柱が拝んでいるから、矩を確認してくれよ」.", _origIndex: 317 },
  { id: 327, category: "career", source: "jac-ch4", furi: "のかくていぎせいりせいとんせいそうせいけつしつけ", jp: "5Sの各定義：整理・整頓・清掃・清潔・しつけ", romaji: "5S no kaku teigi: seiri / seiton / seisou / seiketsu / shitsuke", id_text: "5 definisi individual kegiatan 5S", desc: "5S: ①整理=pilah perlu vs tidak. ②整頓=letakkan di tempat ditentukan. ③清掃=bersih setelah kerja. ④清潔=pertahankan bersih. ⑤しつけ=aturan agar ①–④ dilaksanakan semua orang. Mandor:「5Sを毎日全員でやってくれ」.", _origIndex: 318 },
  { id: 328, category: "gaiyou", source: "jac-ch4", furi: "おさきにしつれいします", jp: "お先に失礼します（おさきにしつれいします）", romaji: "osaki ni shitsurei shimasu", id_text: "Permisi, saya pulang lebih dulu", desc: "Diucapkan saat KAMU pulang lebih dulu dari rekan yang masih bekerja. Respons rekan: お疲れさまでした. Jangan ke atasan tanpa kalimat sopan. Mandor:「先に失礼します」→「お疲れさまでした！」.", _origIndex: 319 },
  { id: 330, category: "anzen", source: "jac-ch4", furi: "ぽいすてきんしがむをかみながらのさぎょうきんし", jp: "ポイ捨て禁止・ガムを噛みながらの作業禁止", romaji: "poi sute kinshi / gamu wo kaminagara no sagyou kinshi", id_text: "Dilarang buang sampah sembarangan / permen karet", desc: "ポイ捨て=buang sampah sembarangan — DILARANG. ガム禁止: ①risiko ポイ捨て ②jika benda jatuh mendadak bisa menggigit lidah. Mandor:「ガムを噛みながら作業するのは禁止だからな」.", _origIndex: 321 },
  { id: 331, category: "sekou", source: "jac-ch5", furi: "ろおどろおらあたいやろおらあしんどうろおらあ", jp: "ロードローラ・タイヤローラ・振動ローラ", romaji: "roodo rooraa / taiya rooraa / shindou rooraa", id_text: "Mesin pemadat: road roller / tire roller", desc: "ロードローラ = rol besi (untuk subgrade/subbase jalan); タイヤローラ = rol karet (tanah biasa, aspal); 振動ローラ = rol besi bergetar (efek kuat meski ukuran kecil).", _origIndex: 322 },
  { id: 332, category: "sekou", source: "jac-ch5", furi: "ほいいるろおだあ", jp: "ホイールローダ", romaji: "hoiiru roodaa", id_text: "Wheel loader (tire dozer / tire shovel)", desc: "Mesin pemuat material (tanah, batu) ke truk menggunakan bucket besar di depan, bergerak dengan roda ban. Berbeda dari バックホウ yang menggali ke belakang.", _origIndex: 323 },
  { id: 333, category: "sekou", source: "jac-ch5", furi: "たわあくれいんますとくらいんぐふろおあくらいみんぐ", jp: "タワークレーン", romaji: "tawaa kurein (masuto kuraingu vs furooa kuraimingu)", id_text: "Tower crane — 2 jenis naik ketinggian", desc: "マストクライング: kepala crane memanjat tiang (mast) yang diperpanjang. フロアークライミング: seluruh crane memanjat bangunan dari lantai ke lantai. Digunakan untuk gedung bertingkat tinggi.", _origIndex: 324 },
  { id: 365, category: "sekou", source: "jac-ch5", furi: "れいきゃくこいるおんすいこいる", jp: "冷却コイル vs 温水コイル", romaji: "reikyaku koiru vs onsui koiru", id_text: "Koil pendingin vs koil pemanas", desc: "冷却コイル = tabung berisi air dingin, dilewati udara untuk mendinginkan → digunakan saat 冷房 (AC pendingin). 温水コイル = tabung berisi air panas, memanaskan udara → digunakan saat 暖房 (pemanas).", _origIndex: 356 },
  { id: 370, category: "sekou", source: "jac-ch5", furi: "どりるどらいばあいんぱくとどらいばあ", jp: "ドリルドライバー vs インパクトドライバー", romaji: "doriru doraibaa vs inpakuto doraibaa", id_text: "Drill driver vs Impact driver", desc: "ドリルドライバー: dapat mengatur kecepatan putar dan torsi, untuk memasang sekrup dan bor. インパクトドライバー: punya mekanisme pukul (ハンマー) sehingga torsi lebih besar, kecepatan & torsi tetap.", _origIndex: 361 },
  { id: 371, category: "sekou", source: "jac-ch5", furi: "ぢすくぐらいんだあこうそくがたていそくがた", jp: "ディスクグラインダー（高速型 vs 低速型）", romaji: "disuku guraindaa (kousoku gata vs teisoku gata)", id_text: "Angle grinder: disc kecepatan tinggi untuk", desc: "Mengganti disc sesuai kebutuhan: memotong pipa metal/beton → disc putaran TINGGI (高速トルク型). Mengamplas / menghaluskan permukaan → disc putaran RENDAH (低速トルク型).", _origIndex: 362 },
  { id: 372, category: "anzen", source: "jac-ch5", furi: "まるのこきっくばっく", jp: "丸のこ", romaji: "maruno ko — kikku bakku", id_text: "Gergaji sirkel — bahaya kickback (gerakan mundur", desc: "Gergaji sirkel berputar tinggi — bahaya キックバック: alat bisa mental balik tiba-tiba. Di proyek: cek safety cover sebelum pakai. Mandor:「カバーを確認してから使え」(cek pelindung dulu).", _origIndex: 363 },
  { id: 373, category: "sekou", source: "jac-ch5", furi: "こうそくせつだんきちっぷそおせつだんき", jp: "高速切断機 vs チップソー切断機", romaji: "kousoku setsudan ki vs chippu soo setsudan ki", id_text: "High-speed cutter (mata gerinda) vs chip saw", desc: "チップソー切断機: menggunakan mata gergaji bundar (丸のこ刃), mata cepat aus. 高速切断機: menggunakan batu gerinda (砥石), mata jauh lebih tahan lama. Keduanya untuk memotong pipa metal, besi tulang, baja ringan.", _origIndex: 364 },
  { id: 374, category: "sekou", source: "jac-ch5", furi: "けんすこっぷかくすこっぷてこきんし", jp: "剣スコップ vs 角スコップ（てこ禁止）", romaji: "ken sukoppu vs kaku sukoppu (teko kinshi)", id_text: "Sekop runcing (menggali) vs Sekop rata (mengeruk)", desc: "剣スコップ: runcing, kaki bisa menginjak → gali tanah keras. 角スコップ: rata, tidak ada tempat injak → keruk tanah/aspal lunak. KEDUANYA dilarang sebagai tuas (てこ禁止).", _origIndex: 365 },
  { id: 375, category: "sekou", source: "jac-ch5", furi: "らんまばいぶろこんぱくたぷれえとこんぱくた", jp: "ランマ vs バイブロコンパクタ vs プレートコ", romaji: "ranma vs baiburo konpakuta vs pureeto konpakuta", id_text: "Rammer (tumbuk kuat) vs Vibratory compactor", desc: "ランマ: tumbuk kuat → pemadat dalam. バイブロコンパクタ: getaran, jangkauan luas. プレートコンパクタ: plat besar → ratakan permukaan. Mandor:「ランマで締め固めて」(pampat pakai rammer).", _origIndex: 366 },
  { id: 376, category: "sekou", source: "jac-ch5", furi: "れえざあすみだしきあかれえざあみどりれえざあ", jp: "レーザー墨出し器（赤レーザー vs 緑レーザー）", romaji: "reezaa sumidashi ki (aka reezaa vs midori reezaa)", id_text: "Laser level — garis acuan konstruksi: hijau lebih", desc: "Alat laser → garis acuan horizontal/vertikal di dinding, plafon, lantai. Laser HIJAU (緑) lebih jelas di tempat terang vs MERAH. Mandor:「緑レーザーで墨出しして」(tarik garis pakai laser hijau).", _origIndex: 367 },
  { id: 377, category: "sekou", source: "jac-ch5", furi: "すいへいき", jp: "水平器（すいへいき）", romaji: "suiheiki", id_text: "Waterpass / spirit level", desc: "Alat genggam untuk memeriksa apakah permukaan horizontal atau vertikal dengan melihat gelembung udara di tabung (気泡管). BERBEDA dari 水準器/レベル yang merupakan alat survei besar untuk menentukan elevasi.", _origIndex: 368 },
  { id: 378, category: "sekou", source: "jac-ch5", furi: "さしがねうらめんおもてめんのばい", jp: "さしがね（裏面 = 表面の√2 ≈ 1.414倍）", romaji: "sashigane (ura men = omote men no √2 ≒ 1.414 bai)", id_text: "Penggaris siku baja — sisi belakang = 1.414× sisi", desc: "Alat pengukur sudut siku-siku dari logam. Sisi depan (表面): skala meter biasa. Sisi belakang (裏面): skala 1.414× lebih besar dari depan, berguna menghitung diagonal papan kayu (teorema Pythagoras √2).", _origIndex: 369 },
  { id: 379, category: "sekou", source: "jac-ch4", furi: "みずいと", jp: "水糸（みずいと）", romaji: "mizuito", id_text: "Tali referensi — tidak mulur, untuk lurus & rata", desc: "Tali dari bahan tidak mudah mulur, direntangkan saat membangun pondasi atau pasang bata/blok untuk memastikan garis lurus dan ketinggian sama. Mandor:「水糸はピンと張ってから作業してくれ」.", _origIndex: 370 },
  { id: 380, category: "sekou", source: "jac-ch5", furi: "たがねはつりさぎょう", jp: "たがね（ハツリ作業）", romaji: "tagane (hatsuri sagyou)", id_text: "Pahat (chisel) — digunakan untuk (memecah beton", desc: "Batang berbentuk pahat yang dipukul dengan palu. Fungsi: ①memotong logam tipis ②ハツリ作業 (memecah/melubangi beton atau mengeruk mortar lama). Jenisnya: 平たがね, コンクリートたがね, 目切りたがね.", _origIndex: 371 },
  { id: 381, category: "sekou", source: "jac-ch5", furi: "ばあるてこのげんり", jp: "バール（てこの原理）", romaji: "baaru (teko no genri)", id_text: "Linggis / crowbar — memanfaatkan prinsip tuas", desc: "Alat logam berbentuk L yang digunakan sebagai pengungkit. Ujung L punya alur untuk mencabut paku (釘抜き). Dapat mengangkat benda berat, mencungkil, membongkar bekisting. バール besar disebut 大バール.", _origIndex: 372 },
  { id: 382, category: "sekou", source: "jac-ch5", furi: "へえんぶろっくればあほいすと", jp: "チェーンブロック vs レバーホイスト", romaji: "cheen burokku vs rebaa hoisuto", id_text: "Chain block (untuk mengangkat berat) vs lever", desc: "チェーンブロック: dipasang di kaki tiga (三脚) untuk mengangkat beban berat naik-turun. レバーホイスト: prinsip sama tapi lebih KECIL, digunakan untuk mengencangkan muatan (contoh: mengamankan backhoe di atas truk).", _origIndex: 373 },
  { id: 383, category: "sekou", source: "jac-ch5", furi: "わいやあろおぷたまかけようだいつけよう", jp: "ワイヤーロープ（玉掛け用・台付け用）", romaji: "waiyaa roopu (tamakake you / daitsuke you)", id_text: "Wire rope — untuk (slinging beban ke crane) dan", desc: "Tali baja dengan kekuatan tarik tinggi, tahan benturan, dan fleksibel. 両端加工済み = 玉掛け用 (mengaitkan beban ke crane/hook). 台付け用 = untuk mengikat/mengamankan muatan di atas kendaraan.", _origIndex: 374 },
  { id: 384, category: "sekou", source: "jac-ch5", furi: "しゃっくる", jp: "シャックル", romaji: "shakkuru", id_text: "Shackle — penghubung wire rope", desc: "Alat penghubung berbentuk U berulir yang digunakan dalam operasi pengangkatan (玉掛け) untuk menyambungkan wire rope atau rantai dengan beban.", _origIndex: 375 },
  { id: 385, category: "sekou", source: "jac-ch5", furi: "じゃっきねじしきはぐるましきゆあつしき", jp: "ジャッキ（ネジ式・歯車式・油圧式）", romaji: "jakki (neji shiki / haguruma shiki / yuatsu shiki)", id_text: "Jack — mengangkat beban berat dengan tenaga", desc: "Alat untuk mengangkat benda sangat berat dengan tenaga minimal. Ada 3 prinsip: ①ネジ式 (ulir) ②歯車式 (roda gigi) ③油圧式 (hidrolik). キリンジャッキ = tipe khusus ulir untuk mengangkat secara vertikal.", _origIndex: 376 },
  { id: 386, category: "anzen", source: "jac-ch5", furi: "はしごかくどやくどほじょうしゃひっす", jp: "はしご（角度 約75度・補助者必須）", romaji: "hashigo (kakudo yaku 75 do / hojousha hissu)", id_text: "Tangga sandar — sudut ±75°", desc: "Tangga sandar harus diletakkan pada sudut sekitar 75°. Sudut terlalu tegak → bahaya jatuh ke belakang. Sudut terlalu landai → tangga bisa patah. Selalu bekerja bersama asisten yang memegang tangga.", _origIndex: 377 },
  { id: 387, category: "anzen", source: "jac-ch7", furi: "きゃたつてんばんきんしまたぎきんし", jp: "脚立（きゃたつ）", romaji: "kyatatsu — tenban kinshi / matagi kinshi", id_text: "Tangga A — DILARANG berdiri/duduk di papan atas", desc: "天板禁止・またぎ禁止。Tangga lipat bentuk A. Tiga larangan: ①Dilarang DUDUK di papan atas (天板). ②Dilarang BERDIRI di papan atas. ③Dilarang bekerja sambil MENUNGGANGI (またぎ乗り) dua sisi.", _origIndex: 378 },
  { id: 388, category: "anzen", source: "jac-ch5", furi: "ろおりんぐたわあいどうしきあしば", jp: "ローリングタワー（移動式足場）", romaji: "rooringu tawaa (idoushiki ashiba)", id_text: "Rolling tower (scaffolding beroda)", desc: "Perancah bertingkat beroda (kastor di 4 sudut) untuk pekerjaan di ketinggian. Dapat dipindahkan. Memiliki standar keselamatan berdasarkan 労働安全衛生法. Berbeda dari 高所作業車 yang menggunakan kendaraan.", _origIndex: 379 },
  { id: 389, category: "sekou", source: "jac-ch5", furi: "もんきいれんちうわあごにちからをかけてまわす", jp: "モンキーレンチ（上あごに力をかけて回す）", romaji: "monkii renchi (uwa ago ni chikara wo kakete mawasu)", id_text: "Kunci inggris — putar ke arah RAHANG ATAS (upper", desc: "Kunci adjustable sesuai ukuran baut/mur. PENTING: gaya ke RAHANG ATAS (上あご) yang menyatu grip. Jika terbalik → rusak/cedera. Mandor:「上あごに力をかけて回せ」(putar tekan rahang atas).", _origIndex: 380 },
  { id: 390, category: "sekou", source: "jac-ch5", furi: "ようじょうようぽりしいと", jp: "養生用ポリシート", romaji: "youjou you pori shiito", id_text: "Polythene sheet untuk curing/proteksi", desc: "Lembaran film polyethylene tipis. Fungsi: ①mencegah kelembapan dari tanah saat pengecoran beton ②proteksi saat pengecatan ③melindungi dari hujan dan debu.", _origIndex: 381 },
  { id: 391, category: "anzen", source: "jac-ch5", furi: "すいちょくようじょうねっとすいへいようじょうねっと", jp: "垂直養生ネット vs 水平養生ネット", romaji: "suichoku youjou netto vs suihei youjou netto", id_text: "Jaring pengaman tegak (cegah material jatuh dari", desc: "垂直養生ネット = dipasang tegak di tepi perancah untuk mencegah material/benda terbang dari perancah. 水平養生ネット = dipasang horizontal untuk mencegah orang atau material jatuh dari tempat tinggi.", _origIndex: 382 },
  { id: 392, category: "sekou", source: "jac-ch5", furi: "とろばことろぶね", jp: "トロ箱（トロ舟）", romaji: "toro bako (toro bune)", id_text: "Bak mortar (tro box/trough)", desc: "Bak kokoh berbentuk persegi panjang untuk mencampur dan mengaduk semen, mortar, atau beton. Juga disebut トロ舟 atau 舟. Material di dalamnya diaduk dengan alat pengaduk atau sekop.", _origIndex: 383 },
  { id: 393, category: "sekou", source: "jac-ch5", furi: "くぎうちきこんぷれっしゃあしよう", jp: "釘打ち機（コンプレッサー使用）", romaji: "kugiuchi ki (konpuresshaa shiyou)", id_text: "Nail gun (menggunakan compressor", desc: "Alat untuk memukul paku menggunakan tekanan udara dari kompresor (コンプレッサー). Jauh lebih cepat dari memukul paku manual dengan palu. Kompresor = mesin yang memampatkan udara.", _origIndex: 384 },
  { id: 394, category: "sekou", source: "jac-ch5", furi: "ふぉおくりふと", jp: "フォークリフト", romaji: "fookku rifuto", id_text: "Forklift — kendaraan garpu hidrolik pemindah palet", desc: "Kendaraan dengan garpu (フォーク) naik-turun hidrolik untuk memindahkan palet/material. Di proyek: memindahkan tumpukan material dan bahan ke gudang.", _origIndex: 385 },
  { id: 395, category: "sekou", source: "jac-ch5", furi: "おやづなきんちょうき", jp: "親綱緊張器（おやづなきんちょうき）", romaji: "oyadzuna kinchouki", id_text: "Pengencang tali induk untuk pekerjaan ketinggian", desc: "Alat memasang tali induk (親綱) tempat kait harness pekerja agar tidak kendur. Di proyek: dipasang di atap atau scaffolding sebelum pekerja naik.", _origIndex: 386 },
  { id: 396, category: "sekou", source: "jac-ch5", furi: "ゆあつしょべる（ばっくほう）", jp: "油圧ショベル（バックホウ）", romaji: "yuatsu shoberu (bakkuhou)", id_text: "Excavator / backhoe — mesin penggali utama", desc: "Mesin penggali dengan boom, arm, dan bucket; upper body berputar (旋回体). Di proyek: menggali galian pondasi dan parit. Mandor:「バックホウで掘削して」(gali pakai excavator).", _origIndex: 387 },
  { id: 397, category: "sekou", source: "jac-ch5", furi: "とらくたあしょべる", jp: "トラクターショベル", romaji: "torakutaa shoberu", id_text: "Tractor shovel — bucket depan, ada tipe roda dan", desc: "Mesin bucket di depan untuk menyekop material ke dump truck. Tipe roda (ホイール) lebih lincah, tipe rantai (クローラ) untuk medan berat. Mandor:「ホイールローダで砂利を積んで」(muat kerikil pakai loader).", _origIndex: 388 },
  { id: 398, category: "sekou", source: "jac-ch5", furi: "とらっくくれいん vs くろおらくれいん", jp: "トラッククレーン vs クローラクレーン", romaji: "torakku kurein vs kuroora kurein", id_text: "Truck crane (di truk) vs Crawler crane (di", desc: "トラッククレーン = crane di atas truk, mobile di jalan. クローラクレーン = bergerak dengan rantai, bisa di salju atau tanah tidak rata. Di proyek: pilih sesuai medan. Mandor:「クローラクレーンを手配して」(pesan crawler crane).", _origIndex: 389 },
  { id: 419, category: "sekou", source: "jac-ch5", furi: "れしぷろそお", jp: "レシプロソー", romaji: "reshipuro soo", id_text: "Reciprocating saw — gergaji maju-mundur untuk", desc: "Gergaji elektrik dengan blade panjang bergerak maju-mundur. Berguna memotong di tempat sempit atau posisi sulit. Di proyek: memotong konduit lama atau rangka di area terbatas.", _origIndex: 410 },
  { id: 420, category: "sekou", source: "jac-ch5", furi: "だぶるすこっぷ（ふかいあなほりよう）", jp: "ダブルスコップ（深い穴掘り用）", romaji: "daburu sukoppu (fukai ana hori you)", id_text: "Post hole digger — gali lubang dalam untuk tiang", desc: "Sekop dua bilah menjepit tanah, memungkinkan menggali lubang dalam dan sempit secara vertikal. Di proyek: memasang tiang listrik atau pancang. Mandor:「ダブルスコップで穴を掘って」(gali lubang pakai double shovel).", _origIndex: 411 },
  { id: 421, category: "sekou", source: "jac-ch5", furi: "つるはし", jp: "つるはし（鶴嘴）", romaji: "tsuruhashi", id_text: "Pickaxe — untuk menggali tanah keras dan memecah", desc: "Alat kepala logam melengkung dua ujung, dipasang di gagang kayu. Di proyek: menggali tanah keras, batuan, atau memecah lapisan aspal. Mandor:「つるはしで掘り起こして」(gali/pecah pakai pickaxe).", _origIndex: 412 },
  { id: 423, category: "sekou", source: "jac-ch5", furi: "ちょおくらいん vs すみつぼ", jp: "チョークライン vs 墨つぼ", romaji: "chooku rain vs sumi tsubo", id_text: "Chalk line (kapur, mudah bersih) vs Sumitsubo", desc: "Keduanya untuk menarik garis lurus panjang. チョークライン = serbuk kapur, mudah dibersihkan. 墨つぼ = tinta hitam tradisional (墨), lebih permanen untuk kayu dan beton. Di proyek: pilih sesuai kebutuhan.", _origIndex: 414 },
  { id: 424, category: "sekou", source: "jac-ch5", furi: "ぽんち（せんたあぽんち）", jp: "ポンチ（センターポンチ）", romaji: "ponchi (sentaa ponchi)", id_text: "Center punch — buat cekungan di logam sebagai", desc: "Alat batang runcing dipukul palu untuk membuat cekungan kecil di permukaan logam (マーキング). Di proyek: menandai titik bor agar mata bor tidak bergeser.", _origIndex: 415 },
  { id: 425, category: "sekou", source: "jac-ch5", furi: "とらんしっと / せおどらいと", jp: "トランシット / セオドライト", romaji: "toranshitto / seodoraiito", id_text: "Transit / theodolite — ukur sudut horizontal &", desc: "Alat survei menggunakan teleskop untuk mengukur sudut horizontal dan vertikal dari titik referensi. Diletakkan di atas tripod. Di proyek: penentuan as bangunan dan peil.", _origIndex: 416 },
  { id: 426, category: "sekou", source: "jac-ch5", furi: "おおがね", jp: "おおがね（大矩）", romaji: "oogane", id_text: "Penggaris siku besar lapangan — rasio 3:4:5,", desc: "Segitiga siku besar untuk cek sudut 90° di lapangan. Dibuat dari 3 bahan dengan rasio 3:4:5 (teorema Pythagoras), dikenal sebagai 'サシゴ'. Di proyek: cek siku pondasi atau dinding.", _origIndex: 417 },
  { id: 427, category: "sekou", source: "jac-ch5", furi: "はんまあのしゅるい", jp: "ハンマーの種類", romaji: "hammaa no shurui", id_text: "Jenis palu: karet, kayu, kayu besar, sledgehammer", desc: "ゴムハンマー: tidak merusak permukaan. 木づち: kepala kayu tradisional. かけや: 木づち besar untuk pasak kayu besar. 大ハンマー: gagang panjang untuk pancang atau pembongkaran. Di proyek: pilih sesuai material.", _origIndex: 418 },
  { id: 428, category: "sekou", source: "jac-ch5", furi: "さんどぺえぱあ", jp: "サンドペーパー", romaji: "sando peepaa", id_text: "Amplas — nomor kecil = kasar, nomor besar = halus", desc: "Kertas amplas dengan partikel pasir/kaca. Nomor KECIL (#60) = kasar untuk material kasar. Nomor BESAR (#400) = halus untuk finishing. Ada 耐水ペーパー (tahan air) dan 布ペーパー (kain, lebih kuat).", _origIndex: 419 },
  { id: 429, category: "sekou", source: "jac-ch5", furi: "そけっとれんち / ぼっくすれんち / ろっかくれんち", jp: "ソケットレンチ / ボックスレンチ / 六角レンチ", romaji: "soketto renchi / bokkusu renchi / rokkaku renchi", id_text: "Socket wrench / Box wrench / Hex key (baut segi", desc: "ソケットレンチ = handle + kepala soket ganti-ganti. ボックスレンチ = soket menyatu dengan handle (L/T). 六角レンチ = batang heksagonal untuk baut berlubang segi enam. Di proyek: pilih sesuai baut.", _origIndex: 420 },
  { id: 430, category: "sekou", source: "jac-ch5", furi: "もるたるみきさ vs こんくりいとみきさ", jp: "モルタルミキサ vs コンクリートミキサ", romaji: "morutaru mikisa vs konkuriito mikisa", id_text: "Mortar mixer (semen+pasir) vs Concrete mixer", desc: "モルタルミキサ = mencampur semen, air, dan pasir → mortar. コンクリートミキサ = lebih kuat untuk beton. バッチミキサ = aduk satu batch per siklus. Di proyek: pilih sesuai campuran.", _origIndex: 421 },
  { id: 431, category: "sekou", source: "jac-ch5", furi: "たあんぶっくる", jp: "ターンバックル", romaji: "taanbukkuru", id_text: "Turnbuckle — pengencang kabel/kawat dengan", desc: "Alat logam berulir untuk mengencangkan atau memperpanjang tali, kabel, atau kawat dengan cara memutar badan tengahnya. Di proyek: mengatur tegangan kawat penopang scaffolding.", _origIndex: 422 },
  { id: 432, category: "sekou", source: "jac-ch5", furi: "ちるほおいる（しゅどうしきういんち）", jp: "チルホール（手動式ウインチ）", romaji: "chiruhooiru (shuudou shiki uinchi)", id_text: "Tirfor / come-along — winch manual tarik beban", desc: "Winch manual yang menarik wire rope melalui mekanisme lever. Di proyek: mengarahkan pohon saat ditebang atau menarik beban tanpa listrik. Mandor:「チルホールで引き寄せて」(tarik pakai tirfor).", _origIndex: 423 },
  { id: 433, category: "sekou", source: "jac-ch5", furi: "きりんじゃっき", jp: "キリンジャッキ", romaji: "kirin jakki", id_text: "Screw jack — angkat beban vertikal dengan prinsip", desc: "Jack yang menggunakan gaya dorong putaran ulir untuk mengangkat beban secara vertikal. Di proyek: juga digunakan dalam 山留め工事 untuk gaya horizontal pada penopang.", _origIndex: 424 },
  { id: 434, category: "sekou", source: "jac-ch5", furi: "ればあぶろっく", jp: "レバーブロック", romaji: "rebaa burokku", id_text: "Lever block — angkat/kencangkan beban; juga untuk", desc: "Mengangkat atau mengencangkan beban via lever+rantai. Di proyek: 建て入れ直し = menegakkan kolom baja agar benar-benar vertikal (垂直を出す). Mandor:「レバーブロックで引っ張って鉄骨を起こして」(tegakkan baja pakai lever block).", _origIndex: 425 },
  { id: 435, category: "anzen", source: "jac-ch5", furi: "かはんしきさぎょうだい（のびうま）", jp: "可搬式作業台（伸び馬）", romaji: "kahansiki sagyoudai (nobi uma)", id_text: "Portable work platform 'nobima' — kaki teleskopik", desc: "Platform kerja 2 kaki yang bisa disesuaikan panjangnya dengan platform di atas, dilengkapi railing (手すり). Di proyek: kerja di ketinggian rendah-sedang dalam ruangan.", _origIndex: 426 },
  { id: 436, category: "sekou", source: "jac-ch5", furi: "ぶろああ（そうふうき）", jp: "ブロアー（送風機）", romaji: "buroaa (souhuuki)", id_text: "Blower — kipas kuat untuk meniup debu, daun, dan", desc: "Alat elektrik menghasilkan aliran udara kencang untuk meniup dan mengumpulkan sampah ringan seperti daun, serbuk gergaji, atau debu konstruksi.", _origIndex: 427 },
  { id: 437, category: "sekou", source: "jac-ch5", furi: "ふぁん（そうふうき vs はいふうき）", jp: "ファン（送風機 vs 排風機）", romaji: "fan (souhuuki vs haihuuki)", id_text: "Fan: supply (dorong masuk) vs exhaust (keluar)", desc: "ファン = alat memberi energi ke udara dalam duct. 送風機 = mengirim udara dari luar ke dalam (supply). 排風機 = menghisap udara dari dalam ke luar (exhaust).", _origIndex: 428 },
  { id: 454, category: "sekou", source: "jac-ch5", furi: "れえき vs じょれん", jp: "レーキ vs ジョレン", romaji: "reeki vs joren", id_text: "Rake (meratakan tanah/aspal) vs Joren/hoe", desc: "レーキ = bergigi banyak untuk meratakan tanah atau kumpulkan daun (model tanpa gigi untuk aspal). ジョレン = mirip cangkul lebar untuk menggeser tanah atau puing. Di proyek: レーキ untuk finishing permukaan.", _origIndex: 445 },
  { id: 455, category: "sekou", source: "jac-ch5", furi: "のこぎり", jp: "のこぎり（のこ）", romaji: "nokogiri", id_text: "Gergaji — memotong kayu, logam, dan pipa", desc: "Alat dengan banyak mata pisau pada plat logam untuk memotong kayu, logam, dan pipa. Disingkat 'のこ' di lapangan. Di proyek: pilih jenis yang sesuai material yang dipotong.", _origIndex: 446 },
  { id: 456, category: "sekou", source: "jac-ch5", furi: "くいきり（にっぱあ）vs ぺんち", jp: "くい切り（ニッパー）vs ペンチ", romaji: "kui kiri (nippaa) vs penchi", id_text: "Diagonal cutter (potong kawat) vs Pliers (bengkok", desc: "くい切り (ニッパー) = memotong kawat, tulangan kecil, atau kepala paku. ペンチ = membengkokkan dan memotong sekaligus dengan bagian bergigi dan pemotong. Di proyek: ニッパー untuk kawat halus, ペンチ serbaguna.", _origIndex: 447 },
  { id: 457, category: "sekou", source: "jac-ch5", furi: "やすり + わいやあぶらし", jp: "やすり（金属用 / 木工用）+ ワイヤーブラシ", romaji: "yasuri + waiyaa burashi", id_text: "Kikir (logam atau kayu) + Wire brush (bersihkan", desc: "やすり = kikir mengamplas logam atau kayu, berbagai jenis sesuai material. ワイヤーブラシ = sikat kawat keras untuk: ①bersihkan karat ②kupas cat ③bersihkan sumbatan pada mata kikir.", _origIndex: 448 },
  { id: 458, category: "sekou", source: "jac-ch5", furi: "たっぴんぐねじ vs くぎのしゅるい", jp: "タッピングねじ vs 釘（くぎ）の種類", romaji: "tappingu neji vs kugi no shurui", id_text: "Tapping screw (buat ulir sendiri) vs berbagai", desc: "タッピングねじ = sekrup yang membuat alur ulir sendiri saat dikencangkan, tak butuh pre-tap. 釘 = paku dipukul palu; berbagai jenis: スクリュー釘, コンクリート釘, ケーシング釘, トタン釘. Di proyek: pilih sesuai material.", _origIndex: 449 },
  { id: 459, category: "sekou", source: "jac-ch5", furi: "ふるい", jp: "ふるい", romaji: "furui", id_text: "Saringan/ayakan — pilah material berdasarkan", desc: "Rangka dengan jaring kawat untuk memisahkan material berdasarkan ukuran, misal memisahkan tanah halus dari kerikil hasil galian. Di proyek: dipakai sebelum penggunaan agregat.", _origIndex: 450 },
  { id: 460, category: "sekou", source: "jac-ch5", furi: "うえす・ばけつ・ひしゃく", jp: "ウェス・バケツ・ひしゃく", romaji: "uesu / baketsu / hishaku", id_text: "Kain lap oli / Ember zinc-plated / Centong air", desc: "ウェス = kain mengelap oli atau bahan kimia. バケツ = ember konstruksi dari pelat besi berlapis seng (亜鉛鉄板製) agar tahan lama. ひしゃく = alat bergagang mengambil air dari ember/bak.", _origIndex: 451 },
  { id: 461, category: "sekou", source: "jac-ch5", furi: "ぶるうしいと vs べにや（ようじょうざいりょう）", jp: "ブルーシート vs ベニヤ（養生材料）", romaji: "buruu shiito vs beniya (youjou zairyou)", id_text: "Blue sheet (proteksi dari cat/debu) vs Plywood", desc: "ブルーシート = lembaran biru plastik melindungi lantai dari tetesan cat atau debu. ベニヤ = plywood tipis di lantai mencegah goresan akibat material berat. Keduanya 養生材料.", _origIndex: 452 },
  { id: 462, category: "sekou", source: "jac-ch5", furi: "そり vs ころ（じゅうりょうぶつのいどう）", jp: "そり vs ころ（重量物の移動）", romaji: "sori vs koro (juryoubutsu no idou)", id_text: "Sledge (tarik beban berat) vs Log rollers (geser", desc: "そり = rangka landai untuk menopang dan menarik beban berat. ころ = batang kayu/pipa bulat disusun di bawah benda berat untuk digeser memanfaatkan prinsip rolling.", _origIndex: 453 },
  { id: 463, category: "sekou", source: "jac-ch5", furi: "ほうき + ちりとり + ぶろああ", jp: "ほうき + ちりとり + ブロアー", romaji: "houki + chiritori + buroaa", id_text: "Sapu / Pengki (kumpulkan sampah) / Blower (tiup", desc: "ほうき = sapu untuk membersihkan lantai. ちりとり = pengki mengumpulkan sampah sapuan. ブロアー = penghasil angin kuat untuk meniup sampah ringan seperti daun atau serbuk.", _origIndex: 454 },
  { id: 464, category: "sekou", source: "jac-ch5", furi: "かはんしきさぎょうだい vs きゃたつ vs ろおりんぐたわあ", jp: "可搬式作業台 vs 脚立 vs ローリングタワー", romaji: "kahanshiki sagyoudai vs kyatatsu vs rooringu tawaa", id_text: "3 alat kerja ketinggian: meja teleskopik / tangga", desc: "可搬式作業台: kaki disesuaikan + platform + railing. 脚立: tangga A — DILARANG berdiri di papan atas. ローリングタワー: perancah multi-lantai beroda (castor 4 sudut). Di proyek: pilih sesuai ketinggian dan luas area.", _origIndex: 455 },
  { id: 469, category: "sekou", source: "jac-ch5", furi: "しゅうじんき vs しゅうじんまるのこ", jp: "集塵機 vs 集塵丸のこ", romaji: "shuujin ki vs shuujin maruno ko", id_text: "Dust collector vs Circular saw dengan penampung", desc: "集塵機 = mesin vakum khusus mengumpulkan debu halus (粉塵) saat memotong beton/keramik. 集塵丸のこ = gergaji sirkel dengan penampung debu: tipe ダストボックス atau disambung ke 集塵機 terpisah.", _origIndex: 460 },
  { id: 470, category: "anzen", source: "jac-ch3", furi: "こうしょさぎょうしゃばすけっとたかさめえとるいじょう", jp: "高所作業車（バスケット高さ 2m以上）", romaji: "kousho sagyousha (basuketto takasa 2 meetoru ijou)", id_text: "Aerial work platform (AWP): keranjang kerja ≥2m", desc: "Kendaraan dengan keranjang (バスケット) ke ≥2m via boom/scissor. ≥10m butuh 技能講習, <10m cukup 特別教育. Mandor:「高所作業車の点検記録見せて」(tunjukkan catatan inspeksi).", _origIndex: 461 },
  { id: 471, category: "sekou", source: "jac-ch5", furi: "でんどうぶろっくかったあ vs まるのこ", jp: "電動ブロックカッター vs 丸のこ", romaji: "dendou burokku kattaa vs maruno ko", id_text: "Electric block cutter (beton/blok) vs Circular", desc: "電動ブロックカッター = khusus memotong material berbasis beton, blok, atau paving. 丸のこ = gergaji sirkel serba guna untuk kayu, logam, dan bahan umum. Di proyek: pilih sesuai material.", _origIndex: 462 },
  { id: 472, category: "sekou", source: "jac-ch5", furi: "さげふり", jp: "下げ振り（さげふり）", romaji: "sagefuri", id_text: "Plumb bob — bandul cek vertikalitas kolom dan", desc: "Bandul logam runcing digantung dengan tali untuk memeriksa apakah kolom/dinding tegak lurus (垂直). Dipasang pada 下げ振り保持器 di atas kolom, jarak tali ke permukaan diukur dari atas dan bawah.", _origIndex: 463 },
  { id: 473, category: "sekou", source: "jac-ch5", furi: "だんぷとらっく", jp: "ダンプトラック", romaji: "danpu torakku", id_text: "Dump truck — angkut tanah/batu dengan bak yang", desc: "Kendaraan pengangkut tanah dan batuan dengan bak (荷台) yang bisa dimiringkan untuk membuang muatan. Di proyek: dikombinasikan dengan excavator atau wheel loader.", _origIndex: 464 },
  { id: 489, category: "sekou", source: "jac-ch3", furi: "といし", jp: "砥石（といし）", romaji: "toishi", id_text: "Batu asah untuk pahat, ketam, dan alat tajam", desc: "Batu untuk mengasah logam atau batu (切削・磨く). Balok kecil (直方体) digunakan untuk mengasah のみ (pahat) atau かんな (ketam kayu) agar tetap tajam. Mandor:「のみの刃、砥石で研いどいて」(asah mata pahat pakai batu asah).", _origIndex: 480 },
  { id: 490, category: "sekou", source: "jac-ch5", furi: "どらいばあ（ぷらす・まいなす）", jp: "ドライバー（プラス・マイナス）", romaji: "doraibaa (purasu / mainasu)", id_text: "Obeng — Phillips (+) dan flathead (−); pilih", desc: "Alat memutar sekrup (ネジ). プラス = Phillips, マイナス = flathead. Gunakan ukuran TEPAT agar alur tidak rusak (なめる). 電工用: grip besar dan bulat untuk genggaman kuat.", _origIndex: 481 },
  { id: 491, category: "sekou", source: "jac-ch5", furi: "ぼると・なっと・わっしゃあ", jp: "ボルト・ナット・ワッシャー", romaji: "boruto / natto / wasshaa", id_text: "Bolt + nut + washer — tiga komponen pengikat satu", desc: "ボルト (おねじ) + ナット (めねじ) = sepasang pengunci. ワッシャー dipasang di antara keduanya mencegah kerusakan permukaan dan mengurangi risiko kendor.", _origIndex: 482 },
  { id: 492, category: "sekou", source: "jac-ch6", furi: "とちのせいやく", jp: "土地の制約（とちのせいやく）", romaji: "tochi no seiyaku", id_text: "Karakteristik konstruksi: terikat pada lahan", desc: "Setiap proyek melekat pada lahan unik sehingga kondisi identik tidak pernah berulang; berbeda dari produksi pabrik. Di proyek: perencanaan harus menyesuaikan kondisi lahan spesifik.", _origIndex: 483 },
  { id: 493, category: "sekou", source: "jac-ch6", furi: "しぜんじょうけんによるえいきょう", jp: "自然条件による影響", romaji: "shizen jouken ni yoru eikyou", id_text: "Karakteristik konstruksi: dipengaruhi kondisi alam", desc: "Pekerjaan konstruksi umumnya di luar ruangan sehingga terpengaruh topografi, musim, dan cuaca — faktor yang tidak sepenuhnya bisa dikendalikan. Di proyek: jadwal menyesuaikan cuaca.", _origIndex: 484 },
  { id: 494, category: "sekou", source: "jac-ch6", furi: "しゃかいてきせいやく", jp: "社会的制約（しゃかいてきせいやく）", romaji: "shakai teki seiyaku", id_text: "Karakteristik konstruksi: terikat regulasi sosial", desc: "Karena produksi di lokasi asli (現地生産), wajib memenuhi peraturan keselamatan dan lingkungan; hukum dan lingkungan sosial berbeda tiap lokasi. Di proyek: izin dan aturan warga sekitar.", _origIndex: 485 },
  { id: 495, category: "sekou", source: "jac-ch6", furi: "せこうけいかく", jp: "施工計画（せこうけいかく）", romaji: "sekou keikaku", id_text: "Rencana pelaksanaan konstruksi", desc: "Rencana berdasarkan dokumen desain untuk mengerjakan konstruksi: kualitas baik, biaya minimal, tepat waktu, nol kecelakaan, dan ramah lingkungan.", _origIndex: 486 },
  { id: 496, category: "sekou", source: "jac-ch6", furi: "せこうようりょうしょ", jp: "施工要領書（せこうようりょうしょ）", romaji: "sekou youryou sho", id_text: "Dokumen prosedur pelaksanaan pekerjaan harian", desc: "Memuat detail teknis pelaksanaan pekerjaan: konfirmasi gambar, kondisi lapangan, urutan kerja, penempatan tenaga, serta persiapan alat dan material. Wajib dipahami sebelum memulai pekerjaan hari itu.", _origIndex: 487 },
  { id: 497, category: "career", source: "jac-ch6", furi: "きゃりああっぷかあど・さぎょうめんきょ", jp: "キャリアアップカード・作業免許", romaji: "kyaria appu kaado / sagyou menkyo no keitai", id_text: "Kartu CCAS & izin kerja — wajib dibawa saat", desc: "Item konfirmasi sebelum施工: wajib memastikan pekerja membawa kartu CCAS (キャリアアップカード) dan semua lisensi/sertifikat yang diperlukan hari itu. Di proyek: dicek di morning briefing.", _origIndex: 488 },
  { id: 498, category: "anzen", source: "jac-ch6", furi: "ひんしつかんり", jp: "品質管理（ひんしつかんり）", romaji: "hinshitsu kanri", id_text: "Manajemen kualitas — Q dalam QCDSE", desc: "QCDSE の Q。Manajemen untuk memenuhi kualitas yang diminta pemberi kerja; mencakup inspeksi kualitas, uji material, uji konstruksi, serta kontrol dimensi dan bentuk sesuai rencana kualitas.", _origIndex: 489 },
  { id: 499, category: "anzen", source: "jac-ch6", furi: "よさんのかんり", jp: "予算の管理（よさんのかんり）", romaji: "yosan no kanri", id_text: "Manajemen biaya — C dalam QCDSE", desc: "QCDSE の C。Mengelola dana yang tersedia di lapangan (biaya material, tenaga kerja, biaya lapangan) agar tidak melampaui anggaran proyek yang ditetapkan.", _origIndex: 490 },
  { id: 500, category: "anzen", source: "jac-ch6", furi: "こうていかんり", jp: "工程管理（こうていかんり）", romaji: "koutei kanri", id_text: "Manajemen jadwal — D dalam QCDSE", desc: "QCDSE の D。Koordinasi dengan kontraktor utama dan kontraktor lain agar pekerjaan selesai dalam batas waktu kontrak (工期内) tanpa keterlambatan.", _origIndex: 491 },
  { id: 501, category: "anzen", source: "jac-ch6", furi: "あんぜんかんり", jp: "安全管理（あんぜんかんり）", romaji: "anzen kanri", id_text: "Manajemen keselamatan — S dalam QCDSE", desc: "QCDSE の S。Mencakup pencegahan jatuh, benda jatuh, dan penyakit akibat kerja; dilaksanakan melalui KY training harian, patroli, rapat keselamatan 5S, dan target nol kecelakaan (無事故・無災害).", _origIndex: 492 },
  { id: 502, category: "anzen", source: "jac-ch6", furi: "かんきょうほぜんかんり", jp: "環境保全管理（かんきょうほぜんかんり）", romaji: "kankyou hozen kanri", id_text: "Manajemen pelestarian lingkungan — E dalam QCDSE", desc: "QCDSE の E。Meminimalkan dampak kebisingan, getaran, dan pencemaran air akibat konstruksi; wajib mematuhi standar yang ditetapkan undang-undang dan peraturan daerah.", _origIndex: 493 },
  { id: 503, category: "sekou", source: "jac-ch6", furi: "れえざあしょうしゃき", jp: "レーザー照射器", romaji: "reezaa shousha ki", id_text: "Alat laser untuk sumidashi — penanda posisi dan", desc: "Memancarkan cahaya laser menggantikan 墨つぼ konvensional; memudahkan pengecekan sudut siku (直角) dan kerataan horizontal (水平) dengan cepat dan akurat. Mandor:「レーザーで墨を出して」(tandai posisi pakai laser).", _origIndex: 494 },
  { id: 504, category: "sekou", source: "jac-ch6", furi: "きじゅんすみ・おやすみ", jp: "基準墨・親墨（きじゅんすみ）", romaji: "kijun sumi / oya sumi", id_text: "3 jenis sumidashi: acuan / komponen / posisi", desc: "①基準墨・親墨 = posisi, ketinggian (GL/FL), dan通り芯 sebagai acuan utama. ②部材加工用墨付け = marking dimensi komponen. ③取付け位置出し = posisi pemasangan perangkat. Mandor:「基準墨を出してから始めて」(buat acuan garis dulu).", _origIndex: 495 },
  { id: 506, category: "sekou", source: "jac-ch6", furi: "ばんどそおかんせつだんき", jp: "バンドソー管切断機", romaji: "bandosoo kan setsudan ki", id_text: "Mesin band saw pemotong pipa — hasil tegak lurus", desc: "Digunakan memotong pipa baja secara tegak lurus. Penyimpangan ≥1,0 mm berupa 斜め切れ (miring) atau 段切れ (bertangga) menjadi penyebab kebocoran air.", _origIndex: 497 },
  { id: 508, category: "anzen", source: "jac-ch6", furi: "ぐんてでのねじかこうぜったいきんし", jp: "軍手でのねじ加工は絶対禁止", romaji: "gunte de no neji kakou zettai kinshi", id_text: "Sarung tangan kain saat mengulir pipa: DILARANG", desc: "Menggunakan 軍手 (sarung tangan kain) saat mengoperasikan mesin ulir sangat berbahaya — tangan bisa tersangkut dan tergulung mesin. Larangan mutlak (絶対にしてはいけない).", _origIndex: 499 },
  { id: 512, category: "sekou", source: "jac-ch6", furi: "ねじげえじけんさたいみんぐぱたあん", jp: "ねじゲージ", romaji: "neji geeji — kensa taimingu 5 pataan", id_text: "Thread gauge — 5 momen wajib inspeksi ulir pipa", desc: "検査タイミング5パターン。Wajib periksa: ①3 uliran pertama, ②setiap ukuran pipa berubah, ③per ~50 uliran (untuk 25A), ④saat lot/merek pipa berubah, ⑤saat チェーザ (mata potong) diganti.", _origIndex: 503 },
  { id: 513, category: "sekou", source: "jac-ch6", furi: "へえざ", jp: "チェーザ（ねじ切り盤の切削工具）", romaji: "cheeza", id_text: "Chaser — mata potong pada mesin pengulir pipa", desc: "Komponen pada ねじ切り機 yang memotong ulir pada pipa; kondisinya mempengaruhi akurasi ulir. Setiap penggantian チェーザ wajib dilakukan pemeriksaan dengan ねじゲージ.", _origIndex: 504 },
  { id: 522, category: "anzen", source: "jac-ch6", furi: "らいにんぐこうかんのがすようだんぜったいきんし", jp: "ライニング鋼管のガス溶断絶対禁止", romaji: "rainingu koukan no gasu youdan zettai kinshi", id_text: "DILARANG: potong pipa lining dengan oxy-acetylene", desc: "Pemotongan ライニング鋼管 dengan ガス溶断 atau panas tinggi adalah LARANGAN MUTLAK — panas merusak lapisan lining. Di proyek: gunakan band saw atau metal saw. Mandor:「ライニング管はバンドソーで切って」(potong pakai band saw).", _origIndex: 513 },
  { id: 525, category: "anzen", source: "jac-ch6", furi: "どうかんのせつだんにかのこぐらいんだあきんし", jp: "銅管の切断に金ノコ・グラインダー禁止", romaji: "doukan no setsudan ni kanoko / guraindaa shiyou kinshi", id_text: "DILARANG: potong pipa tembaga pakai gergaji", desc: "Memotong pipa tembaga (銅管) dengan 金ノコ atau グラインダー menghasilkan serbuk logam yang tertinggal di dalam pipa refrigeran. Di proyek: gunakan パイプカッター.", _origIndex: 516 },
  { id: 540, category: "anzen", source: "jac-ch6", furi: "こうそくといしたいぷのせつだんこうぐ", jp: "高速砥石タイプの切断工具", romaji: "kousoku toishi taipu no setsudan kougu", id_text: "DILARANG: pakai grinder potong pipa polietilen", desc: "Panas dari grinder dapat mendistorsi permukaan potongan pipa polietilen yang dipakai untuk EF接合. Di proyek: gunakan alat potong mekanis atau hand saw.", _origIndex: 531 },
  { id: 541, category: "anzen", source: "jac-ch6", furi: "ちかまいせつぶつひょうじしいとのいろこおど", jp: "地下埋設物表示シートの色コード", romaji: "chika maisetsumono hyouji shiito iro koodo", id_text: "Kode warna lembar penanda utilitas bawah tanah", desc: "Dipasang antara utilitas dan permukaan tanah sebagai peringatan saat penggalian. Kode warna: 通信=赤, 高低圧電力=橙, 水道=青, 下水道=茶, ガス=緑. Mandor:「掘削前に埋設物表示シートを確認して」(cek lembar penanda sebelum gali).", _origIndex: 532 },
  { id: 542, category: "anzen", source: "jac-ch6", furi: "きそんまいせつかんしゅうへんごじゅっせんちいないはじんりきくっさく", jp: "既存埋設管周辺50cm以内は人力掘削", romaji: "kison maisetsukan shuuhen 50cm inai wa jinriki kussaku", id_text: "Radius 50 cm dari utilitas bawah tanah: wajib", desc: "Dalam radius 50 cm dari utilitas yang sudah ada wajib beralih ke penggalian manual (人力). Kecelakaan oleh backhoe menyumbang lebih dari separuh insiden pemutusan utilitas.", _origIndex: 533 },
  { id: 543, category: "anzen", source: "jac-ch6", furi: "さんそけつぼうきけんさぎょうしゅにんしゃ", jp: "酸素欠乏危険作業主任者", romaji: "sanso ketsubou kiken sagyou shuninsha", id_text: "Kepala kerja area rendah oksigen — wajib masuk", desc: "Yang boleh masuk manhole hanya pemegang 第一/二種酸素欠乏危険作業主任者技能講習 atau lulusan pendidikan khusus. Di proyek: O₂ harus ≥18%, H₂S ≤10 ppm setelah ventilasi. Mandor:「酸素濃度を計測してから入って」(ukur kadar oksigen dulu).", _origIndex: 534 },
  { id: 544, category: "anzen", source: "jac-ch6", furi: "りゅうかすいそのうど", jp: "硫化水素濃度（りゅうかすいそのうど）", romaji: "ryuuka suiso noudo", id_text: "Batas konsentrasi H₂S di manhole: ≤10 ppm", desc: "Sebelum masuk manhole: O₂ harus ≥18% DAN H₂S ≤10 ppm. Jika ventilasi tidak memungkinkan, wajib pakai 呼吸用保護具. Wajib pakai 墜落制止用器具 meski ketinggian ≤2 m.", _origIndex: 535 },
  { id: 545, category: "sekou", source: "jac-ch6", furi: "けがきはりでばいだ", jp: "ケガキ針 / デバイダ（けがきばり / デバイダ）", romaji: "kegaki hari / debaida", id_text: "Jarum garis / jangka — alat marking plat logam", desc: "ケガキ針 = jarum untuk menggambar garis tanda pada plat logam (digunakan bersama penggaris logam); デバイダ = jangka untuk menandai jarak atau radius yang sama. Lakukan marking satu kali semaksimal mungkin.", _origIndex: 536 },
  { id: 546, category: "sekou", source: "jac-ch6", furi: "かなとこじょうばん", jp: "金床（アンビル）/ 定盤（じょうばん）", romaji: "kanatoko (anbiru) / jouban", id_text: "Anvil / surface plate — landasan tekuk plat baja", desc: "Landasan baja keras untuk membengkokkan plat logam; sudut pinggir 定盤 digunakan sebagai tumpuan saat memukul plat dengan 影たがね + ハンマー untuk membentuk sudut yang diperlukan secara bertahap.", _origIndex: 537 },
  { id: 557, category: "anzen", source: "jac-ch6", furi: "かくうせんのせつだんじこ", jp: "架空線の切断事故", romaji: "kakuusen no setsudan jiko", id_text: "Kecelakaan pemotongan kabel overhead oleh alat", desc: "Terjadi saat boom alat berat, dump truck terangkat, atau saat loading/unloading tidak memperhatikan kabel overhead. Di proyek: pasang ケーブルカバー pada kabel di atas area kerja.", _origIndex: 548 },
  { id: 558, category: "anzen", source: "jac-ch6", furi: "どうろしようきょかしょう", jp: "道路使用許可証", romaji: "douro shiyou kyoka shou", id_text: "Surat izin penggunaan jalan — wajib dibawa", desc: "作業責任者 wajib membawa surat ini; kondisi izin (jam kerja, syarat) harus dipatuhi. Wajib menempatkan 交通整理員, memasang fasilitas keselamatan, dan memastikan pejalan kaki bisa lewat.", _origIndex: 549 },
  { id: 559, category: "anzen", source: "jac-ch6", furi: "かくうせつびのちじょうこう", jp: "架空設備の地上高", romaji: "kakuu setsubi no chijou kou", id_text: "Ketinggian kabel overhead di atas jalan raya: min", desc: "Untuk keselamatan lalu lintas, tinggi minimum kabel dan perangkat telekomunikasi di tiang di atas jalan raya adalah 5 m dari permukaan jalan. Di proyek: pastikan sebelum instalasi tiang.", _origIndex: 550 },
  { id: 572, category: "career", source: "jac-ch1", furi: "せこうたいせい", jp: "施工体制（せこうたいせい）", romaji: "sekou taisei", id_text: "Struktur manajemen pelaksanaan konstruksi", desc: "Hierarki konstruksi: 発注者→監理者→ゼネコン→専門工事業者→職長→作業員. Proyek besar dipimpin ゼネコン, proyek kecil oleh 工務店. Mandor:「ゼネコンの現場監督の指示に従ってくれよ」(ikuti instruksi site supervisor dari GC).", _origIndex: 563 },
  { id: 573, category: "career", source: "jac-ch1", furi: "はっちゅうしゃ", jp: "発注者（はっちゅうしゃ）", romaji: "hacchuusha", id_text: "Pihak pemberi order konstruksi (klien)", desc: "Pihak yang memesan pekerjaan konstruksi (klien/owner). Bisa berupa kementerian, pemda, perusahaan swasta, atau perorangan. Mandor:「発注者の要求に応えるのが私たちの仕事だ」(memenuhi kebutuhan klien adalah pekerjaan kita).", _origIndex: 564 },
  { id: 574, category: "career", source: "jac-ch1", furi: "かんりしゃ", jp: "監理者（かんりしゃ）", romaji: "kanrisha", id_text: "Pengawas konstruksi — memeriksa kesesuaian gambar", desc: "Teknisi yang memastikan pekerjaan sesuai gambar/blueprint. Posisi terpisah dari 設計者 maupun 現場監督. Mandor:「監理者から指摘があったらすぐ俺に報告してくれ」(ada koreksi dari pengawas, langsung lapor ke saya).", _origIndex: 565 },
  { id: 575, category: "career", source: "jac-ch1", furi: "せっけいしゃ", jp: "設計者（せっけいしゃ）", romaji: "sekkeisha", id_text: "Perancang / Desainer — membuat dokumen desain", desc: "Teknisi yang membuat dokumen desain untuk mewujudkan permintaan klien. Semua pekerjaan wajib sesuai 設計図書. Mandor:「図面に疑問があったら勝手に変えるな、確認が必要だ」(pertanyaan soal gambar, jangan ubah sendiri).", _origIndex: 566 },
  { id: 576, category: "career", source: "jac-ch1", furi: "ぜんこん", jp: "ゼネコン（工事全体をまとめる会社）", romaji: "zenkon", id_text: "General Contractor — perusahaan pemimpin proyek", desc: "Singkatan General Contractor; mengelola semua 専門工事業者 sebagai 元請け di proyek besar. Mandor:「ゼネコンからの指示は最優先で対応してくれよ」(instruksi dari general contractor diutamakan).", _origIndex: 567 },
  { id: 577, category: "career", source: "jac-ch1", furi: "げんばかんとく", jp: "現場監督（げんばかんとく）", romaji: "genba kantoku", id_text: "Pengawas lapangan (site supervisor)", desc: "Teknisi yang mengawasi pekerjaan di lokasi konstruksi. Berkoordinasi dengan 職長 yang meneruskan instruksi ke 技能者. Mandor:「今日の指示は朝のミーティングでもらうぞ」(instruksi hari ini dari site supervisor setiap pagi).", _origIndex: 568 },
  { id: 578, category: "career", source: "jac-ch1", furi: "せんもんこうじぎょうしゃ", jp: "専門工事業者（せんもんこうじぎょうしゃ）", romaji: "senmon kouji gyousha", id_text: "Kontraktor spesialis per jenis pekerjaan", desc: "Kontraktor spesialis yang menerima subkontrak dari ゼネコン. Contoh: 鉄筋工事, 型枠工事, とび工事. Mandor:「うちは配管専門だ、他の工事に口を出すな」(kita spesialis pipa, jangan ikut campur pekerjaan lain).", _origIndex: 569 },
  { id: 579, category: "career", source: "jac-ch1", furi: "しょくちょう", jp: "職長（しょくちょう）", romaji: "shokuchou", id_text: "Mandor / Foreman — pemimpin langsung pekerja", desc: "Pemimpin langsung pekerja; menerima instruksi dari 現場監督 dan meneruskan ke 技能者. CCUS Lv3=シルバー setara 職長. Mandor:「作業中に疑問があれば、まず俺に聞けよ」(ada pertanyaan saat kerja, tanya ke saya dulu).", _origIndex: 570 },
  { id: 580, category: "career", source: "jac-ch1", furi: "ぎのうしゃ", jp: "技能者（ぎのうしゃ）", romaji: "ginousha", id_text: "Pekerja terampil / Skilled worker", desc: "Pekerja yang memiliki keahlian teknis di bidang konstruksi. CCUS Lv1=初級, Lv2=一人前, Lv3=職長級, Lv4=マネジメント. Mandor:「CCUSのレベルを上げたいなら資格を取れよ」(mau naik level CCUS, ambil sertifikat adalah cara terbaik).", _origIndex: 571 },
  { id: 581, category: "career", source: "jac-ch1", furi: "せしゅ", jp: "施主（せしゅ）", romaji: "seshu", id_text: "Pemilik bangunan / klien pada proyek kecil", desc: "Pihak yang memesan bangunan untuk dibangun; istilah khas proyek kecil seperti rumah tinggal. Di proyek besar disebut 発注者. Mandor:「施主さんの要望を最優先に作業してくれよ」(utamakan keinginan pemilik rumah).", _origIndex: 572 },
  { id: 582, category: "career", source: "jac-ch1", furi: "こうむてん", jp: "工務店（こうむてん）", romaji: "koumuten", id_text: "Kontraktor lokal kecil untuk proyek rumah tinggal", desc: "Kontraktor kecil untuk proyek rumah tinggal, bertindak sebagai 元請け dari 施主. Mengelola berbagai 専門工事業者. Mandor:「近隣への挨拶も大事な仕事だ、忘れるな」(menyapa tetangga sekitar juga bagian dari pekerjaan kita).", _origIndex: 573 },
  { id: 583, category: "career", source: "jac-ch1", furi: "もとうけ", jp: "元請け（もとうけ）", romaji: "motouke", id_text: "Kontraktor utama (prime contractor)", desc: "Pihak yang menerima kontrak langsung dari klien lalu memberi subkontrak ke spesialis. Proyek besar=ゼネコン, proyek kecil=工務店. Mandor:「元請けから指示が来たら最優先で動けよ」(instruksi dari kontraktor utama, gerak cepat).", _origIndex: 574 },
  { id: 584, category: "career", source: "jac-ch1", furi: "CCUSひょうかのさんきじゅん", jp: "CCUS評価の3基準", romaji: "CCUS hyouka no 3 kijun", id_text: "3 kriteria CCUS: pengalaman/sertifikat/manajerial", desc: "Tiga kriteria evaluasi CCUS: ①hari kerja tercatat ②lisensi/sertifikat ③kemampuan manajerial. Level 2 butuh ≥645 hari. Mandor:「経験と資格を積んでCCUSレベルを上げろよ」(akumulasikan pengalaman dan sertifikat).", _origIndex: 575 },
  { id: 585, category: "gaiyou", source: "jac-ch1", furi: "しんきにゅうじょうしゃ", jp: "新規入場者（しんきにゅうじょうしゃ）", romaji: "shinki nyuujousha", id_text: "Pekerja baru yang pertama masuk lokasi konstruksi", desc: "Pekerja yang baru pertama kali masuk lokasi konstruksi tertentu. Saat 全体朝礼 wajib sebut nama dan perusahaan dengan suara keras. Mandor:「名前と会社を大声で言えよ」(ucapkan nama dan perusahaan dengan keras di apel).", _origIndex: 576 },
  { id: 586, category: "gaiyou", source: "jac-ch1", furi: "あんぜんしょうわたちあんどこおる", jp: "安全唱和・タッチアンドコール（あんぜんしょうわ）", romaji: "anzen shouwa / tatchi ando kooru", id_text: "Seruan keselamatan bersama + Touch-and-Call", desc: "Seruan keselamatan dan tumpuk tangan bersama di apel per jenis pekerjaan. Semua anggota menunjuk dan berseru untuk bangun kesatuan. Mandor:「全員で指差しして、ゼロ災で行こう、ヨシ！と言えよ」(semua tunjuk dan berseru bersama).", _origIndex: 577 },
  { id: 587, category: "gaiyou", source: "jac-ch1", furi: "ぜろさいでいこうよし", jp: "ゼロ災で行こう、ヨシ！！", romaji: "zero sai de ikou, yoshi!!", id_text: "\"Zero kecelakaan, maju! Oke!!\" — slogan apel K3", desc: "Slogan 安全唱和 yang diucapkan sambil 指さし saat apel per jenis pekerjaan. Diakhiri seruan keras ヨシ!! untuk membangun kesatuan tim. Mandor:「全員で声を合わせて、ゼロ災で行こう、ヨシ！！」(serentak berseru bersama).", _origIndex: 578 },
  { id: 588, category: "gaiyou", source: "jac-ch1", furi: "かつどうすてっぷ", jp: "KY活動の4ステップ", romaji: "KY katsudou 4 suteppu", id_text: "4 langkah KY: bahaya → solusi → target → serukan", desc: "4 langkah KY活動: ①identifikasi bahaya ②diskusi solusi (catat di KYボード) ③tetapkan target ④指差呼称 bersama \"○○○、ヨシ！\". Mandor:「KY活動は4ステップちゃんとやってくれよ」(lakukan KY活動 lengkap 4 langkah).", _origIndex: 579 },
  { id: 589, category: "gaiyou", source: "jac-ch1", furi: "ぼおどきけんよちかつどうひょう", jp: "KYボード（危険予知活動表）", romaji: "KY boodo / kiken yochi katsudou hyou", id_text: "Formulir KY — lembar kegiatan prediksi bahaya", desc: "Formulir yang diisi saat KY活動: kolom titik bahaya dan solusi tim. Semua anggota 指差呼称 ke papan ini sambil berseru \"○○○、ヨシ！\". Mandor:「KYボードはちゃんと記入してから貼り出せよ」(isi KY board dengan benar sebelum dipasang).", _origIndex: 580 },
  { id: 590, category: "gaiyou", source: "jac-ch1", furi: "ぜんたいちょれいのこうもく", jp: "全体朝礼の6項目", romaji: "zentai chorei no 6 koumoku", id_text: "6 agenda apel pagi umum", desc: "Apel umum dengan 6 agenda: sapaan, senam radio, konfirmasi kerja, KY, cek keselamatan berpasangan, lalu \"ご安全に!\". Dipimpin 現場監督. Mandor:「全体朝礼は全員参加が基本だぞ」(apel pagi wajib dihadiri semua).", _origIndex: 581 },
  { id: 591, category: "gaiyou", source: "jac-ch1", furi: "あんぜんかくにんこうもく", jp: "安全確認の8項目", romaji: "anzen kakunin 8 koumoku", id_text: "8 item cek keselamatan berpasangan di akhir apel", desc: "Di akhir 全体朝礼, 2人1組 sambil bersuara: kanan/kiri/depan/belakang/atas/bawah/tali helm/seragam+nama. Mandor:「二人一組で確認し合うのが決まりだぞ」(konfirmasi berpasangan adalah aturannya).", _origIndex: 582 },
  { id: 592, category: "career", source: "jac-ch1", furi: "いったいかん", jp: "一体感（いったいかん）", romaji: "ittaikan", id_text: "Rasa kesatuan tim di lokasi konstruksi", desc: "Rasa kesatuan yang terbentuk dari pekerja berbagai bidang yang bekerja sama. Dibangun melalui sapaan, apel, dan seruan keselamatan. Mandor:「現場はチームワークが大事だ、他の職種にも挨拶しろよ」(sapa juga pekerja bidang lain).", _origIndex: 583 },
  { id: 593, category: "anzen", source: "jac-ch7", furi: "てんとう", jp: "転倒（てんとう）", romaji: "tentou", id_text: "Tersandung / Kehilangan keseimbangan di lantai", desc: "Jenis kecelakaan kerja: benda menghalangi → tersandung, atau kehilangan keseimbangan → jatuh di permukaan yang sama. Berbeda dari 墜落・転落 (jatuh dari ketinggian).", _origIndex: 584 },
  { id: 594, category: "anzen", source: "jac-ch7", furi: "ひらいらっか", jp: "飛来・落下（ひらい・らっか）", romaji: "hirai rakka", id_text: "Benda melayang / jatuh menimpa pekerja dari atas", desc: "Jenis kecelakaan: material terlepas dari crane atau benda jatuh dari ketinggian menimpa pekerja. Penyebab: 玉掛け tidak sempurna, beban crane bergoyang.", _origIndex: 585 },
  { id: 595, category: "anzen", source: "jac-ch7", furi: "げきとつされはさまれまきこまれ", jp: "激突され（げきとつされ）/ はさまれ・巻き込まれ", romaji: "gekitotsu sare / hasamare makikomare", id_text: "Tertabrak alat berat / Terjepit atau terseret", desc: "激突され = tertabrak keras kendaraan berat atau bucket crane saat berputar (旋回中). はさまれ・巻き込まれ = terjepit antara mesin/material, atau terseret ke dalam bagian mesin. Keduanya banyak dalam 建設機械・クレーン災害.", _origIndex: 586 },
  { id: 596, category: "anzen", source: "jac-ch7", furi: "ゆうがいぶつせっしょく / おぼれる / かさい", jp: "有害物接触 / おぼれ / 火災", romaji: "yuugaibutsu sesshoku / oboreru / kasai", id_text: "Kontak bahan berbahaya / Tenggelam / Kebakaran", desc: "有害物との接触: zat kimia menyentuh kulit → gangguan kesehatan. おぼれ: jatuh ke saluran air saat 下水道工事 → tenggelam. 火災: kebakaran di lokasi konstruksi → terjebak asap/api. Ketiganya kecelakaan fatal.", _origIndex: 587 },
  { id: 597, category: "anzen", source: "jac-ch7", furi: "たまがけ", jp: "玉掛け（たまがけ）", romaji: "tamagake", id_text: "Pengikatan beban crane (rigging/slinging)", desc: "Teknik mengikat material ke kait crane dengan wire rope atau sling sebelum diangkat. 玉掛けが不十分 → beban terlepas saat diangkat → 飛来・落下 fatal. Operator wajib punya sertifikat (技能講習 atau 特別教育).", _origIndex: 588 },
  { id: 598, category: "anzen", source: "jac-ch7", furi: "どどめくっさくふかさいじょうでげんそくひつよう", jp: "土留め（どどめ）", romaji: "dodome — kussaku fukasa 1.5m ijou de gensoku hitsuyou", id_text: "Penahan tanah — wajib jika galian kedalaman ≥1.5m", desc: "Saat menggali parit untuk pipa (掘削工事), tanah bisa longsor menimbun pekerja. Jika kedalaman ≥1.5m: wajib gunakan 土留め, umumnya dengan 鋼矢板 (steel sheet pile). Mandor:「1.", _origIndex: 589 },
  { id: 599, category: "anzen", source: "jac-ch7", furi: "こうやいた", jp: "鋼矢板（こうやいた）", romaji: "kou yaita", id_text: "Sheet pile baja — material penahan tanah galian", desc: "土留めの代表材料。Lembaran baja yang dipancang vertikal di sisi galian untuk mencegah longsor tanah (崩壊). Metode utama 土留め pada galian dalam (≥1.5m) seperti pekerjaan pipa bawah tanah (管布設工事).", _origIndex: 590 },
  { id: 600, category: "anzen", source: "jac-ch7", furi: "ほあんせつびゆどういん", jp: "保安設備・誘導員（ほあんせつび・ゆうどういん）", romaji: "hoan setsubi / yudouin", id_text: "Pengaman & pemandu lalu lintas — wajib kerja di", desc: "Saat bekerja di jalan umum (公道上): wajib pasang 囲い, 柵, ガード untuk cegah kendaraan masuk. Wajib tempatkan 誘導員 (traffic guide). Pekerja dilarang bekerja di luar 作業範囲 yang ditentukan.", _origIndex: 591 },
  { id: 601, category: "anzen", source: "jac-ch7", furi: "きいろっくほうしきろおぷ", jp: "キーロック方式ロープ（移動用ロープの安全機構）", romaji: "kii rokku houshiki roopu", id_text: "Key-lock rope — tali lama tak bisa dilepas", desc: "Sistem keselamatan フルハーネス: melepas tali paling sering terjadi saat pindah titik. キーロック方式 = tali lama TIDAK BISA dilepas sebelum tali baru terpasang di titik berikutnya → mencegah jeda tanpa pengaman.", _origIndex: 592 },
  { id: 602, category: "anzen", source: "jac-ch7", furi: "あんぜんせこうさいくるのすてっぷ", jp: "安全施工サイクルの8ステップ", romaji: "anzen sekou saikuru no 8 suteppu", id_text: "8 langkah siklus keselamatan harian konstruksi", desc: "①Apel pagi ②Safety meeting (KY, orientasi baru) ③Cek mesin & alat sebelum mulai ④Pengawasan saat bekerja ⑤Ronda keselamatan ⑥Koordinasi jadwal besok ⑦Bersih-bersih ⑧Cek kebakaran & bahaya saat tutup.", _origIndex: 593 },
  { id: 603, category: "anzen", source: "jac-ch7", furi: "しんにゅうしゃあんぜんえいせいきょういくのはちこうもく", jp: "新入者安全衛生教育の8項目", romaji: "shinnyuusha anzen eisei kyouiku 8 koumoku", id_text: "8 materi K3 wajib untuk rekrutan baru perusahaan", desc: "①Bahaya mesin & bahan ②APD & alat keselamatan ③Prosedur kerja ④Cek awal sebelum bekerja ⑤Penyakit akibat kerja ⑥Kebersihan & kerapian ⑦Tindakan darurat & evakuasi ⑧Materi K3 lainnya.", _origIndex: 594 },
  { id: 604, category: "anzen", source: "jac-ch7", furi: "しんきにゅうじょうしゃきょういくしぼうのはんぶんがにゅうじょうしゅうかんいないじっしぷん", jp: "新規入場者教育", romaji: "shinki nyuujousha kyouiku: shibou no hanbun ga nyuujou 1 shuukan inai / jisshi 30 pun", id_text: "Orientasi pekerja baru lokasi: 50% meninggal", desc: "死亡の半数が入場1週間以内。Kematian di lokasi konstruksi: separuhnya terjadi dalam 1 minggu pertama → maka 新規入場者教育 diwajibkan. Dilaksanakan oleh 職長 hari pertama masuk, durasi ±30 menit.", _origIndex: 595 },
  { id: 605, category: "anzen", source: "jac-ch7", furi: "ふるはあねすぎむたかさ", jp: "フルハーネス義務高さ", romaji: "furu haanesugata gimu takasa", id_text: "Wajib full harness: >6.75m umum / >5m konstruksi", desc: "2022年1月施行: ketinggian >6.75m → semua sektor wajib full harness. Konstruksi lebih ketat: >5m sudah wajib karena risiko tinggi. Di proyek: pakai meskipun merasa tidak perlu.", _origIndex: 596 },
  { id: 606, category: "anzen", source: "jac-ch7", furi: "ほごめがね", jp: "保護メガネ（ほごめがね）", romaji: "hogo megane", id_text: "Kacamata pelindung dari debu, percikan, dan sinar", desc: "Melindungi mata dari: debu logam/kayu (粉じん), percikan api las (火花), panas & asap, sinar laser/UV (有害光線). Di proyek: pilih jenis sesuai bahaya pekerjaan.", _origIndex: 597 },
  { id: 607, category: "anzen", source: "jac-ch7", furi: "ほごますくじんぱい", jp: "保護マスク・じん肺（ほごますく・じんぱい）", romaji: "hogo masuku / jinpai", id_text: "Masker debu — cegah penyakit paru-paru (jinpai)", desc: "じん肺 = kerusakan paru akibat debu logam/batu jangka panjang saat las busur atau potong batu. Masker tersedia: 使い捨て式 dan フィルタ取換え式. Di proyek: wajib dipakai.", _origIndex: 598 },
  { id: 608, category: "anzen", source: "jac-ch7", furi: "てぶくろきんしかいてんするはものしようじ", jp: "手袋（軍手）禁止", romaji: "tebukuro (gunto) kinshi — kaiten suru hamono shiyouji", id_text: "DILARANG sarung tangan saat alat potong berputar", desc: "丸のこ, ボール盤, パイプねじ切機 dan alat berputar lain → sarung tangan (軍手) bisa tersangkut mata pisau → kecelakaan serius. Sarung tangan BOLEH untuk las, kimia, potong manual.", _origIndex: 599 },
  { id: 609, category: "anzen", source: "jac-ch7", furi: "しいるどめんつきへるめっと / あんぜんぐつ", jp: "シールド面付きヘルメット / 安全靴", romaji: "shiirudo mentsuki herumetto / anzen gutsu", id_text: "Helm pelindung wajah (untuk las) / Sepatu safety", desc: "シールド面付きヘルメット = helm dengan pelindung wajah penuh untuk pekerjaan las — melindungi dari percikan api dan UV. 安全靴 = sepatu pelindung keras, perlengkapan dasar wajib semua lokasi.", _origIndex: 600 },
  { id: 610, category: "anzen", source: "jac-ch7", furi: "あつさしすうまなつびもうしょび", jp: "WBGT（暑さ指数）・真夏日・猛暑日", romaji: "WBGT (atsusa shisuu) / manatsubi / moushobi", id_text: "WBGT / Hari panas 30℃+ / Hari terik 35℃+", desc: "WBGT = indeks risiko 熱中症 dari 気象庁. 真夏日 = >30℃, 猛暑日 = >35℃. Di proyek: pasang kipas besar, jaring pelindung, mist, sediakan tempat istirahat ber-AC. Pada 猛暑日 bisa ubah jam kerja.", _origIndex: 601 },
  { id: 611, category: "anzen", source: "jac-ch7", furi: "ねちゅうしょうのしょうじょう", jp: "熱中症の症状（ねっちゅうしょうのしょうじょう）", romaji: "netchuushou no shoujou", id_text: "Gejala heatstroke — dari pusing hingga fatal", desc: "Bertahap: ①pusing/pingsan ②nyeri & kram otot ③keringat berlebih ④sakit kepala, mual, muntah ⑤gangguan kesadaran & kejang ⑥suhu tinggi → meninggal.", _origIndex: 602 },
  { id: 612, category: "anzen", source: "jac-ch7", furi: "みどりじゅうじ / あんぜんえいせいき / きゅうきゅうばこ", jp: "緑十字 / 安全衛生旗 / 救急箱", romaji: "midori juuji / anzen eisei ki / kyuukyuu bako", id_text: "Palang Hijau / Bendera K3 / Kotak P3K", desc: "緑十字 (palang hijau di latar putih) = simbol K3, dipasang di helm dan 救急箱. 安全衛生旗 = gabungan 緑十字 (安全) + 白十字 (衛生), dikibarkan di lokasi. Di proyek: 救急箱 wajib tersedia berisi obat & alat P3K.", _origIndex: 603 },
  { id: 613, category: "anzen", source: "jac-ch7", furi: "ひゅうまんえらあしゅるい", jp: "ヒューマンエラー（12種類の概要）", romaji: "hyuuman eraa 12 shurui", id_text: "Human Error — 12 jenis penyebab kecelakaan manusia", desc: "Kesalahan manusia yang menyebabkan kecelakaan, penurunan kualitas, dan keterlambatan. 12 jenis: ①認知ミス ②不注意 ③意識低下 ④経験不足 ⑤慣れ手抜き ⑥集団欠陥 ⑦近道行動 ⑧連絡不足 ⑨場面本能 ⑩パニック ⑪心身低下 ⑫疲労.", _origIndex: 604 },
  { id: 614, category: "anzen", source: "jac-ch7", furi: "はにんちみすふちゅういちゅういていか", jp: "ヒューマンエラー①〜③：認知ミス・不注意・注意低下", romaji: "HA: ninchi misu / fuchuui / chuui teika", id_text: "HA 1–3: salah tangkap / kurang waspada / otomatis", desc: "①認知ミス = asumsi salah → salah baca instruksi. ②不注意 = terlalu fokus 1 hal → tidak waspada → jatuh ke lubang. ③注意低下 = pekerjaan monoton → bergerak tanpa berpikir (無意識の動作) → lalai tanpa sadar.", _origIndex: 605 },
  { id: 615, category: "anzen", source: "jac-ch7", furi: "はけいけんぶそくなれによるてぬき", jp: "ヒューマンエラー④〜⑤：経験不足・慣れによる手抜き", romaji: "HA: keiken busoku / nare ni yoru tenuki", id_text: "HA 4–5: kurang pengalaman / terbiasa → potong", desc: "④経験・知識不足 = tidak tahu cara benar gunakan alat, tidak bisa prediksi bahaya; KY活動 membantu belajar dari senior. ⑤慣れによる手抜き = makin terbiasa → skip prosedur. Kecelakaan sering saat hati mulai 緩む (lengah).", _origIndex: 606 },
  { id: 616, category: "anzen", source: "jac-ch7", furi: "ひゅうまんえらあろくからはち", jp: "ヒューマンエラー⑥〜⑧", romaji: "HA 6 kara 8", id_text: "HA 6–8: tekanan kelompok / shortcut / salah", desc: "⑥集団欠陥 = deadline menciptakan tekanan ambil jalan tidak aman — keselamatan tetap prioritas. ⑦近道行動 = demi efisiensi → skip langkah prosedur. ⑧連絡不足 = instruksi tidak jelas → pekerja bertindak salah.", _origIndex: 607 },
  { id: 617, category: "anzen", source: "jac-ch7", furi: "ひゅうまんえらあきゅうからじゅうに", jp: "ヒューマンエラー⑨〜⑫", romaji: "HA 9 kara 12", id_text: "HA 9–12: refleks bahaya / panik / fisik menurun /", desc: "⑨場面本能 = refleks selamatkan diri → melempar alat → mengenai orang. ⑩パニック = terkejut → tindakan tidak aman. ⑪心身低下 = penuaan → fisik & penglihatan menurun tanpa disadari. ⑫疲労 = lelah → konsentrasi turun.", _origIndex: 608 },
  { id: 618, category: "hourei", source: "jac-ch2", furi: "ぱわあはらすめんとぼうしほうろうどうしさくそうごうすいしんほう", jp: "パワハラ防止法", romaji: "pawaa harasumento boushi hou (roudou shisaku sougou suishin hou)", id_text: "UU Anti-Harassment: kewajiban buat kebijakan", desc: "UU yang mewajibkan perusahaan buat kebijakan anti-パワハラ dan sediakan loket konsultasi. Berbeda dari sekedar definisi パワハラ. Mandor:「困ったら相談窓口を使えよ、会社が対処する」(kalau ada masalah, gunakan loket konsultasi).", _origIndex: 609 },
  { id: 619, category: "hourei", source: "jac-ch2", furi: "ねんじゆうきゅうきゅうかのふよてえぶる", jp: "年次有給休暇の付与テーブル", romaji: "nenji yuukyuu kyuuka no fuyo teeburu", id_text: "Tabel cuti: syarat 6 bln kerja + hadir ≥80%", desc: "Syarat: kerja ≥6 bulan + hadir ≥80%. Tabel: 0.5th→10hr, 1.5th→11hr ... ≥6.5th→20hr (maks). Diatur 労働基準法. Mandor:「6ヶ月経ったら有給が10日使えるぞ」(setelah 6 bulan, bisa pakai 10 hari cuti berbayar).", _origIndex: 610 },
  { id: 620, category: "hourei", source: "jac-ch2", furi: "あんぜんえいせいきょういくのとりがあやといいれじさぎょうないようへんこうじ", jp: "安全衛生教育の2トリガー", romaji: "anzen eisei kyouiku no 2 torigaa: yatoiire ji / sagyou naiyou henkou ji", id_text: "2 wajib K3: saat rekrut + ganti isi pekerjaan", desc: "Pendidikan K3 wajib dua kali: ①saat rekrut baru ②saat isi pekerjaan berubah. Pekerjaan khusus butuh pelatihan tambahan. Mandor:「作業内容が変わったらK3教育をするぞ」(isi pekerjaan berubah, wajib pendidikan K3 dulu).", _origIndex: 611 },
  { id: 621, category: "hourei", source: "jac-ch2", furi: "ろうどうしゃのせきむろうどうあんぜんえいせいほう", jp: "労働者の責務（ろうどうしゃのせきむ）", romaji: "roudousha no sekimu — roudou anzen eisei hou", id_text: "Kewajiban PEKERJA menurut UU K3", desc: "UU K3 tidak hanya mengatur pengusaha — pekerja juga wajib mematuhi aturan K3. Mengabaikan APD pun bisa dipersalahkan. Mandor:「安全ルールを守るのは労働者の義務でもあるんだ」(mematuhi K3 adalah kewajiban pekerja juga).", _origIndex: 612 },
  { id: 622, category: "anzen", source: "jac-ch2", furi: "あんぜんきあんぜんえいせいき", jp: "安全旗 vs 安全衛生旗", romaji: "anzen ki vs anzen eisei ki", id_text: "Bendera Keselamatan vs Bendera K3 — beda tujuan", desc: "安全旗: simbol 安全週間, dikibarkan hanya selama periode tersebut. 安全衛生旗: simbol K3 terpadu, dikibarkan permanen di lokasi. Mandor:「安全衛生旗は常に掲げておくものだよ」(安全衛生旗 harus selalu berkibar di lokasi kerja).", _origIndex: 613 },
  { id: 623, category: "anzen", source: "jac-ch2", furi: "ろうさいしぼうげにんらんきんぐいれいわねんどけんせつぎょう", jp: "労災死亡原因ランキング5位（令和3年度・建設業）", romaji: "rousai shibou genin rankingu 5i — reiwa 3 nendo kensetsu gyou", id_text: "Top 5 penyebab kematian konstruksi 2021 + angka", desc: "令和3年度 288 kematian konstruksi: ①墜落転落=110件 ②崩壊倒壊=31件 ③はさまれ=27件 ④交通事故=25件 ⑤激突され=19件. Dasar kewajiban フルハーネス. Mandor:「墜落が一番多い、高所は絶対フルハーネスを使えよ」(di ketinggian wajib full harness).", _origIndex: 614 },
  { id: 624, category: "hourei", source: "jac-ch2", furi: "けんせつぎょうほうのいつつのもくてき", jp: "建設業法の5つの目的", romaji: "kensetsu gyou hou no itsutsu no mokuteki", id_text: "5 tujuan UU Industri Konstruksi", desc: "5 tujuan 建設業法: ①kualitas usaha ②kontrak layak ③pelaksanaan tepat ④perlindungan pemesan ⑤pengembangan industri. Mandor:「建設業法は俺たちを守るためにある」(UU Konstruksi ada untuk melindungi kita).", _origIndex: 615 },
  { id: 625, category: "hourei", source: "jac-ch2", furi: "けんちくきじゅんほうたんたいきていしゅうだんきてい", jp: "建築基準法：単体 vs 集団規定", romaji: "kenchiku kijun hou: tantai kitei vs shuudan kitei", id_text: "UU Bangunan: peraturan individu vs kawasan kota", desc: "単体規定: standar bangunan itu sendiri (keselamatan, tahan gempa, dll). 集団規定: standar kawasan perkotaan (KDB, KLB, tinggi). Mandor:「建ぺい率と容積率は図面で確認してくれよ」(KDB dan KLB wajib dicek di gambar).", _origIndex: 616 },
  { id: 626, category: "hourei", source: "jac-ch2", furi: "はいきぶものしょりほうさんぎょうはいきぶものしゅうりょううんぱんきょかもとうけしたうけせきにんぶんたん", jp: "廃棄物処理法：産廃と責任分担", romaji: "haikibumono shori hou: sangyou haikibumono shuuryou unpan kyoka + motouke shitauke sekinin buntan", id_text: "UU Limbah: izin angkut + tanggung jawab kontraktor", desc: "Pengangkutan limbah industri butuh izin resmi. Kontraktor utama wajib buat manifest; sub-kontraktor bertanggung jawab penyimpanan. Mandor:「産廃は許可業者しか運べない、分別して保管して」(simpan sesuai jenis).", _origIndex: 617 },
  { id: 627, category: "hourei", source: "jac-ch2", furi: "げすいどうほうきんしはいすいのりゆうこうじげんばのはいすいしゅるい", jp: "下水道法：禁止排水の6理由 + 工事現場の排水種類", romaji: "gesuidou hou: kinshi haisui no 6 riyuu + kouji genba no haisui shurui", id_text: "UU Saluran Pembuangan: 6 larangan buang", desc: "6 alasan larangan buang ke saluran: merusak pipa, gas beracun, sumbat pipa, bahaya pekerja, ganggu pengolahan, sulit olah lumpur. Air beton wajib dinetralkan. Mandor:「コンクリートの排水は中和処理してから流してくれよ」.", _origIndex: 618 },
  { id: 628, category: "sekou", source: "jac-ch3", furi: "けんせつこうじのさんだいぶんるい", jp: "建設工事の3大分類", romaji: "kensetsu kouji no sandai bunrui", id_text: "3 kategori besar pekerjaan konstruksi", desc: "①土木=alam: dam, jalan, terowongan, jembatan. ②建築=gedung: rumah, RS, sekolah. ③ライフライン・設備=infrastruktur: listrik, gas, air, AC, pemadam. Mandor:「土木か建築か、まず確認して」(konfirmasi jenis pekerjaan).", _origIndex: 619 },
  { id: 643, category: "sekou", source: "jac-ch3", furi: "ようせつのさんだいぶんるいゆうせつあっせつろうせつ", jp: "溶接の3大分類：融接・圧接・ろう接", romaji: "yousetsu no sandai bunrui: yuusetsu assetsu rousetsu", id_text: "3 kategori las: lelehkan / tekan / brazing", desc: "①融接=lelehkan material (arc/gas/laser) — paling umum. ②圧接=panas+tekan tanpa cair sempurna (ガス圧接tulangan). ③ろう接=logam penghubung suhu rendah sebagai lem. Mandor:「融接箇所の検査します」(inspeksi hasil las leleh).", _origIndex: 634 },
  { id: 652, category: "sekou", source: "jac-ch3", furi: "かいたいこうじかいたいがらあすべすとたいさく", jp: "解体工事（解体ガラ・アスベスト対策）", romaji: "kaitai kouji kaitai gara asubesuto taisaku", id_text: "Pekerjaan bongkar: limbah & prosedur asbes", desc: "アスベスト対策。Bongkar bangunan tua, survei asbes wajib dulu. 解体ガラ dipilah (beton, besi, berbahaya) per 建設リサイクル法. Mandor:「石綿飛散防止処置してから始めて」(pasang pelindung asbes sebelum mulai).", _origIndex: 643 },
  { id: 653, category: "career", source: "jac-ch3", furi: "けんせつこうじのしかくさんしゅるい", jp: "建設工事の資格3種類", romaji: "kensetsu kouji no shikaku sanshurui", id_text: "3 tingkat kualifikasi konstruksi berdasarkan UU K3", desc: "①国家免許=lisensi negara tertinggi. ②技能講習修了証=lulus pelatihan terdaftar. ③特別教育=K3 sebelum tugas berbahaya. 作業主任者=pengawas wajib dipilih dari pemegang 技能講習. Mandor:「この作業の主任者はだれですか」(siapa pengawas?).", _origIndex: 644 },
  { id: 654, category: "career", source: "jac-ch3", furi: "くれえんいどうしきくれえんたまかけのしかくきじゅんかじゅうべつ", jp: "クレーン・移動式クレーン・玉掛け資格", romaji: "kureen idoushiki kureen tamakake no shikaku kijun kajuubetsu", id_text: "Kualifikasi crane & rigging berdasarkan kapasitas", desc: "クレーン: ≥5t免許, 1〜5t技能講習, <1t特別教育. 移動式: ≥5t免許. 玉掛け: ≥1t技能講習, <1t特別教育. Batas kunci: 5t (免許) dan 1t (玉掛け). Mandor:「何トンの荷物か確認して資格チェックして」(cek beban dan lisensi).", _origIndex: 645 },
  { id: 655, category: "career", source: "jac-ch3", furi: "しゃりょけいけんせつきかいこうしょさぎょうしゃおおとっくりふとのしかく", jp: "車両系・高所作業車・フォークリフト資格", romaji: "sharyokei kensetsu kikai kousho sagyousha footokku rifuto no shikaku", id_text: "Kualifikasi alat berat: berat / tinggi / angkat", desc: "車両系: ≥3t技能講習, <3t特別教育. 高所作業車: ≥10m技能講習, <10m特別教育. フォーク: ≥1t技能講習, <1t特別教育. Mandor:「機体重量確認してから乗せて」(cek berat mesin sebelum operasikan).", _origIndex: 646 },
  { id: 656, category: "career", source: "jac-ch3", furi: "ようせつさんっけつはっぱあしばのしかくくぶん", jp: "溶接・酸欠・発破・足場の資格区分", romaji: "yousetsu sankketsu happa ashiba no shikaku kubun", id_text: "Kualifikasi las/O₂ rendah/peledakan/scaffolding", desc: "ガス溶接者=技能講習. ガス溶接主任者=免許. アーク溶接者=特別教育. 酸欠主任者=技能講習. 発破技士=免許(tertinggi). 足場主任者(≥5m)=技能講習. 石綿作業者=特別教育. Mandor:「作業前に資格証確認してから始めて」(cek sertifikat sebelum mulai).", _origIndex: 647 },
  { id: 661, category: "gaiyou", source: "jac-ch4", furi: "おはようございます", jp: "おはようございます（朝のあいさつの基本）", romaji: "ohayou gozaimasu", id_text: "Selamat pagi — salam dasar di pagi hari", desc: "Ucapkan kepada orang yang PERTAMA KALI ditemui di pagi hari. Fungsi ganda: ①memberi kesan baik kepada lawan bicara ②membuat lawan bicara bersemangat. Tidak perlu kenal — tetap ucapkan dengan semangat.", _origIndex: 652 },
  { id: 662, category: "gaiyou", source: "jac-ch4", furi: "ごあんぜんに", jp: "ご安全に（建設現場専用のあいさつ）", romaji: "go anzen ni", id_text: "Semoga selamat — salam khas lokasi konstruksi", desc: "Ungkapan harapan agar selamat dan tidak kecelakaan. Digunakan saat akhir 朝礼 dan saat berpapasan dengan pekerja tugas berbahaya. Mandor:「では、今日もご安全に！」(semoga hari ini selamat semua!).", _origIndex: 653 },
  { id: 663, category: "gaiyou", source: "jac-ch4", furi: "おつかれさまです", jp: "おつかれさまです（感謝・労い", romaji: "otsukaresama desu", id_text: "Kerja keras ya — ungkapan penghargaan kerja keras", desc: "Ungkapan terima kasih dan penghargaan atas kerja keras. Bisa dipakai di mana saja. Yang sudah selesai: おつかれさまでした!. Mandor:「今日は大変だったね、おつかれさまでした！」.", _origIndex: 654 },
  { id: 664, category: "gaiyou", source: "jac-ch4", furi: "ごくろさまおつかれさまちがい", jp: "ご苦労さま vs おつかれさまです", romaji: "gokurosama vs otsukaresama — chigai", id_text: "Gokurosama ke atasan tidak sopan — pakai otsukare", desc: "ご苦労さま=kurang sopan untuk atasan. おつかれさまです=lebih sopan, bisa ke siapa saja. Jika atasan bilang ご苦労さま, jawab ありがとうございます！. Mandor:「上司にはおつかれさまですって言ってくれよ」.", _origIndex: 655 },
  { id: 665, category: "gaiyou", source: "jac-ch4", furi: "しつれいしますみっつのばめん", jp: "失礼します（3つの場面での使い方）", romaji: "shitsurei shimasu — mittsu no bamen", id_text: "Permisi / maaf mengganggu — 3 situasi penggunaan", desc: "3 situasi: ①masuk ruangan ②menyela percakapan untuk hal mendesak ③pulang lebih dulu: お先に失礼します → dijawab お疲れさまでした. Mandor:「部屋に入る前に失礼しますって言ってくれよ」.", _origIndex: 656 },
  { id: 666, category: "gaiyou", source: "jac-ch4", furi: "あぶないよけろ", jp: "危ない！よけろっ！（緊急の呼びかけ）", romaji: "abunai! yokero!", id_text: "Awas! Minggir! — seruan darurat saat bahaya datang", desc: "Saat seseorang tidak menyadari bahaya, orang sekitar berteriak 危ない！. Untuk benda jatuh: 危ない！よけろっ！. Dengar → LANGSUNG bereaksi tanpa pikir panjang. Mandor:「危ない！と言われたら迷わず動けよ！」.", _origIndex: 657 },
  { id: 667, category: "sekou", source: "jac-ch4", furi: "すみだしきじゅんずみとおりしん", jp: "墨出し・基準墨・通り芯", romaji: "sumidashi / kijunzumi / toorishin", id_text: "3 istilah dasar penandaan garis konstruksi", desc: "墨出し=menarik garis referensi konstruksi. 基準墨=garis lurus referensi utama bangunan. 通り芯=garis yang melewati titik tengah komponen. Mandor:「基準墨を正確に引いてから通り芯を出してくれ」.", _origIndex: 658 },
  { id: 668, category: "sekou", source: "jac-ch4", furi: "にげずみろくずみたてずみじずみしあがずみ", jp: "逃げ墨・陸墨・立て墨・地墨・仕上げ墨（5種類の墨）", romaji: "nigezumi / rokuzumi / tatezumi / jizumi / shiagazumi", id_text: "5 jenis garis tinta konstruksi berdasarkan fungsi", desc: "逃げ墨=garis paralel dari referensi jika ada halangan. 陸墨=referensi ketinggian horizontal. 立て墨=garis vertikal. 地墨=garis di lantai. 仕上げ墨=garis dimensi finishing. Mandor:「逃げ墨は何センチか必ずメモして」.", _origIndex: 659 },
  { id: 671, category: "sekou", source: "jac-ch4", furi: "べんま", jp: "BM・GL・FH・FL・SL・CH（高さ基準6語）", romaji: "benchmark / GL / FH / FL / SL / CH", id_text: "6 istilah referensi ketinggian — tanah ke plafon", desc: "BM=titik referensi ketinggian proyek. GL=tinggi tanah. FH=tinggi tanah rencana. FL=tinggi lantai jadi. SL=tinggi permukaan slab. CH=tinggi lantai ke plafon. Mandor:「全部の高さはBMからの+/-で確認してくれ」.", _origIndex: 662 },
  { id: 680, category: "sekou", source: "jac-ch4", furi: "じぎょうきそちょくせつきそべたきそふうちんぐ", jp: "地業・基礎・直接基礎（ベタ基礎・フーチング）", romaji: "jigyou / kiso / chokusetsu kiso (beta kiso / fuuchingu)", id_text: "Pekerjaan tanah dasar & pondasi langsung", desc: "地業=lapisan di bawah slab pondasi (pasir/kerikil/捨てコン/tiang). 基礎=meneruskan beban ke tanah. ベタ基礎=cor seluruh dasar. フーチング=hanya di titik beban. Mandor:「転圧後に捨てコンを打てよ」.", _origIndex: 671 },
  { id: 682, category: "sekou", source: "jac-ch4", furi: "あしばのしゅるいさぎょうゆかかりがこい", jp: "足場の種類・作業床・仮囲い（仮設工事3語）", romaji: "ashiba no shurui / sagyouyuka / karigakoi", id_text: "Jenis perancah, lantai kerja & pagar sementara", desc: "足場=lantai sementara untuk kerja di ketinggian (枠組み/単管/くさび). 作業床=lantai perancah dari 布板. 仮囲い=pembatas sementara lokasi ke jalan/lahan tetangga. Mandor:「作業床の点検を毎日してくれよ」.", _origIndex: 673 },
  { id: 686, category: "sekou", source: "jac-ch4", furi: "うちこみうちかさねひゃくごじゅうぷんひゃくにじゅうぷんおじょいんうちつぎ", jp: "打ち込み・打ち重ね・コールドジョイント・打ち継ぎ", romaji: "uchikomi / uchikasane (hyakugojuupun/hyakunijuupun) / cold joint / uchitsugi", id_text: "Pengecoran berlapis — batas waktu & sambungan", desc: "打ち込み=tuang beton ke bekisting. 打ち重ね=cor di atas beton BELUM keras (<25°C→150mnt, ≥25°C→120mnt). Terlambat→コールドジョイント. 打ち継ぎ=cor di atas SUDAH keras. Mandor:「時間オーバーでコールドジョイントにするなよ」.", _origIndex: 677 },
  { id: 687, category: "sekou", source: "jac-ch4", furi: "しめかためたんぴんぐねりまぜはいごう", jp: "締固め・タンピング・練り混ぜ・配合", romaji: "shimekatame / tanpingu / nerimaze / haigou (konkuriito)", id_text: "4 istilah kualitas pengecoran beton", desc: "締固め=gunakan バイブレータ untuk getar beton, hilangkan rongga. タンピング=pukul permukaan slab agar padat. 練り混ぜ=campur semen dan agregat merata. 配合=perbandingan bahan beton. Mandor:「バイブレーターを入れながら締め固めてくれよ」.", _origIndex: 678 },
  { id: 688, category: "sekou", source: "jac-ch4", furi: "おさまりとりあいあみつけみえがかりみえがくれ", jp: "納まり・取合い・見付け・見え掛かり・見え隠れ", romaji: "osamari / toriaia / mitsuke / miegakari / miegakure", id_text: "5 istilah kondisi finishing & keselarasan komponen", desc: "納まり=keseimbangan penempatan komponen. 取合い=pertemuan 2+ komponen. 見付け=permukaan tampak penuh dari depan. 見え掛かり=tampak dari celah. 見え隠れ=tampak saat digerakkan. Mandor:「取合いの納まりが悪いから図面と照合してくれ」.", _origIndex: 679 },
  { id: 689, category: "sekou", source: "jac-ch4", furi: "とおりつらつらいちそりむくりろくふろく", jp: "通り・面一・反り・起り・陸・不陸", romaji: "toori / tsura / tsuraichi / sori / mukuri / roku / furoku", id_text: "6 istilah kelurusan, kerataan & kelengkungan", desc: "通り=kondisi lurus. 面一=dua permukaan rata sejajar. 反り=melengkung cekung. 起り=melengkung cembung. 陸=horizontal sempurna. 不陸=permukaan bergelombang. Mandor:「不陸があったらサンダーで修正してくれよ」.", _origIndex: 680 },
  { id: 690, category: "sekou", source: "jac-ch4", furi: "めちがいおがむかねころびにげみきる", jp: "目違い・拝む・転び・逃げ・見切る", romaji: "mechigai / ogamu / kane / korobi / nige / mikiru", id_text: "5 istilah cacat konstruksi & penanganan sambungan", desc: "目違い=sambungan tidak rata. 拝む=elemen miring. 転び=kolom miring dari vertikal. 逃げ=toleransi dimensi yang sengaja diambil. 見切る=selesaikan sambungan dengan 見切り材. Mandor:「目違いと転びがないか最終確認してくれよ」.", _origIndex: 681 },
  { id: 691, category: "sekou", source: "jac-ch4", furi: "なじみすてべたふかしてもどりだんどりてなおしだめ", jp: "駄目・手直し・手戻り・段取り・馴染み", romaji: "najimi / sute / beta / fukashi / temodori / dandori / tenaoshi / dame", id_text: "5 istilah kondisi pemasangan & proses kerja", desc: "駄目=bagian terlewat saat hampir selesai. 手直し=koreksi pekerjaan. 手戻り=pengerjaan ulang. 段取り=rencanakan urutan kerja. 馴染み=sambungan menempel sempurna. Mandor:「駄目直しはリストを作って確実に終わらせてくれ」.", _origIndex: 682 },
  { id: 692, category: "sekou", source: "jac-ch4", furi: "ぴっちおうすんぽういっけんいっしゃくいっすんひとつぼ", jp: "ピッチ・追う・寸法・一間・一尺・一寸・一坪", romaji: "picchi / ou / sunpou / ikken / isshaku / issun / hitotsubo", id_text: "7 istilah ukuran termasuk satuan tradisional", desc: "ピッチ=jarak antar elemen berulang. 追う=ukur dari titik referensi. 寸法=dimensi panjang. 1間≈1.8m, 1尺≈30.3cm, 1寸≈3.03cm. 1坪=1間×1間≈3.3m². Mandor:「ピッチ300ミリで追って墨を出してくれよ」.", _origIndex: 683 },
  { id: 705, category: "anzen", source: "jac-ch4", furi: "ごえすかつどうせいりせいとんせいそうせいけつしつけ", jp: "5S活動（整理・整頓・清掃・清潔・しつけ）", romaji: "go-esu katsudou — seiri / seiton / seisou / seiketsu / shitsuke", id_text: "Program 5S — 5 kebiasaan lingkungan kerja aman", desc: "5S: ①整理=pisahkan perlu & tidak. ②整頓=tempatkan ditentukan. ③清掃=bersih setelah kerja. ④清潔=pertahankan bersih. ⑤しつけ=aturan agar ①–④ dilaksanakan disiplin. Mandor:「5Sを毎日全員でやってくれ」.", _origIndex: 696 },
  { id: 706, category: "anzen", source: "jac-ch4", furi: "さぎょういんつめしょのろくるうる", jp: "作業員詰め所の6ルール", romaji: "sagyouin tsumesho no roku ruuru", id_text: "6 aturan ruang istirahat pekerja lokasi konstruksi", desc: "詰め所=ruang ganti & istirahat pekerja. Aturan: merokok di tempat khusus, ポイ捨て禁止, helm di tempat ditentukan, barang di loker, cuci tangan, cek 掲示板. Mandor:「詰め所のルールを全員守ってくれよ」.", _origIndex: 697 },
  { id: 707, category: "anzen", source: "jac-ch4", furi: "ふくそうのよんきんしじこうけんせつげんば", jp: "服装の4禁止事項（建設現場）", romaji: "fukusou no yon kinshi jikou (kensetsu genba)", id_text: "4 larangan pakaian di lokasi konstruksi", desc: "4 larangan: ①半袖・短パン禁止 ②上着前開け禁止 (tersangkut) ③袖まくり禁止 (lengan ke pergelangan) ④ポケット手禁止 (tak bisa menahan saat jatuh). Mandor:「服装を整えて入場してくれよ」.", _origIndex: 698 },
  { id: 708, category: "career", source: "jac-ch4", furi: "ほうれんそうほおこくれんらくそうだん", jp: "ほうれんそう（報告・連絡・相談）", romaji: "hourensou — hookoku / renraku / soudan", id_text: "Hourensou — 3 pilar komunikasi efektif di kerja", desc: "ほうれんそう=報告 (lapor ke atasan), 連絡 (sampaikan info/jadwal), 相談 (konsultasikan masalah). Sampaikan singkat dan jelas. Mandor:「何かあったらすぐほうれんそうしてくれよ」.", _origIndex: 699 },
  { id: 709, category: "anzen", source: "jac-ch4", furi: "あとかたずけさぎょうしゅうりょうごのぎむ", jp: "後片付け（作業終了後の義務・火の確認）", romaji: "atokatazuke — sagyou shuuryougo no gimu", id_text: "Aturan beres-beres wajib setelah selesai bekerja", desc: "Setelah selesai bekerja WAJIB後片付け. Lakukan seolah段取り untuk esok hari. Jika menggunakan api, pastikan benar-benar padam sebelum pulang. Mandor:「帰る前に火の元を確認したか？確かめてくれよ」.", _origIndex: 700 },
  { id: 710, category: "hourei", source: "jac-ch2", furi: "しょくぎょうのうりょくかいはつそくしんほう", jp: "職業能力開発促進法（技能検定）", romaji: "shokugyou nouryoku kaihatsu sokushin hou", id_text: "UU Pengembangan Kemampuan Kerja", desc: "UU yang meningkatkan kemampuan kerja melalui pelatihan dan sertifikasi. Lulus 技能検定 → dapat 合格証書 dan boleh sebut diri 技能士. Mandor:「技能士の資格を取れば手当もつくし、CCUSも上がるぞ」(sertifikat, ada tunjangan dan CCUS naik).", _origIndex: 701 },
  { id: 712, category: "hourei", source: "jac-ch2", furi: "ほうていろうどうじかん", jp: "法定労働時間（週40時間・1日8時間）", romaji: "houtei roudou jikan", id_text: "Jam kerja legal", desc: "Jam kerja legal: max 8 jam/hari & 40 jam/minggu. Lembur butuh 36協定 dan dibayar upah tambahan: biasa +25%, libur +35%, malam +25%. Mandor:「8時間超えたら必ず記録してくれよ」(catat kalau lebih 8 jam).", _origIndex: 703 },
  { id: 717, category: "sekou", source: "jac-ch5", furi: "れべる（すいじゅんそくりょうき）/ れえざあれべる", jp: "レベル（水準測量機）/ レーザーレベル", romaji: "reberu (suijun sokuryouki) / reezaa reberu", id_text: "Alat ukur ketinggian — water level / laser level", desc: "レベル = alat survei ketinggian, dipasang di tripod, diatur manual. Versi otomatis: オートレベル. レーザーレベル = memancarkan laser untuk garis referensi horizontal/vertikal di dinding/plafon.", _origIndex: 708 },
  { id: 718, category: "sekou", source: "jac-ch5", furi: "めじゃあ（まきじゃく）・じょうぎ", jp: "メジャー（巻き尺）・定規", romaji: "mejaa (makijaku) / jougi", id_text: "Meteran gulung / Penggaris (mistar lurus)", desc: "メジャー = pita ukur gulung; tipe baja tipis disebut コンベックス. 定規 = penggaris untuk menarik garis lurus; bahan: aluminium, stainless, atau bambu.", _origIndex: 709 },
  { id: 720, category: "sekou", source: "jac-ch5", furi: "はんどみきさ・かくはんき", jp: "ハンドミキサ・かくはん機", romaji: "hando mikisa / kakuhanki", id_text: "Pengaduk material — hand mixer / mesin pengaduk", desc: "ハンドミキサ = alat pengaduk genggam untuk cat, mortar, atau beton dalam ember. かくはん機 = sebutan umum mesin pengaduk, mencakup mortar mixer, concrete mixer, dan batch mixer.", _origIndex: 711 },
  { id: 721, category: "sekou", source: "jac-ch5", furi: "ぶらし（よごれおとし）・すぽんじ", jp: "ブラシ（汚れ落とし）・スポンジ", romaji: "burashi (yogore otoshi) / suponji", id_text: "Sikat pembersih / Spons — bukan sikat kawat baja", desc: "ブラシ = sikat untuk menggosok kotoran; pada pekerjaan pemasangan batu, membersihkan sisa adukan (ノロ) yang meluap. スポンジ = busa untuk mengelap permukaan batu yang kotor akibat ノロ.", _origIndex: 712 },
  { id: 740, category: "anzen", source: "jac-ch7", furi: "さんだいさいがいついらくてんらくけんせつきかいくれええんほうかいとうかい", jp: "三大災害（さんだいさいがい）", romaji: "sandai saigai — tsuiraku tenraku / kensetsu kikai kureeen / houkai toukai", id_text: "3 Bencana Besar Konstruksi — 40–70% kecelakaan", desc: "①墜落・転落 (terbanyak, saat kerja di ketinggian) ②建設機械・クレーン災害 (激突され, はさまれ) ③崩壊・倒壊災害. Ketiganya menyumbang 4–7割 kematian di konstruksi. Di luar itu: kecelakaan lalu lintas.", _origIndex: 731 },
  { id: 741, category: "anzen", source: "jac-ch7", furi: "がいこくじんろうどうしゃのしぼうさいがいけんせつぎょうがもっともおおい", jp: "外国人労働者の死亡災害", romaji: "gaikokujin roudousha no shibou saigai — kensetsu gyou ga mottomo ooi", id_text: "Kecelakaan fatal TKA — sektor konstruksi terbanyak", desc: "厚生労働省データ（令和2・3年度）: 外国人労働者の死亡災害発生件数は建設業が最も多い（製造業・その他より多い）。事故の型別では墜落・転落が最多、続いて交通事故（道路）。建設業で働く外国人は特にこのリスクに注意が必要。", _origIndex: 732 },
  { id: 742, category: "anzen", source: "jac-ch7", furi: "ほうかいとうかいさいがいのけんせつとくゆうれいかせつでんちゅうせきさいでんちゅう", jp: "崩壊・倒壊災害の建設特有例", romaji: "houkai toukai saigai no kensetsu tokuyuu rei — kasetsu denchuu / sekisai denchuu", id_text: "Tiang sementara roboh / tiang di truk rubuh →", desc: "Contoh 崩壊・倒壊 pada pekerjaan listrik: ①仮設電柱 patah & rubuh ②tiang listrik di atas truk ambruk menimpa pekerja. Pada galian air: tanah longsor menimbun (≥1.5m → wajib 土留め).", _origIndex: 733 },
  { id: 743, category: "anzen", source: "jac-ch7", furi: "きかいせっちこうじのしぼうじこおおがたきかいのてんとうによるしたじき", jp: "機械設置工事の死亡事故", romaji: "kikai secchi kouji no shibou jiko — oogata kikai no tentou ni yoru shitajiki", id_text: "Pasang mesin besar — mesin terbalik, pekerja", desc: "Karakteristik kecelakaan fatal 機械設置工事: mesin besar terbalik (転倒) menimpa pekerja. Saat menangani beban berat, tindakan pencegahan terbalik (転倒防止措置) wajib dilakukan.", _origIndex: 734 },
  { id: 744, category: "anzen", source: "jac-ch7", furi: "じょうげすいどうこうじのしゅるいのじこりすく", jp: "上下水道工事の3種類の事故リスク", romaji: "jougesuidou kouji no 3 shurui no jiko risuku", id_text: "3 risiko saluran air: longsor, tersandung, backhoe", desc: "①Tanah longsor di galian → tertimbun (≥1.5m: wajib 鋼矢板). ②Tersandung kabel atau amblas di tepi galian → jatuh. ③Backhoe berputar menabrak atau mundur → tertabrak (wajib ada 誘導員 khusus).", _origIndex: 735 },
  { id: 745, category: "anzen", source: "jac-ch7", furi: "しんきにゅうじょうしゃきょういくのはちこうもく", jp: "新規入場者教育の8項目", romaji: "shinki nyuujousha kyouiku no 8 koumoku", id_text: "8 materi wajib orientasi pekerja baru di lapangan", desc: "[1]混在作業場所の状況 [2]危険有害箇所と立入禁止区域 [3]混在作業場所での作業相互の連絡・調整 [4]災害発生時の避難の方法 [5]指揮命令系統 [6]担当する作業内容と労働災害防止対策 [7]安全衛生に関する規程 [8]基本方針・目標など。死亡の半数近くが入場1週間以内に発生するため義務化。実施時間: 30分程度。", _origIndex: 736 },
  { id: 746, category: "career", source: "jac-gakka1", furi: "せんもんこうじぎょうしゃかんのちいむわあく", jp: "専門工事業者間のチームワーク", romaji: "senmon kouji gyousha kan no chiimu waaku", id_text: "Kerja tim antar kontraktor spesialis", desc: "Untuk memajukan konstruksi dengan lancar, kerja tim (チームワーク) antar kontraktor spesialis sangat penting. Masing-masing sub-kontraktor bekerja sesuai jadwal dan berkoordinasi ketat.", _origIndex: 737 },
  { id: 775, category: "anzen", source: "vocab-supplementary", furi: "とうけつぼうし", jp: "凍結防止", romaji: "touketsu boushi", id_text: "Pencegahan pembekuan", desc: "Kombinasi 保温材 + 電熱線 untuk mencegah pipa bawah tanah membeku.", _origIndex: 761 },
  { id: 777, category: "anzen", source: "vocab-general", furi: "たはつ", jp: "多発", romaji: "tahatsu", id_text: "Sering terjadi / berulang", desc: "Kejadian yang terjadi berulang-ulang. 結露が多発 = kondensasi sering terjadi.", _origIndex: 763 },
  { id: 781, category: "anzen", source: "vocab-general", furi: "さび", jp: "錆", romaji: "sabi", id_text: "Karat", desc: "Oksidasi pada permukaan logam. Pipa berkarat → wajib 洗浄 & 防錆処理 sebelum konstruksi.", _origIndex: 767 },
  { id: 782, category: "anzen", source: "vocab-general", furi: "れっか", jp: "劣化", romaji: "rekka", id_text: "Degradasi / kemunduran", desc: "Material melemah seiring waktu. Sinar UV menyebabkan 劣化 pada kabel di luar ruangan.", _origIndex: 768 },
  { id: 786, category: "anzen", source: "vocab-general", furi: "いおん", jp: "異音", romaji: "ion", id_text: "Suara abnormal", desc: "Suara tidak normal pada sistem pipa/mesin. Membuka katup terlalu cepat → aliran mendadak → 異音.", _origIndex: 772 },
  { id: 787, category: "anzen", source: "vocab-supplementary", furi: "ひーとろす", jp: "ヒートロス", romaji: "hiitorosu", id_text: "Heat loss (kehilangan panas)", desc: "Panas yang terbuang keluar dari sistem insulasi melalui celah 断熱材.", _origIndex: 773 },
  { id: 789, category: "sekou", source: "vocab-supplementary", furi: "あつりょくしけん", jp: "圧力試験", romaji: "atsuryoku shiken", id_text: "Uji tekanan", desc: "Pengujian pipa dengan memberikan tekanan di atas tekanan kerja untuk mengecek kebocoran.", _origIndex: 775 },
  { id: 790, category: "sekou", source: "vocab-supplementary", furi: "がすもれしけん", jp: "ガス漏れ試験", romaji: "gasu more shiken", id_text: "Uji kebocoran gas", desc: "Wajib dilakukan setiap kali menyambung pipa gas. Menggunakan air sabun atau detektor gas.", _origIndex: 776 },
  { id: 791, category: "sekou", source: "vocab-supplementary", furi: "もれけんさ", jp: "漏れ検査", romaji: "more kensa", id_text: "Inspeksi kebocoran", desc: "Pemeriksaan setelah pengelasan. Wajib dilakukan untuk memastikan sambungan kedap.", _origIndex: 777 },
  { id: 802, category: "anzen", source: "vocab-supplementary", furi: "しようちゅうし", jp: "使用中止", romaji: "shiyou chuushi", id_text: "Menghentikan penggunaan", desc: "Jika kabel 電動工具 panas → segera hentikan penggunaan (使用を中止する).", _origIndex: 788 },
  { id: 803, category: "sekou", source: "vocab-supplementary", furi: "せこうほうほう", jp: "施工方法", romaji: "sekou houhou", id_text: "Metode konstruksi", desc: "Cara/prosedur pelaksanaan pekerjaan konstruksi. Di proyek: ditentukan berdasarkan dokumen desain dan spesifikasi. Mandor:「施工方法を確認してから始めて」(cek metode kerja dulu sebelum mulai).", _origIndex: 789 },
  { id: 807, category: "sekou", source: "vocab-supplementary", furi: "ついかせこう", jp: "追加施工", romaji: "tsuika sekou", id_text: "Pekerjaan tambahan", desc: "Pekerjaan konstruksi yang ditambahkan setelah konstruksi utama. 屋外保温の追加施工.", _origIndex: 792 },
  { id: 811, category: "sekou", source: "vocab-supplementary", furi: "ぼうせいしょり", jp: "防錆処理", romaji: "bousei shori", id_text: "Perawatan anti-karat", desc: "Proses melapisi permukaan logam untuk mencegah karat. Dilakukan setelah pembersihan pipa.", _origIndex: 796 },
  { id: 812, category: "sekou", source: "vocab-general", furi: "へいよう", jp: "併用", romaji: "heiyou", id_text: "Penggunaan bersamaan", desc: "Menggunakan dua hal sekaligus. 保温材と電熱線を併用する = pakai insulasi + kawat pemanas bersamaan.", _origIndex: 797 },
  { id: 825, category: "career", source: "vocab-general", furi: "きゅうへん", jp: "急変", romaji: "kyuuhen", id_text: "Perubahan mendadak", desc: "バルブを開いた直後に流量が急変する → 異音発生の原因. Di proyek: buka katup perlahan agar aliran tidak tiba-tiba berubah. Mandor:「バルブはゆっくり開いて」(buka katup perlahan-lahan).", _origIndex: 809 },
  { id: 826, category: "career", source: "vocab-general", furi: "ちょくご", jp: "直後", romaji: "chokugo", id_text: "Segera setelah", desc: "バルブを開いた直後 = segera setelah katup dibuka. 直後 = langsung setelah.", _origIndex: 810 },
  { id: 830, category: "career", source: "vocab-supplementary", furi: "しーるせい", jp: "シール性", romaji: "shiiru sei", id_text: "Kemampuan penyegelan (sealing)", desc: "Kemampuan sambungan untuk tidak bocor. 油が付着すると→シール性が低下する. Di proyek: bersihkan bagian sambungan sebelum memasang. Mandor:「油を拭いてからシールして」(bersihkan minyak sebelum menyegel).", _origIndex: 814 },
  { id: 835, category: "career", source: "vocab-general", furi: "げんしょう", jp: "現象", romaji: "genshou", id_text: "Fenomena / gejala", desc: "Kejadian atau gejala fisik. 断熱材の隙間から熱が漏れる現象 = fenomena panas bocor dari celah insulasi.", _origIndex: 819 },
  { id: 837, category: "sekou", source: "vocab-supplementary", furi: "あつりょくけい", jp: "圧力計", romaji: "atsuryoku kei", id_text: "Manometer / alat ukur tekanan", desc: "Alat untuk mengukur tekanan fluida dalam pipa. Berbeda dari 圧力試験 (uji tekanan). 破損 = rusak.", _origIndex: 821 },
  { id: 841, category: "anzen", source: "vocab-supplementary", furi: "ぶりっじ", jp: "ブリッジ", romaji: "burijji", id_text: "Bridge (jembatan termal)", desc: "Istilah pengecoh di soal Q10. Fenomena bocornya panas melalui material yang menghubungkan sisi panas & dingin. Jawaban benar Q10 adalah ヒートロス.", _origIndex: 825 },
  { id: 842, category: "anzen", source: "vocab-supplementary", furi: "さーまるぎゃっぷ", jp: "サーマルギャップ", romaji: "saamaru gyappu", id_text: "Thermal gap (celah termal)", desc: "Istilah pengecoh di soal Q10. Bukan istilah standar konstruksi Jepang. Jawaban benar Q10 adalah ヒートロス bukan サーマルギャップ.", _origIndex: 826 },
  { id: 853, category: "sekou", source: "vocab-supplementary", furi: "ぺんきぬり", jp: "ペンキ塗り", romaji: "penki nuri", id_text: "Pengecatan dengan cat biasa", desc: "Pengecoh di Q11. Jika pipa berkarat, solusinya bukan hanya cat biasa (ペンキ塗り) — harus 洗浄＋防錆処理 (cuci + anti-karat) sebelum konstruksi.", _origIndex: 837 },
  { id: 854, category: "career", source: "vocab-general", furi: "いろ", jp: "色", romaji: "iro", id_text: "Warna", desc: "Pengecoh paling sering di soal — muncul 6x: バルブの色(Q4)、材料の色(Q6)、色を塗る(Q15)、色検査(Q16)、色をそろえる(Q18)、色が変わる(Q20). Warna tidak pernah jadi jawaban benar.", _origIndex: 838 },
  { id: 855, category: "anzen", source: "vocab-supplementary", furi: "ふえる", jp: "増える", romaji: "fueru", id_text: "Bertambah / meningkat", desc: "Pengecoh yang muncul 4x: 流量が増える(Q2,Q17)、重量が増える(Q14,Q20). Selalu jadi pengecoh — bukan jawaban benar di soal manapun.", _origIndex: 839 },
  { id: 860, category: "anzen", source: "vocab-supplementary", furi: "あがる", jp: "上がる", romaji: "agaru", id_text: "Naik / meningkat", desc: "流量が上がる = debit aliran naik. Pengecoh Q14 — minyak pada sambungan 冷媒管 tidak menyebabkan debit naik, melainkan シール性が低下する.", _origIndex: 844 },
  { id: 861, category: "career", source: "vocab-general", furi: "おと", jp: "音", romaji: "oto", id_text: "Suara / bunyi", desc: "音検査 = inspeksi suara. Pengecoh Q16 — inspeksi wajib setelah pengelasan bukan 音検査 melainkan 漏れ検査 (inspeksi kebocoran).", _origIndex: 845 },
  { id: 862, category: "anzen", source: "vocab-supplementary", furi: "へる", jp: "減る", romaji: "heru", id_text: "Berkurang / menurun", desc: "騒音が減る = kebisingan berkurang. Pengecoh Q17 — jarak saddle terlalu lebar tidak mengurangi kebisingan, melainkan menyebabkan たわみ (lendutan).", _origIndex: 846 },
  { id: 864, category: "anzen", source: "vocab-supplementary", furi: "かわる", jp: "変わる", romaji: "kawaru", id_text: "Berubah", desc: "色が変わる = warna berubah. Pengecoh Q20 — kemiringan pipa kurang (勾配不足) tidak menyebabkan warna berubah, melainkan 流れが悪くなる (aliran memburuk).", _origIndex: 848 },
  { id: 866, category: "career", source: "vocab-general", furi: "はだか", jp: "裸", romaji: "hadaka", id_text: "Tanpa pelindung / telanjang", desc: "裸のまま埋める = kubur pipa tanpa pelindung apapun. Pengecoh Q1 — cara terburuk untuk pipa bawah tanah di cuaca dingin. Wajib pakai 保温材＋電熱線.", _origIndex: 850 },
  { id: 868, category: "career", source: "vocab-general", furi: "こくしょく", jp: "黒色", romaji: "kokushoku", id_text: "Warna hitam", desc: "黒色テープで覆う = tutup dengan selotip hitam. Pengecoh Q7 — selotip hitam bukan pelindung UV yang tepat. Yang benar: 耐候性カバーを使用する.", _origIndex: 852 },
  { id: 869, category: "career", source: "vocab-general", furi: "けいさん", jp: "計算", romaji: "keisan", id_text: "Perhitungan / kalkulasi", desc: "流量計算 = menghitung debit aliran. Pengecoh Q8 — sebelum mengoperasikan pipa gas bukan saatnya hitung debit, yang wajib adalah ガス漏れ試験 dulu.", _origIndex: 853 },
  { id: 872, category: "career", source: "vocab-general", furi: "しょうらい", jp: "将来", romaji: "shourai", id_text: "Masa depan / kelak", desc: "将来確認するために = agar bisa diketahui di masa depan. Konteks Q15: posisi pipa bawah tanah dicatat di 図面 agar bisa dilacak kelak.", _origIndex: 856 },
  { id: 874, category: "sekou", source: "vocab-supplementary", furi: "そろえる", jp: "そろえる", romaji: "soroeru", id_text: "Menyamakan / menyelaraskan", desc: "色をそろえる = samakan warna (Q18 pengecoh). 長さをそろえる = samakan panjang (Q18 pengecoh). Kedua-duanya bukan hal yang diutamakan saat banyak kabel masuk konduit.", _origIndex: 858 },
  { id: 875, category: "career", source: "vocab-general", furi: "さい", jp: "際", romaji: "sai", id_text: "Pada saat / ketika", desc: "〜する際（さい）= pada saat melakukan〜. 配管を埋設する際 = pada saat pemasangan pipa. Mirip 時（とき）tapi lebih formal. Sering muncul di teks soal.", _origIndex: 859 },
  { id: 880, category: "career", source: "vocab-supplementary", furi: "みじかい", jp: "短い", romaji: "mijikai", id_text: "Pendek", desc: "電線を短く切る = potong kabel lebih pendek. Pengecoh Q7 — memotong kabel tidak ada hubungannya dengan pencegahan degradasi UV. Yang benar: 耐候性カバー.", _origIndex: 864 },
  { id: 884, category: "sekou", source: "vocab-supplementary", furi: "せこうじ", jp: "施工時", romaji: "sekou ji", id_text: "Saat konstruksi / waktu pengerjaan", desc: "施工時（せこうじ）に行うこと = yang dilakukan saat konstruksi. Konteks Q15: posisi pipa bawah tanah dicatat di 図面 saat施工時.", _origIndex: 868 },
  { id: 885, category: "sekou", source: "vocab-supplementary", furi: "さぎょうご", jp: "作業後", romaji: "sagyou go", id_text: "Setelah pekerjaan", desc: "溶接作業後（さぎょうご）= setelah pekerjaan pengelasan. Konteks Q16: 溶接作業後に必ず行うべき検査 = inspeksi wajib setelah las → 漏れ検査.", _origIndex: 869 },
  { id: 935, category: "sekou", source: "vocab-general", furi: "しゅんこう", jp: "竣工", romaji: "shunkou", id_text: "Selesai konstruksi / serah terima", desc: "例: 竣工検査に合格したら引き渡し。→ Setelah lulus inspeksi akhir, bangunan diserahkan ke pemilik.", _origIndex: 919 },
  { id: 936, category: "sekou", source: "vocab-general", furi: "ちゃっこう", jp: "着工", romaji: "chakkou", id_text: "Mulai konstruksi / groundbreaking", desc: "例: 着工から竣工まで18ヶ月かかった。→ Dari mulai konstruksi sampai selesai butuh 18 bulan.", _origIndex: 920 },
  { id: 952, category: "sekou", source: "vocab-general", furi: "つぼ", jp: "坪", romaji: "tsubo", id_text: "Tsubo — satuan luas (≈3.3 m²)", desc: "例: 1坪＝約3.3m²。→ Satuan luas tradisional Jepang, masih dipakai di properti.", _origIndex: 936 },
  { id: 953, category: "sekou", source: "vocab-general", furi: "しゃく", jp: "尺", romaji: "shaku", id_text: "Shaku — satuan panjang (≈30.3 cm)", desc: "Satuan panjang tradisional Jepang. 1尺 ≈ 30.3 cm. 10寸＝1尺, 10尺＝1丈. Di proyek: sering muncul di gambar tua. Mandor:「1尺は約30センチと覚えて」(ingat 1 shaku ≈ 30 cm).", _origIndex: 937 },
  { id: 954, category: "sekou", source: "vocab-general", furi: "すん", jp: "寸", romaji: "sun", id_text: "Sun — satuan panjang (≈3.03 cm)", desc: "例: 1寸＝約3.03cm＝1尺の1/10。→ Sering muncul di gambar teknik bangunan tradisional Jepang.", _origIndex: 938 },
  { id: 974, category: "gaiyou", source: "vocab-supplementary", furi: "おつかれさまです", jp: "お疲れ様です", romaji: "otsukaresama desu", id_text: "Terima kasih sudah bekerja keras", desc: "例: 現場でも事務所でもすれ違ったときに使える。→ Bisa dipakai di mana saja — di lapangan, kantor, atau lorong.", _origIndex: 958 },
  { id: 981, category: "sekou", source: "vocab-general", furi: "はしら", jp: "柱", romaji: "hashira", id_text: "Kolom / pilar", desc: "Kolom vertikal menopang beban bangunan. 柱は建物の垂直荷重を支える. Di proyek: kolom baja dipasang tegak lurus, dicek dengan plumb bob. Mandor:「柱が垂直か確認して」(cek apakah kolom tegak lurus).", _origIndex: 965 },
  { id: 982, category: "sekou", source: "vocab-general", furi: "はり", jp: "梁", romaji: "hari", id_text: "Balok struktural", desc: "例: 梁は柱と柱をつなぐ水平部材。→ Balok = elemen horizontal yang menghubungkan kolom ke kolom.", _origIndex: 966 },
  { id: 983, category: "sekou", source: "vocab-general", furi: "ゆか", jp: "床", romaji: "yuka", id_text: "Lantai", desc: "例: 地墨は床など水平面に直接つける墨。→ Garis lantai (jizumi) ditarik langsung di permukaan horizontal.", _origIndex: 967 },
  { id: 1006, category: "sekou", source: "vocab-supplementary", furi: "すいへいき", jp: "水平器", romaji: "suihei ki", id_text: "Waterpass / spirit level", desc: "Alat pengukur kerataan/kelurusan horizontal. Digunakan saat memasang pipa dan peralatan.", _origIndex: 985 },
  { id: 1011, category: "sekou", source: "vocab-general", furi: "はしご", jp: "梯子", romaji: "hashigo", id_text: "Tangga (ladder)", desc: "Tangga panjang yang disandarkan ke dinding. Untuk akses ke tempat tinggi.", _origIndex: 990 },
  { id: 1088, category: "sekou", source: "vocab-supplementary", furi: "モップ", jp: "モップ", romaji: "moppu", id_text: "Mop / alat pel", desc: "Alat pembersih lantai, digunakan untuk membersihkan lokasi kerja.", _origIndex: 1067 },
  { id: 1089, category: "sekou", source: "vocab-supplementary", furi: "たらい", jp: "たらい", romaji: "tarai", id_text: "Baskom (basin)", desc: "Wadah besar untuk mencuci atau menampung air di lokasi konstruksi. Di proyek: digunakan untuk cuci tangan dan peralatan. Mandor:「たらいを使って道具を洗って」(gunakan baskom untuk cuci peralatan).", _origIndex: 1068 },
  { id: 1090, category: "sekou", source: "vocab-supplementary", furi: "はしごきゃたつ", jp: "梯子脚立", romaji: "hashigo kyatatsu", id_text: "Tangga lipat (folding ladder)", desc: "Tangga yang bisa dilipat, digunakan untuk pekerjaan di ketinggian rendah.", _origIndex: 1069 },
  { id: 1091, category: "sekou", source: "vocab-supplementary", furi: "ゴムパッド", jp: "ゴムパッド", romaji: "gomu paddo", id_text: "Bantalan karet (rubber pad)", desc: "Bantalan karet untuk peredam atau alas anti-selip pada peralatan.", _origIndex: 1070 },
  { id: 1092, category: "sekou", source: "vocab-supplementary", furi: "シートガスケット", jp: "シートガスケット", romaji: "shiito gasuketto", id_text: "Gasket lembaran (sheet gasket)", desc: "Gasket berbentuk lembaran untuk mencegah kebocoran pada sambungan flensa.", _origIndex: 1071 },
  { id: 1093, category: "sekou", source: "vocab-supplementary", furi: "かんしょうざい", jp: "緩衝材", romaji: "kanshouzai", id_text: "Material peredam benturan (cushioning material)", desc: "Bahan untuk melindungi peralatan atau pipa dari benturan fisik.", _origIndex: 1072 },
  { id: 1094, category: "sekou", source: "vocab-supplementary", furi: "だんさだい", jp: "段差台", romaji: "dansadai", id_text: "Platform bertingkat (step platform)", desc: "Platform kecil bertingkat sebagai pijakan untuk pekerjaan di ketinggian rendah.", _origIndex: 1073 },
  { id: 1222, category: "anzen", source: "vocab-supplementary", furi: "わくぐみあしば", jp: "枠組足場", romaji: "wakugumi ashiba", id_text: "Scaffolding rangka (perancah pabrikasi)", desc: "例: 枠組足場は、建設工事で最も一般的に使われる仮設足場の一種です。→ Scaffolding rangka adalah jenis perancah sementara yang paling umum di proyek konstruksi. Terbuat dari panel baja pabrikasi yang dipasang vertikal dan horizontal.", _origIndex: 1200 },
  { id: 1227, category: "anzen", source: "vocab-supplementary", furi: "なかさん", jp: "中さん", romaji: "nakasan", id_text: "Mid-rail / rel tengah scaffolding", desc: "例: 手すりと幅木の間に中さんを取り付けて、作業員の転落を防ぎます。→ Mid-rail dipasang di antara guardrail atas dan toe board untuk mencegah pekerja tergelincir jatuh. Posisi sekitar 35–50 cm dari platform.", _origIndex: 1205 },
  { id: 1228, category: "anzen", source: "vocab-general", furi: "はばき", jp: "巾木", romaji: "habaki", id_text: "Toe board / papan pengaman bawah", desc: "例: 巾木を足場の端に設置することで、工具や資材の落下を防げます。→ Toe board dipasang di bagian bawah tepi scaffolding untuk mencegah alat dan material jatuh ke bawah. Tinggi minimal 10 cm.", _origIndex: 1206 },
  { id: 1229, category: "anzen", source: "vocab-supplementary", furi: "しょうこうせつび", jp: "昇降設備", romaji: "shouko setsubi", id_text: "Fasilitas naik-turun (tangga/stairway)", desc: "例: 足場には、作業員が安全に昇降できる昇降設備を設けることが義務です。→ Scaffolding wajib dilengkapi fasilitas naik-turun agar pekerja dapat mengakses ketinggian dengan aman. Termasuk tangga tetap dan tangga portable.", _origIndex: 1207 },
  { id: 1230, category: "anzen", source: "vocab-supplementary", furi: "さんそのうどけい", jp: "酸素濃度計", romaji: "sanso noudokei", id_text: "Alat ukur kadar oksigen", desc: "例: 密閉空間に入る前に、酸素濃度計で酸素濃度が18%以上あることを確認します。→ Sebelum memasuki ruang tertutup, konfirmasi kadar oksigen minimal 18% dengan oksimeter. Kadar di bawah 18% = bahaya kekurangan oksigen.", _origIndex: 1208 },
  { id: 1232, category: "anzen", source: "vocab-supplementary", furi: "ゆうがいがすけんちき", jp: "有害ガス検知器", romaji: "yuugai gasu kenchiki", id_text: "Detektor gas berbahaya", desc: "例: 密閉空間作業前に有害ガス検知器を使って、一酸化炭素や硫化水素の濃度を測ります。→ Sebelum kerja di ruang tertutup, ukur konsentrasi CO dan H₂S menggunakan detektor gas berbahaya. Wajib dilakukan sebelum pekerja masuk.", _origIndex: 1210 },
  { id: 1234, category: "anzen", source: "vocab-supplementary", furi: "ろっくあうとたぐあうと", jp: "ロックアウト・タグアウト", romaji: "rokkuauto taguauto", id_text: "Lockout-Tagout (LOTO) — prosedur pengamanan energi", desc: "例: 設備のメンテナンス中は、ロックアウト・タグアウトを実施して誤作動を防ぎます。→ Saat perawatan alat, terapkan prosedur LOTO untuk mencegah mesin menyala tidak sengaja. Energi dikunci (lock) dan diberi tanda peringatan (tag).", _origIndex: 1212 },
  { id: 1236, category: "anzen", source: "vocab-supplementary", furi: "つーるぼっくすみーてぃんぐ", jp: "ツールボックスミーティング", romaji: "tsuuru bokkusu miitingu", id_text: "Toolbox meeting (TBM) / rapat singkat keselamatan", desc: "例: 毎朝の作業開始前にツールボックスミーティングで当日の危険ポイントを確認します。→ Setiap pagi sebelum kerja dimulai, bahaya hari itu dikonfirmasi bersama dalam toolbox meeting. Biasanya berlangsung 5–15 menit di lokasi kerja.", _origIndex: 1214 },
  { id: 1237, category: "anzen", source: "vocab-supplementary", furi: "あんぜんとうばん", jp: "安全当番", romaji: "anzen touban", id_text: "Petugas keselamatan harian (giliran)", desc: "例: 安全当番は、当日の現場の安全状態を巡回して確認し、記録する役割を担います。→ Petugas keselamatan harian bertugas berkeliling mengecek dan mencatat kondisi keamanan lapangan. Dilakukan secara bergilir oleh anggota tim.", _origIndex: 1215 },
  { id: 1239, category: "anzen", source: "vocab-supplementary", furi: "さぎょうてじゅんしょ", jp: "作業手順書", romaji: "sagyou tejunsho", id_text: "Manual prosedur kerja (SOP)", desc: "例: 作業手順書には、作業の流れ・使用機材・注意事項・緊急時の対応が記載されています。→ Manual prosedur kerja memuat alur pekerjaan, peralatan yang digunakan, peringatan keselamatan, dan langkah darurat.", _origIndex: 1217 },
  { id: 1245, category: "anzen", source: "vocab-supplementary", furi: "ひやりはっと", jp: "ヒヤリハット", romaji: "hiyari hatto", id_text: "Near miss / hampir celaka", desc: "例: ヒヤリハット報告書を提出・共有することで、重大事故の予防につながります。→ Melaporkan dan berbagi near miss membantu mencegah kecelakaan serius.", _origIndex: 1223 },
  { id: 1246, category: "anzen", source: "vocab-supplementary", furi: "きけんよちくんれん", jp: "KYT（危険予知訓練）", romaji: "kiken yochi kunren", id_text: "Pelatihan prediksi bahaya (KYT)", desc: "例: KYTでは、作業前にチーム全員で現場の危険箇所を指摘し合い、対策を決めます。→ Dalam KYT, seluruh tim saling menunjukkan titik berbahaya di lokasi sebelum kerja dimulai dan menetapkan tindakan pencegahan.", _origIndex: 1224 },
  { id: 1248, category: "sekou", source: "vocab-supplementary", furi: "ピーシーぐい", jp: "PC杭", romaji: "pii shii kui", id_text: "Tiang pancang beton prategang", desc: "例: PC杭はプレストレストコンクリート製の既製杭である。→ PC杭 adalah tiang pracetak dari beton prategang (prestressed concrete). Digunakan sebagai pondasi dalam di tanah berbatu.", _origIndex: 1226 },
  { id: 1249, category: "sekou", source: "vocab-supplementary", furi: "ピーエイチシーぐい", jp: "PHC杭", romaji: "pii eichi shii kui", id_text: "Tiang beton prategang tegangan tinggi", desc: "例: PHC杭はPC杭より強度が高く、大型建築物の基礎に使われる。→ PHC杭 memiliki kekuatan lebih tinggi dari PC杭, dipakai untuk pondasi bangunan besar. PHC = Pretensioned spun High strength Concrete.", _origIndex: 1227 },
  { id: 1255, category: "sekou", source: "vocab-supplementary", furi: "しつじゅんようじょう", jp: "湿潤養生", romaji: "shitsujun youjou", id_text: "Perawatan beton dengan pembasahan", desc: "例: 打設後のコンクリートは湿潤養生を行い、乾燥によるクラックを防ぐ。→ Setelah pengecoran, beton dirawat dengan menjaga kelembaban (湿潤養生) untuk mencegah retak akibat pengeringan terlalu cepat.", _origIndex: 1233 },
  { id: 1256, category: "sekou", source: "vocab-supplementary", furi: "じょうきようじょう", jp: "蒸気養生", romaji: "jouki youjou", id_text: "Perawatan beton dengan uap panas", desc: "例: プレキャスト製品は蒸気養生で短期間に強度を出す。→ Produk precast (pracetak) menggunakan steam curing (蒸気養生) untuk mencapai kekuatan awal dalam waktu singkat. Suhu dijaga sekitar 60–80°C.", _origIndex: 1234 },
  { id: 1257, category: "sekou", source: "vocab-supplementary", furi: "ひまくようじょう", jp: "被膜養生", romaji: "himaku youjou", id_text: "Perawatan beton dengan lapisan membran", desc: "例: 被膜養生剤を散布して、コンクリート表面から水分が蒸発するのを防ぐ。→ Agen membran disemprotkan ke permukaan beton untuk mencegah penguapan air. Metode ini tidak memerlukan penyiraman berkala.", _origIndex: 1235 },
  { id: 1259, category: "sekou", source: "vocab-supplementary", furi: "うちつぎめ", jp: "打ち継ぎ目", romaji: "uchitsugi me", id_text: "Sambungan pengecoran beton", desc: "例: 打ち継ぎ目は構造的弱点になりやすいため、位置を適切に設けること。→ Construction joint (打ち継ぎ目) adalah batas antara pengecoran lama dan baru, yang rawan menjadi titik lemah struktural jika tidak dikerjakan dengan benar.", _origIndex: 1237 },
  { id: 1263, category: "sekou", source: "vocab-supplementary", furi: "ぶりーでぃんぐ", jp: "ブリーディング", romaji: "buriidingu", id_text: "Bleeding (naiknya air ke permukaan beton)", desc: "例: ブリーディングが過剰だと表面強度が低下し、クラックの原因となる。→ Bleeding adalah fenomena air naik ke permukaan beton segar akibat gravitasi. Jika berlebihan, permukaan beton menjadi lemah dan mudah retak.", _origIndex: 1241 },
  { id: 1265, category: "sekou", source: "vocab-supplementary", furi: "くらっく", jp: "クラック", romaji: "kurakku", id_text: "Retak / retakan pada beton", desc: "例: 乾燥収縮や過大な応力によってコンクリートにクラックが生じる。→ Retakan (クラック) pada beton bisa disebabkan oleh penyusutan pengeringan, pembebanan berlebih, atau perawatan yang tidak tepat.", _origIndex: 1243 },
  { id: 1277, category: "sekou", source: "vocab-supplementary", furi: "ALCパネル", jp: "ALCパネル", romaji: "ALC paneru", id_text: "Panel beton ringan otoklaf (ALC)", desc: "例: ALCパネルは軽量で断熱性・耐火性に優れ、外壁や床・屋根に使用される。→ Panel ALC (Autoclaved Lightweight Concrete) sangat ringan, memiliki sifat insulasi panas dan tahan api yang baik, digunakan untuk dinding luar, lantai, dan", _origIndex: 1255 },
  { id: 1280, category: "sekou", source: "vocab-supplementary", furi: "コーキング", jp: "コーキング", romaji: "kookingu", id_text: "Caulking / pengisian celah sambungan", desc: "例: サイディングのパネル継ぎ目にコーキング材を充填して防水性を確保する。→ Material caulking diisikan pada celah sambungan antar panel siding untuk memastikan ketahanan air.", _origIndex: 1258 },
  { id: 1282, category: "sekou", source: "vocab-supplementary", furi: "バックアップざい", jp: "バックアップ材", romaji: "bakkuappu zai", id_text: "Backer rod / pengisi belakang sealant", desc: "例: 目地が深い場合はバックアップ材を入れてシーリングの厚みを適切に調整する。→ Jika celah terlalu dalam, backer rod (biasanya busa polyethylene bulat)", _origIndex: 1260 },
  { id: 1284, category: "sekou", source: "vocab-supplementary", furi: "みずきり", jp: "水切り", romaji: "mizukiri", id_text: "Flashing / talang pengarah air hujan", desc: "例: 外壁の最下部に水切りを取り付けて、雨水が壁内部へ回り込まないようにする。→ Flashing dipasang di bagian bawah dinding luar untuk mengalirkan air hujan menjauhi struktur bangunan.", _origIndex: 1262 },
  { id: 1288, category: "sekou", source: "vocab-supplementary", furi: "ビニルゆかシート", jp: "ビニル床シート", romaji: "biniru yuka shiito", id_text: "Lembaran lantai vinil", desc: "例: トイレや厨房などの水まわりにはビニル床シートが多く使用される。→ Lembaran lantai vinil banyak dipakai di toilet dan dapur karena tahan air, mudah dibersihkan, dan relatif mudah dipasang.", _origIndex: 1266 },
  { id: 1289, category: "sekou", source: "vocab-supplementary", furi: "ちょうじゃくシート", jp: "長尺シート", romaji: "choojaku shiito", id_text: "Long sheet: lembaran lantai panjang minim sambung", desc: "例: 廊下や通路に長尺シートを施工すると継ぎ目が少なく衛生的に管理できる。→ Long sheet banyak dipakai di koridor dan area publik karena sambungan sedikit sehingga mudah dijaga kebersihannya.", _origIndex: 1267 },
  { id: 1297, category: "sekou", source: "vocab-supplementary", furi: "はんまーどりる", jp: "ハンマードリル", romaji: "hanmaa doriru", id_text: "Bor rotary / hammer drill", desc: "例: ハンマードリルはコンクリートへの穴あけや斫り作業に使う。→ Hammer drill digunakan untuk mengebor beton dan pekerjaan bongkaran (斫り). Wajib pakai pelindung telinga saat operasi.", _origIndex: 1275 },
  { id: 1304, category: "sekou", source: "vocab-supplementary", furi: "とるくれんち", jp: "トルクレンチ", romaji: "toruku renchi", id_text: "Kunci torsi / torque wrench", desc: "例: フランジボルトの締め付けはトルクレンチで規定トルク値を守る。→ Saat mengencangkan baut flens, gunakan kunci torsi sesuai nilai torsi yang ditentukan dalam spesifikasi. Mencegah over-torque yang bisa merusak ulir atau sambungan.", _origIndex: 1282 },
  { id: 1305, category: "sekou", source: "vocab-supplementary", furi: "しゃこまんりき", jp: "シャコ万力", romaji: "shako manriki", id_text: "Klem-C / C-clamp / ragum penjepit", desc: "例: 溶接作業中、シャコ万力で部材を固定して位置ずれを防ぐ。→ Saat pengelasan, gunakan C-clamp untuk memfix material agar tidak bergeser. Juga disebut Cクランプ. Digunakan saat menjepit papan, profil baja, atau pipa selama pengerjaan.", _origIndex: 1283 },
  { id: 1306, category: "sekou", source: "vocab-supplementary", furi: "たっぷ・だいす", jp: "タップ・ダイス", romaji: "tappu daisu", id_text: "Tap & dies / alat pembuat ulir", desc: "例: タップで金属に雌ねじを切り、ダイスで丸棒に雄ねじを切る。→ Tap digunakan untuk membuat ulir dalam (mur/雌ねじ), sedangkan dies untuk membuat ulir luar (baut/雄ねじ) pada batang logam. Keduanya adalah alat threading manual.", _origIndex: 1284 },
  { id: 1307, category: "sekou", source: "vocab-supplementary", furi: "かなきりのこ", jp: "金切りのこ", romaji: "kanakiri noko", id_text: "Gergaji besi / hacksaw", desc: "例: 金切りのこは鋼管や鉄棒の手動切断に使う。刃は消耗したら交換する。→ Gergaji besi digunakan untuk memotong pipa baja, besi batang, atau profil logam secara manual. Bilah gergaji (刃) dapat diganti saat sudah aus.", _origIndex: 1285 },
  { id: 1309, category: "sekou", source: "vocab-supplementary", furi: "がすばーなー", jp: "ガスバーナー", romaji: "gasu baanaa", id_text: "Pembakar gas / gas torch / burner", desc: "例: ガスバーナーは銅管のろう付けや防水材の炙り加工に使用する。→ Gas torch digunakan untuk penyolderan pipa tembaga (ろう付け/brazing) atau pemanasan material waterproofing. Pastikan ventilasi cukup dan jauh dari bahan mudah terbakar.", _origIndex: 1287 },
  { id: 1310, category: "sekou", source: "vocab-supplementary", furi: "ぜつえんていこうけい", jp: "絶縁抵抗計", romaji: "zetsuen teikou kei", id_text: "Megger / alat ukur tahanan isolasi kabel", desc: "例: 絶縁抵抗計（メガー）で電線の絶縁状態を確認し、漏電がないかを検査する。→ Megger digunakan untuk mengukur resistansi isolasi kabel listrik. Memastikan tidak ada kebocoran arus (漏電) ke ground sebelum sistem dinyalakan.", _origIndex: 1288 },
  { id: 1311, category: "sekou", source: "vocab-supplementary", furi: "せっちていこうけい", jp: "接地抵抗計", romaji: "secchi teikou kei", id_text: "Earth tester / alat ukur tahanan grounding", desc: "例: 接地抵抗計でアース極の接地抵抗値が規定値以下かを確認する。→ Earth tester digunakan untuk mengukur nilai tahanan grounding (接地/アース) dan memastikan instalasi pembumian memenuhi standar keamanan listrik.", _origIndex: 1289 },
  { id: 1313, category: "sekou", source: "vocab-supplementary", furi: "えあこんぷれっさー", jp: "エアコンプレッサー", romaji: "ea konpuressaa", id_text: "Kompresor udara / air compressor", desc: "例: エアコンプレッサーは釘打ち機やエアブロー清掃など幅広い作業に使用される。→ Kompresor udara digunakan untuk berbagai pekerjaan: alat tembak paku (釘打ち機), pembersihan debu dengan udara bertekanan, dan pengecatan semprot.", _origIndex: 1291 },
  { id: 1314, category: "sekou", source: "vocab-supplementary", furi: "こんくりーとかったー", jp: "コンクリートカッター", romaji: "konkuriito kattaa", id_text: "Gergaji beton / concrete cutter / floor saw", desc: "例: コンクリートカッターで床スラブに配管用の溝を切る。粉塵対策と給水が必須。→ Concrete cutter digunakan untuk memotong alur jalur pipa di lantai beton. Wajib menggunakan proteksi debu (防塵マスク) dan pendingin air saat operasi.", _origIndex: 1292 },
  { id: 1315, category: "sekou", source: "vocab-supplementary", furi: "ちっぱー", jp: "チッパー", romaji: "chippaa", id_text: "Pahat pneumatik / chipping hammer", desc: "例: チッパーはコンクリートのはつり作業や古い仕上げ材の除去に使う。→ Chipping hammer (chipper) digunakan untuk membongkar beton (斫り/はつり) atau mengupas material finishing lama. Gunakan goggles dan pelindung telinga saat operasi.", _origIndex: 1293 },
  { id: 1316, category: "sekou", source: "vocab-supplementary", furi: "じぐそー", jp: "ジグソー", romaji: "jigusoo", id_text: "Jigsaw / gergaji listrik serabut", desc: "例: ジグソーは曲線や複雑な形状の切断に適した電動のこぎりだ。→ Jigsaw adalah gergaji listrik yang cocok untuk memotong bentuk melengkung atau pola kompleks pada kayu, lembaran logam, atau papan gipsum di lokasi konstruksi.", _origIndex: 1294 },
  { id: 1319, category: "sekou", source: "vocab-supplementary", furi: "すこや", jp: "スコヤ", romaji: "sukoya", id_text: "Siku presisi / try square / engineer's square", desc: "例: スコヤで部材の直角を確認してから溶接や加工を行う。→ Try square (スコヤ) digunakan untuk memeriksa sudut siku-siku (90°) pada material sebelum pengelasan atau pengerjaan lebih lanjut.", _origIndex: 1297 },
  { id: 1320, category: "sekou", source: "vocab-supplementary", furi: "ぷらいやー", jp: "プライヤー", romaji: "puraiyaa", id_text: "Tang jepit / pliers", desc: "例: プライヤーはナットや配管継手など円筒物をつかんで回す作業に使う。→ Pliers digunakan untuk mencengkeram dan memutar mur, fitting pipa, atau benda silindris lainnya.", _origIndex: 1298 },
  { id: 1322, category: "career", source: "vocab-supplementary", furi: "せこうけいかくしょ", jp: "施工計画書", romaji: "sekou keikaku sho", id_text: "Dokumen rencana pelaksanaan konstruksi", desc: "例: 施工計画書は着工前に作成し、監理者に提出する。→ Dokumen rencana pelaksanaan dibuat sebelum mulai kerja dan diserahkan ke pengawas. Mencakup metode kerja, jadwal, keselamatan, dan pengelolaan kualitas.", _origIndex: 1300 },
  { id: 1325, category: "career", source: "vocab-supplementary", furi: "グリーンファイル", jp: "グリーンファイル", romaji: "guriin fairu", id_text: "Green file — kumpulan dokumen keselamatan", desc: "例: グリーンファイルには、安全衛生計画書・KY記録・作業員名簿などが綴られる。→ Green file memuat rencana K3, catatan KY, daftar tenaga kerja, dll. Disimpan di lokasi dan diperiksa oleh pengawas proyek.", _origIndex: 1303 },
  { id: 1327, category: "career", source: "vocab-supplementary", furi: "バーチャート", jp: "バーチャート", romaji: "baachaato", id_text: "Jadwal balok (Gantt chart konstruksi)", desc: "例: バーチャートは見やすいが、作業の関連性が分かりにくい。→ Jadwal balok mudah dibaca tapi tidak menunjukkan ketergantungan antar pekerjaan. Cocok untuk proyek sederhana atau laporan kemajuan ke klien.", _origIndex: 1304 },
  { id: 1328, category: "career", source: "vocab-supplementary", furi: "ネットワークこうていひょう", jp: "ネットワーク工程表", romaji: "nettowa ku koutei hyou", id_text: "Jadwal jaringan / CPM schedule", desc: "例: ネットワーク工程表でクリティカルパスを特定し、遅延リスクを管理した。→ Dengan jadwal jaringan, jalur kritis diidentifikasi untuk mengelola risiko keterlambatan. Menunjukkan urutan dan ketergantungan antar pekerjaan.", _origIndex: 1305 },
  { id: 1329, category: "career", source: "vocab-supplementary", furi: "できだか", jp: "出来高", romaji: "dekidaka", id_text: "Nilai pekerjaan yang telah selesai (progres)", desc: "例: 今月の出来高は契約金額の40%に達した。→ Progres bulan ini mencapai 40% dari nilai kontrak. Digunakan untuk penagihan bertahap (partial billing) dan laporan kemajuan proyek.", _origIndex: 1306 },
  { id: 1330, category: "career", source: "vocab-supplementary", furi: "ぶがかり", jp: "歩掛り", romaji: "bugakari", id_text: "Koefisien produktivitas tenaga kerja", desc: "例: 配管工事の歩掛りは、1mあたり何人工かかるかを示す。→ Koefisien kerja pipa menunjukkan berapa orang-hari yang dibutuhkan per meter. Digunakan untuk estimasi biaya tenaga kerja dalam RAB.", _origIndex: 1307 },
  { id: 1331, category: "career", source: "vocab-supplementary", furi: "ちょくせつかせつ", jp: "直接仮設", romaji: "chokusetsu kasetsu", id_text: "Pekerjaan sementara langsung (per lokasi)", desc: "例: 直接仮設には、各工事専用の足場・型枠支保工などが含まれる。→ Pekerjaan sementara langsung mencakup perancah dan bekisting yang khusus untuk satu area pekerjaan tertentu. Berbeda dari 共通仮設.", _origIndex: 1308 },
  { id: 1332, category: "career", source: "vocab-supplementary", furi: "きょうつうかせつ", jp: "共通仮設", romaji: "kyoutsuu kasetsu", id_text: "Pekerjaan sementara bersama (seluruh proyek)", desc: "例: 共通仮設には、現場事務所・トイレ・電力引込などが含まれる。→ Pekerjaan sementara bersama mencakup kantor lapangan, toilet, dan sambungan listrik yang dipakai semua pihak di proyek.", _origIndex: 1309 },
  { id: 1333, category: "career", source: "vocab-supplementary", furi: "げんかかんり", jp: "原価管理", romaji: "genka kanri", id_text: "Manajemen biaya / pengendalian harga pokok", desc: "例: 原価管理では、実際原価と計画原価を比較して差異を分析する。→ Dalam manajemen biaya, biaya aktual dibandingkan dengan biaya rencana untuk menganalisis selisih. Termasuk dalam 4 pilar施工管理 (Q, C, D, S).", _origIndex: 1310 },
  { id: 1335, category: "career", source: "vocab-supplementary", furi: "しゅんこうず", jp: "竣工図", romaji: "shunkou zu", id_text: "Gambar as-built (setelah selesai dibangun)", desc: "例: 竣工図は、実際に施工した内容を反映した最終図面で、引渡し時に提出する。→ Gambar as-built mencerminkan kondisi yang benar-benar dibangun, diserahkan saat serah terima ke klien. Berbeda dari gambar desain awal.", _origIndex: 1312 },
  { id: 1336, category: "career", source: "vocab-supplementary", furi: "せこうず", jp: "施工図", romaji: "sekouzu", id_text: "Gambar kerja lapangan (shop drawing)", desc: "例: 施工図は設計図書をもとに現場で作業できるよう詳細化した図面である。→ Gambar kerja adalah gambar detail yang dibuat dari dokumen desain agar bisa langsung digunakan di lapangan. Dibuat oleh kontraktor, disetujui pengawas.", _origIndex: 1313 },
  { id: 1337, category: "career", source: "vocab-supplementary", furi: "うちあわせきろく", jp: "打合せ記録", romaji: "uchiawasekiroku", id_text: "Notulen / catatan rapat koordinasi", desc: "例: 打合せ記録には、日時・参加者・決定事項・担当者を明記する。→ Notulen rapat mencantumkan tanggal, peserta, keputusan, dan penanggung jawab. Dokumen penting sebagai bukti kesepakatan di lapangan.", _origIndex: 1314 },
  { id: 1338, category: "career", source: "vocab-supplementary", furi: "こうじにっぽう", jp: "工事日報", romaji: "kouji nippou", id_text: "Laporan harian pekerjaan konstruksi", desc: "例: 工事日報には、当日の作業内容・人員数・天気・問題点を記録する。→ Laporan harian mencatat jenis pekerjaan, jumlah tenaga kerja, cuaca, dan kendala hari itu. Diisi oleh pengawas lapangan setiap hari.", _origIndex: 1315 },
  { id: 1339, category: "career", source: "vocab-supplementary", furi: "ざいりょうはんにゅう", jp: "材料搬入", romaji: "zairyou hanyuu", id_text: "Pengiriman / penerimaan material ke lokasi", desc: "例: 材料搬入時は、納品書と照合して数量・品番を確認する。→ Saat material tiba, jumlah dan nomor produk dicocokkan dengan surat jalan. Proses ini mendahului 検収 (penerimaan resmi setelah inspeksi).", _origIndex: 1316 },
  { id: 1340, category: "career", source: "vocab-general", furi: "けんしゅう", jp: "検収", romaji: "kenshuu", id_text: "Inspeksi & penerimaan material resmi", desc: "例: 検収では、材料の品質・数量・規格が仕様書と一致するか確認する。→ Dalam inspeksi penerimaan, kualitas, jumlah, dan spesifikasi material dikonfirmasi sesuai dokumen. Setelah 検収 dinyatakan lulus, material sah digunakan.", _origIndex: 1317 },
  { id: 1341, category: "career", source: "vocab-general", furi: "ぜせい", jp: "是正", romaji: "zesei", id_text: "Tindakan koreksi / perbaikan ketidaksesuaian", desc: "例: 検査で不適合が見つかり、是正処置を施工者に指示した。→ Ketidaksesuaian ditemukan saat inspeksi, dan tindakan koreksi diperintahkan ke kontraktor. Dalam sistem ISO 9001, 是正処置は根本原因の除去を含む.", _origIndex: 1318 },
  { id: 1342, category: "career", source: "vocab-supplementary", furi: "ひきわたし", jp: "引渡し", romaji: "hikiwatashi", id_text: "Serah terima bangunan / fasilitas ke klien", desc: "例: 引渡し前に竣工検査を行い、合格後に鍵と竣工図書を施主に渡す。→ Sebelum serah terima, inspeksi akhir dilakukan; lulus → kunci dan dokumen diserahkan ke pemilik. Menandai berakhirnya tanggung jawab kontraktor.", _origIndex: 1319 },
  { id: 1344, category: "career", source: "vocab-supplementary", furi: "そうごうせこうけいかくしょ", jp: "総合施工計画書", romaji: "sougou sekou keikaku sho", id_text: "Rencana pelaksanaan konstruksi menyeluruh", desc: "例: 総合施工計画書は工事全体を俯瞰した計画書で、着工前に作成される。→ Dokumen ini merangkum rencana keseluruhan proyek dan dibuat sebelum pekerjaan dimulai. Menjadi acuan bagi semua 施工計画書 per bidang pekerjaan.", _origIndex: 1321 },
  { id: 1345, category: "career", source: "vocab-supplementary", furi: "ひんしつかんりけいかくしょ", jp: "品質管理計画書", romaji: "hinshitsu kanri keikaku sho", id_text: "Dokumen rencana manajemen kualitas", desc: "例: 品質管理計画書には、検査項目・頻度・担当者・合否基準を定める。→ Dokumen ini menetapkan item inspeksi, frekuensi, penanggung jawab, dan kriteria lulus/gagal. Bagian dari sistem ISO 9001 yang diterapkan di proyek konstruksi.", _origIndex: 1322 },
  { id: 1354, category: "anzen", source: "vocab-supplementary", furi: "あんぜんかんりしゃ", jp: "安全管理者", romaji: "anzen kanrisha", id_text: "Safety manager / manajer keselamatan kerja", desc: "例: 常時50人以上の事業場には安全管理者の選任が義務付けられている。→ Wajib ada safety manager di tempat kerja dengan ≥50 pekerja tetap. Berbeda dari 衛生管理者 yang fokus pada kesehatan.", _origIndex: 1331 },
  { id: 1365, category: "sekou", source: "vocab-supplementary", furi: "こうていひょう", jp: "工程表", romaji: "koutei hyou", id_text: "Bagan jadwal konstruksi (Gantt chart / network)", desc: "例: 工程表で各作業の開始・終了予定日と担当者を管理する。→ Jadwal menampilkan tanggal mulai/selesai setiap pekerjaan. バーチャート = mudah dibaca; ネットワーク工程表 = menampilkan ketergantungan antar pekerjaan.", _origIndex: 1339 },
  { id: 1369, category: "hourei", source: "vocab-supplementary", furi: "せんもんぎょうしゃ", jp: "専門業者", romaji: "senmon gyousha", id_text: "Kontraktor spesialis / specialty contractor", desc: "例: 電気・空調・配管などは各分野の専門業者が施工する。→ Listrik, AC, dan perpipaan dikerjakan oleh kontraktor spesialis masing-masing bidang. 元請けが全体調整し、各専門業者が実施工を担う.", _origIndex: 1341 },
  { id: 1382, category: "gaiyou", source: "vocab-supplementary", furi: "よろしくおねがいします", jp: "よろしくお願いします", romaji: "yoroshiku onegai shimasu", id_text: "Mohon bimbingannya / salam kenal (serba guna)", desc: "例: 初日の挨拶「よろしくお願いします」／作業依頼の最後にも使う。→ Dipakai saat: pertama kali bertemu, menitipkan tugas ke orang lain, memohon bantuan. Frasa yang paling sering dibutuhkan di lapangan.", _origIndex: 1354 },
  { id: 1384, category: "gaiyou", source: "vocab-supplementary", furi: "すみません", jp: "すみません", romaji: "sumimasen", id_text: "Permisi / maaf / excuse me (serbaguna)", desc: "例: 通路をふさいでいるとき「すみません」／何か頼むときにも使う。→ Dipakai untuk: meminta izin lewat, minta tolong, meminta perhatian seseorang, atau minta maaf ringan. Frasa paling serbaguna di tempat kerja Jepang.", _origIndex: 1356 },
  { id: 1385, category: "gaiyou", source: "vocab-supplementary", furi: "わかりました", jp: "わかりました", romaji: "wakarimashita", id_text: "Sudah mengerti / paham (merespons instruksi)", desc: "例: 監督から指示を受けたら「わかりました」と返事する。→ Respons standar saat menerima instruksi dari atasan. Lebih formal dari 分かった (wakata). Wajib biasakan ini agar tidak dianggap tidak mendengarkan.", _origIndex: 1357 },
  { id: 1386, category: "gaiyou", source: "vocab-supplementary", furi: "わかりません", jp: "わかりません", romaji: "wakarimasen", id_text: "Tidak mengerti / tidak tahu", desc: "例: 指示が聞き取れなかったら「わかりません。もう一度お願いします」と言う。→ Jika tidak mengerti, selalu bilang dengan jelas — jangan pura-pura mengerti! Tambahkan もう一度お願いします untuk minta diulang.", _origIndex: 1358 },
  { id: 1387, category: "gaiyou", source: "vocab-supplementary", furi: "もういちどいってください", jp: "もう一度言ってください", romaji: "mou ichido itte kudasai", id_text: "Tolong ulangi sekali lagi", desc: "例: 聞き取れなかったとき「すみません、もう一度言ってください」。→ Kalimat wajib untuk meminta pengulangan. Tidak perlu malu menggunakannya — lebih baik bertanya daripada melakukan pekerjaan yang salah.", _origIndex: 1359 },
  { id: 1388, category: "gaiyou", source: "vocab-supplementary", furi: "てつだってください", jp: "手伝ってください", romaji: "tetsudatte kudasai", id_text: "Tolong bantu saya", desc: "例: 重い材料を運ぶとき「手伝ってください」と頼む。→ Minta bantuan saat mengangkat beban berat, kesulitan teknis, dsb. Versi lebih sopan: お手伝いいただけますか？", _origIndex: 1360 },
  { id: 1389, category: "gaiyou", source: "vocab-supplementary", furi: "ちょっとまってください", jp: "ちょっと待ってください", romaji: "chotto matte kudasai", id_text: "Tolong tunggu sebentar", desc: "例: 準備が終わっていないとき「ちょっと待ってください」と言う。→ Minta waktu sebentar sebelum mulai atau menjawab. Sopan dan alami di lapangan. ちょっと = sedikit/sebentar.", _origIndex: 1361 },
  { id: 1391, category: "gaiyou", source: "vocab-supplementary", furi: "おつかれさまでした", jp: "お疲れ様でした", romaji: "otsukaresama deshita", id_text: "Terima kasih kerja kerasnya (akhir hari / selesai)", desc: "例: 一日の作業が終わったとき「お疲れ様でした」と言い合う。→ Ucapkan di akhir shift kepada semua orang. Berbeda dari お疲れ様です (sedang berlangsung) vs です (formal ongoing). Respon yang sama: お疲れ様でした.", _origIndex: 1363 },
  { id: 1393, category: "gaiyou", source: "vocab-supplementary", furi: "おわりました", jp: "終わりました", romaji: "owarimashita", id_text: "Sudah selesai (laporan penyelesaian tugas)", desc: "例: 作業が完了したら監督に「○○の作業が終わりました」と報告する。→ Laporan setelah menyelesaikan tugas. Selalu laporkan ke pengawas saat pekerjaan selesai — jangan diam saja. Bisa ditambahkan: 確認をお願いします (mohon diperiksa).", _origIndex: 1365 },
  { id: 1394, category: "gaiyou", source: "vocab-supplementary", furi: "きをつけて", jp: "気をつけて", romaji: "ki wo tsukete", id_text: "Hati-hati! / Be careful! (kepada orang lain)", desc: "例: 危険な場所を通る仲間に「気をつけて」と声をかける。→ Ucapkan kepada rekan yang sedang melewati area berbahaya atau pulang kerja. Versi lebih kuat: 気をつけてください (formal) atau 危ない！ (darurat).", _origIndex: 1366 },
  { id: 1395, category: "gaiyou", source: "vocab-supplementary", furi: "おねがいします", jp: "お願いします", romaji: "onegai shimasu", id_text: "Mohon / tolong (saat meminta sesuatu)", desc: "例: 資材を運んでほしいとき「○○をお願いします」と頼む。→ Tambahkan setelah permintaan apapun: 確認をお願いします (tolong cek), 手伝いをお願いします (tolong bantu), dll. Lebih sopan dari ください saja.", _origIndex: 1367 },
  { id: 1397, category: "gaiyou", source: "vocab-supplementary", furi: "いってきます／いってらっしゃい", jp: "行ってきます／行ってらっしゃい", romaji: "ittekimasu / itterasshai", id_text: "Hati-hati di jalan (pasangan sapaan saat pergi)", desc: "例: 現場に向かう前「行ってきます」→ 残る人「行ってらっしゃい」。→ Pasangan sapaan saat seseorang berangkat meninggalkan tempat. Juga dipakai antar rekan kerja di site besar.", _origIndex: 1369 },
  { id: 1398, category: "gaiyou", source: "vocab-supplementary", furi: "おせわになっております", jp: "お世話になっております", romaji: "osewa ni natte orimasu", id_text: "Terima kasih atas bimbingan selama ini (formal)", desc: "例: 電話や会議の冒頭「お世話になっております、○○の田中です」。→ Kalimat pembuka formal dalam telepon atau rapat. Setara dengan 'thank you for your continued support'. Wajib di lingkungan kerja profesional Jepang.", _origIndex: 1370 },
  { id: 1404, category: "career", source: "vocab-general", furi: "けいご", jp: "敬語", romaji: "keigo", id_text: "Bahasa hormat Jepang (kepada atasan/klien)", desc: "例: 上司や発注者には敬語を使う。「食べる」→「いただく」、「言う」→「おっしゃる」。→ Bahasa hormat digunakan kepada atasan, senior, dan klien. Keigo dasar: ～ます/～ます form = sudah cukup di lapangan.", _origIndex: 1376 },
  { id: 1405, category: "career", source: "vocab-supplementary", furi: "みだしなみ", jp: "身だしなみ", romaji: "midashinami", id_text: "Penampilan / kerapian diri di tempat kerja", desc: "例: 現場では清潔な作業着・正しくかぶったヘルメット・安全靴が身だしなみの基本。→ Penampilan di site: seragam bersih, helm benar, sepatu safety. 身だしなみが良い = kesan profesional, kepercayaan atasan meningkat.", _origIndex: 1377 },
  { id: 1406, category: "career", source: "vocab-general", furi: "ちこく", jp: "遅刻", romaji: "chikoku", id_text: "Terlambat / keterlambatan masuk kerja", desc: "例: 遅刻しそうなときは、必ず事前に上司に連絡する。無断遅刻は厳禁。→ Jika akan terlambat, WAJIB hubungi atasan lebih dulu. Terlambat tanpa kabar (無断遅刻) = pelanggaran serius. 朝礼の時間に間に合うよう余裕を持って出勤する。", _origIndex: 1378 },
  { id: 1407, category: "career", source: "vocab-general", furi: "けっきん", jp: "欠勤", romaji: "kekkin", id_text: "Tidak masuk kerja / absen", desc: "例: 体調不良で欠勤する場合は、始業時間前に会社へ電話連絡する。→ Kalau sakit dan tidak bisa masuk, telepon perusahaan SEBELUM jam kerja dimulai. 無断欠勤 = 最悪の場合、解雇の原因になる。欠勤の際は診断書が必要な場合もある。", _origIndex: 1379 },
  { id: 1409, category: "anzen", source: "vocab-supplementary", furi: "たいちょうかんり", jp: "体調管理", romaji: "taichoukanri", id_text: "Manajemen kondisi fisik / menjaga kesehatan diri", desc: "例: プロとして毎日の体調管理は自分の責任だ。睡眠・食事・水分補給の3つが基本。→ Sebagai profesional, menjaga kondisi tubuh adalah tanggung jawab pribadi. 体調不良で作業すると事故・ミスの原因になる。JAC テキスト必出トピック。", _origIndex: 1381 },
  { id: 1410, category: "anzen", source: "vocab-supplementary", furi: "たいちょうふりょう", jp: "体調不良", romaji: "taichoufuryou", id_text: "Kondisi badan tidak fit / merasa tidak enak badan", desc: "例: 体調不良を感じたら無理せず、すぐに上司に「体調が悪いです」と報告する。→ Kalau tidak enak badan, jangan dipaksakan — langsung lapor ke atasan. 高所作業・機械操作中の体調不良は重大事故の原因になる。", _origIndex: 1382 },
  { id: 1411, category: "anzen", source: "vocab-supplementary", furi: "すいぶんほきゅう", jp: "水分補給", romaji: "suibunhokyuu", id_text: "Minum air / rehidrasi (cegah heat stroke)", desc: "例: 夏の現場では、1時間ごとに水分補給して熱中症を予防する。→ Di musim panas, minum air setiap jam untuk cegah heat stroke. のどが渇く前に飲む = minum sebelum merasa haus. スポーツドリンクで電解質も補充する。", _origIndex: 1383 },
  { id: 1414, category: "career", source: "vocab-supplementary", furi: "じかんげんしゅ", jp: "時間厳守", romaji: "jikangennshu", id_text: "Tepat waktu / kepatuhan terhadap jadwal", desc: "例: 朝礼・作業開始・材料搬入など、すべての時間を厳守することが信頼の基本。→ Semua jadwal — apel, mulai kerja, pengiriman material — harus tepat waktu. 「5分前行動」= siap 5 menit sebelum waktu yang ditetapkan. Kebiasaan di Jepang.", _origIndex: 1386 },
  { id: 1415, category: "career", source: "vocab-supplementary", furi: "きゅうよめいさい", jp: "給与明細", romaji: "kyuuyomeisai", id_text: "Slip gaji / rincian pembayaran upah bulanan", desc: "例: 毎月の給与明細を確認し、残業代・各種控除が正しいか確認する。→ Cek slip gaji setiap bulan: pastikan upah lembur dan potongan sudah benar. 不明な点は会社の担当者に相談する権利がある。給与明細の交付は法律上の義務。", _origIndex: 1387 },
  { id: 1420, category: "hourei", source: "vocab-general", furi: "しゅうろう", jp: "就労", romaji: "shuurou", id_text: "Bekerja / kegiatan kerja berdasarkan izin tinggal", desc: "例: 在留資格の範囲外での就労は「不法就労」として処罰される。雇用主も罰則の対象。→ Kerja di luar izin tinggal = kerja ilegal, bisa dipenjara/dideportasi. Majikan juga kena sanksi. 特定技能では指定分野のみ就労可。", _origIndex: 1392 },
  { id: 1424, category: "hourei", source: "vocab-supplementary", furi: "こうせいねんきん", jp: "厚生年金", romaji: "kousei nenkin", id_text: "Pensiun perusahaan / employees' pension insurance", desc: "例: 厚生年金保険料は会社と従業員で折半し、将来の年金受給権が積み上がる。→ Premi pensiun ditanggung bersama (50%:50%). Setelah pensiun, berhak menerima uang pensiun. 外国人は帰国時に「脱退一時金」を受け取れる場合あり。", _origIndex: 1396 },
  { id: 1426, category: "hourei", source: "vocab-supplementary", furi: "ほけんしょう", jp: "保険証", romaji: "hokenshou", id_text: "Kartu asuransi kesehatan / health insurance card", desc: "例: 病院に行くときは保険証を持参する。提示することで3割負担になる。紛失したらすぐ会社に連絡。→ Bawa kartu asuransi setiap kali ke dokter. 忘れた場合は一旦全額負担になるが後で差額が戻る場合あり。", _origIndex: 1398 },
  { id: 1429, category: "anzen", source: "vocab-supplementary", furi: "ぼうじんますく", jp: "防じんマスク", romaji: "boujin masuku", id_text: "Masker anti-debu / dust respirator", desc: "例: コンクリート切断・はつり作業では防じんマスク（DS2以上）を着用する。→ Saat memotong beton/keramik, wajib pakai masker anti-debu. 通常のマスク（布・サージカル）では粉じん・シリカを防げない。塵肺（じんぱい）予防のために必須。", _origIndex: 1401 },
  { id: 1430, category: "anzen", source: "vocab-general", furi: "みみせん", jp: "耳栓", romaji: "mimisen", id_text: "Penyumbat telinga / earplugs", desc: "例: 85dB以上の騒音環境（グラインダー・チッパー使用時）では耳栓または耳覆いを着用する義務がある。→ Lingkungan >85 dB wajib pakai pelindung telinga. Paparan bising berkepanjangan → 騒音性難聴 (tuli akibat kebisingan) yang tidak bisa sembuh.", _origIndex: 1402 }
];
